pragma solidity ^0.8.4;

import "@openzeppelin/contracts/utils/Context.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "./utils/Constants.sol";
import "./interfaces/IStrategy.sol";

contract Zunami is Context, Ownable, ERC20 {
    using SafeERC20 for IERC20Metadata;

    struct PendingDeposit {
        uint256[3] amounts;
        address depositor;
    }

    struct PendingWithdrawal {
        uint256 lpAmount;
        uint256[3] minAmounts;
        address withdrawer;
    }

    struct PoolInfo {
        IStrategy strategy;
        uint256 startTime;
    }

    uint8 private constant POOL_ASSETS = 3;

    address[POOL_ASSETS] public tokens;
    mapping(address => uint256) public deposited;
    uint256[] userCompleteHoldings;

    PoolInfo[] public poolInfo;
    uint256 public totalDeposited;

    uint256 public FEE_DENOMINATOR = 1000;
    uint256 public managementFee = 10; 
    bool public isLock = false;
    uint256 public constant MIN_LOCK_TIME = 86400; 

    address public admin;
    uint256 public completedDeposits;
    uint256 public completedWithdrawals;
    PendingWithdrawal[] public pendingWithdrawals;
    mapping(address => uint256[]) public accDepositPending;

    event PendingDepositEvent(address depositor, uint256[3] amounts);
    event Deposited(address depositor, uint256[3] amounts, uint256 lpShares);
    event Withdrawn(address withdrawer, uint256[3] amounts, uint256 lpShares);
    event AddStrategy(address strategyAddr);
    event BadDeposit(address depositor, uint256[3] amounts, uint256 lpShares);
    event BadWithdraw(address withdrawer, uint256[3] amounts, uint256 lpShares);

    modifier isLocked() {
        require(!isLock, "Zunami: Deposit functions locked");
        _;
    }

    constructor() ERC20("ZunamiLP", "ZLP") {
        tokens[0] = Constants.DAI_ADDRESS;
        tokens[1] = Constants.USDC_ADDRESS;
        tokens[2] = Constants.USDT_ADDRESS;
    }

    function setManagementFee(uint256 newManagementFee) external onlyOwner {
        require(newManagementFee < FEE_DENOMINATOR, "Zunami: wrong fee");
        managementFee = newManagementFee;
    }

    function calcManagementFee(uint256 amount) public view virtual
    returns (uint256)
    {
        return (amount * managementFee) / FEE_DENOMINATOR;
    }


    function totalHoldings() public view virtual returns (uint256) {
        uint256 length = poolInfo.length;
        uint256 totalHold = 0;
        for (uint256 pid = 0; pid < length; ++pid) {
            totalHold += poolInfo[pid].strategy.totalHoldings();
        }
        return totalHold;
    }

    function lpPrice() public view virtual returns (uint256) {
        return totalHoldings() * 1e18 / totalSupply();
    }

    function delegateDeposit(uint256[3] memory amounts) external virtual isLocked {

        for (uint256 i = 0; i < amounts.length; ++i) {
            if (amounts[i] > 0) {
                IERC20Metadata(tokens[i]).safeTransferFrom(
                    _msgSender(),
                    address(this),
                    amounts[i]
                );
            }
        }
        accDepositPending[_msgSender()] = amounts;
        emit PendingDepositEvent(_msgSender(), amounts);
    }


    function delegateWithdrawal(uint256 lpAmount, uint256[3] memory minAmounts)
    external virtual
    {
        PendingWithdrawal memory pendingWithdrawal;
        pendingWithdrawal.lpAmount = lpAmount;
        pendingWithdrawal.minAmounts = minAmounts;
        pendingWithdrawal.withdrawer = _msgSender();
        pendingWithdrawals.push(pendingWithdrawal);
    }

    function completeDeposits(address[] memory userList, uint256 pid)
    external virtual onlyOwner
    {
        IStrategy strategy = poolInfo[pid].strategy;
        uint256[3] memory totalAmounts;

        uint256 addHoldings = 0;
        uint256 holdings = totalHoldings();
        for (uint256 i = 0; i < userList.length; i++) {
            userCompleteHoldings.push(0);
            for (uint256 x = 0; x < totalAmounts.length; ++x) {
                uint256 decimalsMultiplier = 1;
                if (IERC20Metadata(tokens[x]).decimals() < 18) {
                    decimalsMultiplier =
                    10 ** (18 - IERC20Metadata(tokens[x]).decimals());
                }
                totalAmounts[x] += accDepositPending[userList[i]][x];
                addHoldings += accDepositPending[userList[i]][x] * decimalsMultiplier;
                userCompleteHoldings[i] += accDepositPending[userList[i]][x] * decimalsMultiplier;
            }
        }
        for (uint256 _i = 0; _i < POOL_ASSETS; ++_i) {
            if (totalAmounts[_i] > 0) {
                IERC20Metadata(tokens[_i]).safeTransfer(address(strategy), totalAmounts[_i]);
            }
        }
        uint256 sum = strategy.deposit(totalAmounts);
        uint256 lpShares = 0;
        uint256 changedHoldings = 0;
        uint256 currentUserAmount = 0;
        for (uint256 z = 0; z < userList.length; z++) {
            currentUserAmount = sum * userCompleteHoldings[z] / addHoldings;
            deposited[userList[z]] += currentUserAmount;
            totalDeposited += currentUserAmount;
            changedHoldings += currentUserAmount;
            if (totalSupply() == 0) {
                lpShares = currentUserAmount;
            } else {
                lpShares = (currentUserAmount * totalSupply()) / (holdings + changedHoldings - currentUserAmount);
            }
            _mint(userList[z], lpShares);
            strategy.updateZunamiLpInStrat(lpShares, true);

            accDepositPending[userList[z]] = [0, 0, 0];
        }
        delete userCompleteHoldings;
        require(sum > 0, "too low amount!");
    }

    function completeWithdrawals(uint256 withdrawalsToComplete, uint256 pid)
    external virtual onlyOwner
    {
        uint256 maxWithdrawals = withdrawalsToComplete < pendingWithdrawals.length
        ? withdrawalsToComplete : pendingWithdrawals.length;
        for (uint256 i = 0; i < maxWithdrawals && pendingWithdrawals.length > 0; i++) {
            delegatedWithdrawal(
                pendingWithdrawals[0].withdrawer,
                pendingWithdrawals[0].lpAmount,
                pendingWithdrawals[0].minAmounts,
                pid
            );
            pendingWithdrawals[0] = pendingWithdrawals[pendingWithdrawals.length - 1];
            pendingWithdrawals.pop();
        }
    }

    function deposit(uint256[3] memory amounts, uint256 pid)
    external virtual isLocked returns (uint256)
    {
        IStrategy strategy = poolInfo[pid].strategy;
        require(block.timestamp >= poolInfo[pid].startTime, "Zunami: strategy not started yet!");
        uint256 holdings = totalHoldings();

        for (uint256 i = 0; i < amounts.length; ++i) {
            if (amounts[i] > 0)
            {
                IERC20Metadata(tokens[i]).safeTransferFrom(
                    _msgSender(),
                    address(strategy),
                    amounts[i]
                );
            }
        }
        uint256 sum = strategy.deposit(amounts);

        uint256 lpShares = 0;
        if (totalSupply() == 0) {
            lpShares = sum;
        } else {
            lpShares = (sum * totalSupply()) / holdings;
        }
        _mint(_msgSender(), lpShares);
        strategy.updateZunamiLpInStrat(lpShares, true);
        deposited[_msgSender()] += sum;
        totalDeposited += sum;

        require(sum > 0, "too low amount!");
        emit Deposited(_msgSender(), amounts, lpShares);
        return lpShares;
    }

    function withdraw(uint256 lpShares, uint256[3] memory minAmounts, uint256 pid)
    external virtual
    {
        IStrategy strategy = poolInfo[pid].strategy;
        require(balanceOf(_msgSender()) >= lpShares,
            "Zunami: not enough LP balance"
        );
        require(strategy.withdraw(_msgSender(), lpShares, minAmounts),
            "user lps share should be at least required");
        uint256 userDeposit = (totalDeposited * lpShares) / totalSupply();
        _burn(_msgSender(), lpShares);
        strategy.updateZunamiLpInStrat(lpShares, false);
        deposited[_msgSender()] -= userDeposit > deposited[_msgSender()] ? deposited[_msgSender()] : userDeposit;
        totalDeposited -= userDeposit > totalDeposited ? totalDeposited : userDeposit;
        emit Withdrawn(_msgSender(), minAmounts, lpShares);
    }

    function delegatedWithdrawal(
        address withdrawer,
        uint256 lpShares,
        uint256[3] memory minAmounts,
        uint256 pid
    ) internal virtual {
        if ((balanceOf(withdrawer) >= lpShares) && lpShares > 0) {
            IStrategy strategy = poolInfo[pid].strategy;
            if (!(strategy.withdraw(withdrawer, lpShares, minAmounts))) {
                emit BadWithdraw(withdrawer, minAmounts, lpShares);
                return;
            }
            uint256 userDeposit = (totalDeposited * lpShares) / totalSupply();
            _burn(withdrawer, lpShares);
            strategy.updateZunamiLpInStrat(lpShares, false);
            deposited[withdrawer] -= userDeposit > deposited[withdrawer] ? deposited[withdrawer] : userDeposit;
            totalDeposited -= userDeposit;
            emit Withdrawn(withdrawer, minAmounts, lpShares);
        }
    }

    function setLock(bool _lock) external virtual onlyOwner
    {
        isLock = _lock;
    }

    function claimManagementFees(address strategyAddr) external virtual onlyOwner
    {
        IStrategy(strategyAddr).claimManagementFees();
    }


    function add(address _strategy) external virtual onlyOwner {
        poolInfo.push(PoolInfo({
        strategy : IStrategy(_strategy),
        startTime : block.timestamp + MIN_LOCK_TIME
        }));
    }

    function moveFunds(uint256 _from, uint256 _to)
    external virtual onlyOwner {
        IStrategy fromStrat = poolInfo[_from].strategy;
        IStrategy toStrat = poolInfo[_to].strategy;
        fromStrat.withdrawAll();
        uint256[3] memory amounts;
        for (uint256 i = 0; i < POOL_ASSETS; ++i) {
            amounts[i] = IERC20Metadata(tokens[i]).balanceOf(address(this));
            if (amounts[i] > 0) {
                IERC20Metadata(tokens[i]).safeTransfer(
                    address(toStrat),
                    amounts[i]
                );
            }
        }
        toStrat.deposit(amounts);
        uint256 transferLpAmount = fromStrat.getZunamiLpInStrat();
        fromStrat.updateZunamiLpInStrat(transferLpAmount, false);
        toStrat.updateZunamiLpInStrat(transferLpAmount, true);
    }

    function moveFundsBatch(uint256[] memory _from, uint256 _to)
    external virtual onlyOwner {
        uint256 length = _from.length;
        uint256[3] memory amounts;
        uint256 zunamiLp = 0;
        for (uint256 i = 0; i < length; ++i) {
            poolInfo[_from[i]].strategy.withdrawAll();
            uint256 thisPidLpAmount = poolInfo[_from[i]].strategy.getZunamiLpInStrat();
            zunamiLp += thisPidLpAmount;
            poolInfo[_from[i]].strategy.updateZunamiLpInStrat(thisPidLpAmount, false);
        }
        for (uint256 _i = 0; _i < POOL_ASSETS; ++_i) {
            amounts[_i] = IERC20Metadata(tokens[_i]).balanceOf(address(this));
            if (amounts[_i] > 0) {
                IERC20Metadata(tokens[_i]).safeTransfer(
                    address(poolInfo[0].strategy),
                    amounts[_i]
                );
            }
        }
        poolInfo[_to].strategy.updateZunamiLpInStrat(zunamiLp, true);
        require(poolInfo[_to].strategy.deposit(amounts) > 0, "too low amount!");
    }

    function emergencyWithdraw() external virtual onlyOwner {
        uint256 length = poolInfo.length;
        require(length > 1, "Zunami: Nothing withdraw");
        uint256[3] memory amounts;
        uint256 zunamiLp = 0;
        for (uint256 i = 1; i < length; ++i) {
            poolInfo[i].strategy.withdrawAll();
            uint256 thisPidLpAmount = poolInfo[i].strategy.getZunamiLpInStrat();
            zunamiLp += thisPidLpAmount;
            poolInfo[i].strategy.updateZunamiLpInStrat(thisPidLpAmount, false);
        }
        for (uint256 _i = 0; _i < POOL_ASSETS; ++_i) {
            amounts[_i] = IERC20Metadata(tokens[_i]).balanceOf(address(this));
            if (amounts[_i] > 0) {
                IERC20Metadata(tokens[_i]).safeTransfer(
                    address(poolInfo[0].strategy),
                    amounts[_i]
                );
            }
        }
        poolInfo[0].strategy.updateZunamiLpInStrat(zunamiLp, true);
        require(poolInfo[0].strategy.deposit(amounts) > 0, "too low amount!");
    }


    function pendingDepositRemove() external virtual {
        for (uint256 i = 0; i < POOL_ASSETS; ++i) {
            if (accDepositPending[_msgSender()][i] > 0) {
                IERC20Metadata(tokens[i]).safeTransfer(_msgSender(), accDepositPending[_msgSender()][i]);
            }
        }
        accDepositPending[_msgSender()] = [0, 0, 0];
    }

}

pragma solidity ^0.8.10;

import "@openzeppelin/contracts/token/ERC20/extensions/IERC20Metadata.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";

import "./libraries/FullMath.sol";
import "./libraries/TickMath.sol";
import "./libraries/Silo.sol";
import "./libraries/Uniswap.sol";

import "./interfaces/IAloeBlend.sol";
import "./interfaces/IFactory.sol";
import "./interfaces/IVolatilityOracle.sol";

import "./AloeBlendERC20.sol";
import "./UniswapHelper.sol";



uint256 constant Q96 = 2**96;

contract AloeBlend is AloeBlendERC20, UniswapHelper, ReentrancyGuard, IAloeBlend {
    using SafeERC20 for IERC20;
    using Uniswap for Uniswap.Position;
    using Silo for ISilo;


    uint24 public constant MIN_WIDTH = 201; 


    uint24 public constant MAX_WIDTH = 13864; 


    uint8 public constant K = 10;


    uint8 public constant B = 2; 


    uint8 public constant MAINTENANCE_FEE = 10; 


    IVolatilityOracle public immutable volatilityOracle;


    ISilo public immutable silo0;


    ISilo public immutable silo1;


    Uniswap.Position public primary;


    Uniswap.Position public limit;


    uint256 public recenterTimestamp;


    uint256 public maintenanceBudget0;


    uint256 public maintenanceBudget1;

    uint224[10] public rewardPerGas0Array;

    uint224[10] public rewardPerGas1Array;

    uint224 public rewardPerGas0Accumulator;

    uint224 public rewardPerGas1Accumulator;

    uint64 public rebalanceCount;


    receive() external payable {}

    constructor(
        IUniswapV3Pool _uniPool,
        ISilo _silo0,
        ISilo _silo1
    )
        AloeBlendERC20(

            string(
                abi.encodePacked(
                    "Aloe Blend ",
                    IERC20Metadata(_uniPool.token0()).symbol(),
                    "/",
                    IERC20Metadata(_uniPool.token1()).symbol()
                )
            )
        )
        UniswapHelper(_uniPool)
    {
        volatilityOracle = IFactory(msg.sender).VOLATILITY_ORACLE();
        silo0 = _silo0;
        silo1 = _silo1;
        recenterTimestamp = block.timestamp;

        (uint32 oldestObservation, , , ) = volatilityOracle.cachedPoolMetadata(address(_uniPool));
        require(oldestObservation >= 1 hours, "Aloe: oracle");
    }


    function getInventory() public view returns (uint256 inventory0, uint256 inventory1) {
        (uint160 sqrtPriceX96, , , , , , ) = UNI_POOL.slot0();
        (inventory0, inventory1, , ) = _getDetailedInventory(sqrtPriceX96, true);
    }

    function _getDetailedInventory(uint160 sqrtPriceX96, bool includeLimit)
        private
        view
        returns (
            uint256 inventory0,
            uint256 inventory1,
            uint256 availableForLimit0,
            uint256 availableForLimit1
        )
    {
        if (includeLimit) {
            (availableForLimit0, availableForLimit1) = limit.collectableAmountsAsOfLastPoke(UNI_POOL, sqrtPriceX96);
        }

        availableForLimit0 += silo0.balanceOf(address(this)) + _balance0();
        availableForLimit1 += silo1.balanceOf(address(this)) + _balance1();


        (inventory0, inventory1) = primary.collectableAmountsAsOfLastPoke(UNI_POOL, sqrtPriceX96);
        inventory0 += availableForLimit0;
        inventory1 += availableForLimit1;
    }


    function getRebalanceUrgency() public view returns (uint32 urgency) {
        urgency = uint32(FullMath.mulDiv(10_000, block.timestamp - recenterTimestamp, 24 hours));
    }


    function deposit(
        uint256 amount0Max,
        uint256 amount1Max,
        uint256 amount0Min,
        uint256 amount1Min
    )
        external
        nonReentrant
        returns (
            uint256 shares,
            uint256 amount0,
            uint256 amount1
        )
    {
        require(amount0Max != 0 || amount1Max != 0, "Aloe: 0 deposit");


        primary.poke(UNI_POOL);
        limit.poke(UNI_POOL);
        silo0.delegate_poke();
        silo1.delegate_poke();


        (uint160 sqrtPriceX96, , , , , , ) = UNI_POOL.slot0();
        uint224 priceX96 = uint224(FullMath.mulDiv(sqrtPriceX96, sqrtPriceX96, Q96));

        (shares, amount0, amount1) = _computeLPShares(amount0Max, amount1Max, priceX96);
        require(shares != 0, "Aloe: 0 shares");
        require(amount0 >= amount0Min, "Aloe: amount0 too low");
        require(amount1 >= amount1Min, "Aloe: amount1 too low");


        TOKEN0.safeTransferFrom(msg.sender, address(this), amount0);
        TOKEN1.safeTransferFrom(msg.sender, address(this), amount1);


        _mint(msg.sender, shares);
        emit Deposit(msg.sender, shares, amount0, amount1);
    }


    function withdraw(
        uint256 shares,
        uint256 amount0Min,
        uint256 amount1Min
    ) external nonReentrant returns (uint256 amount0, uint256 amount1) {
        require(shares != 0, "Aloe: 0 shares");
        uint256 _totalSupply = totalSupply + 1;
        uint256 temp0;
        uint256 temp1;



        amount0 = FullMath.mulDiv(_balance0(), shares, _totalSupply);
        amount1 = FullMath.mulDiv(_balance1(), shares, _totalSupply);


        (temp0, temp1) = _withdrawFractionFromUniswap(shares, _totalSupply);
        amount0 += temp0;
        amount1 += temp1;


        temp0 = FullMath.mulDiv(silo0.balanceOf(address(this)), shares, _totalSupply);
        temp1 = FullMath.mulDiv(silo1.balanceOf(address(this)), shares, _totalSupply);
        silo0.delegate_withdraw(temp0);
        silo1.delegate_withdraw(temp1);
        amount0 += temp0;
        amount1 += temp1;


        require(amount0 >= amount0Min, "Aloe: amount0 too low");
        require(amount1 >= amount1Min, "Aloe: amount1 too low");


        TOKEN0.safeTransfer(msg.sender, amount0);
        TOKEN1.safeTransfer(msg.sender, amount1);


        _burn(msg.sender, shares);
        emit Withdraw(msg.sender, shares, amount0, amount1);
    }

    struct RebalanceCache {
        uint160 sqrtPriceX96;
        uint96 magic;
        int24 tick;
        uint24 w;
        uint32 urgency;
        uint224 priceX96;
    }


    function rebalance(uint8 rewardToken) external nonReentrant {
        uint32 gasStart = uint32(gasleft());
        RebalanceCache memory cache;


        (cache.sqrtPriceX96, cache.tick, , , , , ) = UNI_POOL.slot0();
        cache.priceX96 = uint224(FullMath.mulDiv(cache.sqrtPriceX96, cache.sqrtPriceX96, Q96));

        cache.urgency = getRebalanceUrgency();

        Uniswap.Position memory _limit = limit;
        (uint128 liquidity, , , , ) = _limit.info(UNI_POOL);
        _limit.withdraw(UNI_POOL, liquidity);

        (uint256 inventory0, uint256 inventory1, uint256 fluid0, uint256 fluid1) = _getDetailedInventory(
            cache.sqrtPriceX96,
            false
        );
        uint256 ratio = FullMath.mulDiv(
            10_000,
            inventory0,
            inventory0 + FullMath.mulDiv(inventory1, Q96, cache.priceX96)
        );

        if (ratio < 4900) {

            _limit.upper = TickMath.floor(cache.tick, TICK_SPACING);
            _limit.lower = _limit.upper - TICK_SPACING;



            uint256 amount1 = (inventory1 - FullMath.mulDiv(inventory0, cache.priceX96, Q96)) >> 1;
            if (amount1 > fluid1) amount1 = fluid1;

            uint256 balance1 = _balance1();
            if (balance1 < amount1) silo1.delegate_withdraw(amount1 - balance1);

            _limit.deposit(UNI_POOL, _limit.liquidityForAmount1(amount1));
            limit.lower = _limit.lower;
            limit.upper = _limit.upper;
        } else if (ratio > 5100) {

            _limit.lower = TickMath.ceil(cache.tick, TICK_SPACING);
            _limit.upper = _limit.lower + TICK_SPACING;



            uint256 amount0 = (inventory0 - FullMath.mulDiv(inventory1, Q96, cache.priceX96)) >> 1;
            if (amount0 > fluid0) amount0 = fluid0;

            uint256 balance0 = _balance0();
            if (balance0 < amount0) silo0.delegate_withdraw(amount0 - balance0);

            _limit.deposit(UNI_POOL, _limit.liquidityForAmount0(amount0));
            limit.lower = _limit.lower;
            limit.upper = _limit.upper;
        } else {
            recenter(cache, inventory0, inventory1);
        }


        {
            (, , uint256 earned0, uint256 earned1) = primary.withdraw(UNI_POOL, 0);
            _earmarkSomeForMaintenance(earned0, earned1);
        }


        {
            uint32 gasUsed = uint32(21000 + gasStart - gasleft());
            if (rewardToken == 0) {

                uint224 rewardPerGas = uint224(FullMath.mulDiv(rewardPerGas0Accumulator, cache.urgency, 10_000));
                uint256 rebalanceIncentive = gasUsed * rewardPerGas;

                if (rewardPerGas == 0 || rebalanceIncentive > maintenanceBudget0)
                    rebalanceIncentive = maintenanceBudget0;

                TOKEN0.safeTransfer(msg.sender, rebalanceIncentive);

                pushRewardPerGas0(rewardPerGas);
                maintenanceBudget0 -= rebalanceIncentive;
                if (maintenanceBudget0 > K * rewardPerGas * block.gaslimit)
                    maintenanceBudget0 = K * rewardPerGas * block.gaslimit;
            } else {

                uint224 rewardPerGas = uint224(FullMath.mulDiv(rewardPerGas1Accumulator, cache.urgency, 10_000));
                uint256 rebalanceIncentive = gasUsed * rewardPerGas;

                if (rewardPerGas == 0 || rebalanceIncentive > maintenanceBudget1)
                    rebalanceIncentive = maintenanceBudget1;

                TOKEN1.safeTransfer(msg.sender, rebalanceIncentive);

                pushRewardPerGas1(rewardPerGas);
                maintenanceBudget1 -= rebalanceIncentive;
                if (maintenanceBudget1 > K * rewardPerGas * block.gaslimit)
                    maintenanceBudget1 = K * rewardPerGas * block.gaslimit;
            }
        }

        rebalanceCount++;
        emit Rebalance(cache.urgency, ratio, totalSupply, inventory0, inventory1);
    }

    function recenter(
        RebalanceCache memory cache,
        uint256 inventory0,
        uint256 inventory1
    ) private {
        Uniswap.Position memory _primary = primary;

        uint256 sigma = volatilityOracle.estimate24H(UNI_POOL, cache.sqrtPriceX96, cache.tick);
        cache.w = _computeNextPositionWidth(sigma);


        {
            (uint128 liquidity, , , , ) = _primary.info(UNI_POOL);
            (, , uint256 earned0, uint256 earned1) = _primary.withdraw(UNI_POOL, liquidity);
            _earmarkSomeForMaintenance(earned0, earned1);
        }


        uint256 amount0;
        uint256 amount1;
        cache.w = cache.w >> 1;
        (amount0, amount1, cache.magic) = _computeAmountsForPrimary(inventory0, inventory1, cache.priceX96, cache.w);

        uint256 balance0 = _balance0();
        uint256 balance1 = _balance1();
        bool hasExcessToken0 = balance0 > amount0;
        bool hasExcessToken1 = balance1 > amount1;



        if (!hasExcessToken0) silo0.delegate_withdraw(amount0 - balance0);
        if (!hasExcessToken1) silo1.delegate_withdraw(amount1 - balance1);


        _primary.lower = TickMath.floor(cache.tick - int24(cache.w), TICK_SPACING);
        _primary.upper = TickMath.ceil(cache.tick + int24(cache.w), TICK_SPACING);
        if (_primary.lower < TickMath.MIN_TICK) _primary.lower = TickMath.MIN_TICK;
        if (_primary.upper > TickMath.MAX_TICK) _primary.upper = TickMath.MAX_TICK;


        delete lastMintedAmount0;
        delete lastMintedAmount1;
        _primary.deposit(UNI_POOL, _primary.liquidityForAmounts(cache.sqrtPriceX96, amount0, amount1));
        primary.lower = _primary.lower;
        primary.upper = _primary.upper;


        if (hasExcessToken0) silo0.delegate_deposit(balance0 - lastMintedAmount0);
        if (hasExcessToken1) silo1.delegate_deposit(balance1 - lastMintedAmount1);

        recenterTimestamp = block.timestamp;
        emit Recenter(_primary.lower, _primary.upper, cache.magic);
    }




    function _computeLPShares(
        uint256 amount0Max,
        uint256 amount1Max,
        uint224 priceX96
    )
        private
        view
        returns (
            uint256 shares,
            uint256 amount0,
            uint256 amount1
        )
    {
        uint256 _totalSupply = totalSupply;
        (uint256 inventory0, uint256 inventory1) = getInventory();


        assert(_totalSupply == 0 || inventory0 != 0 || inventory1 != 0);

        if (_totalSupply == 0) {

            amount0 = FullMath.mulDiv(amount1Max, Q96, priceX96);

            if (amount0 < amount0Max) {
                amount1 = amount1Max;
                shares = amount1;
            } else {
                amount0 = amount0Max;
                amount1 = FullMath.mulDiv(amount0, priceX96, Q96);
                shares = amount0;
            }
        } else if (inventory0 == 0) {
            amount1 = amount1Max;
            shares = FullMath.mulDiv(amount1, _totalSupply, inventory1);
        } else if (inventory1 == 0) {
            amount0 = amount0Max;
            shares = FullMath.mulDiv(amount0, _totalSupply, inventory0);
        } else {
            amount0 = FullMath.mulDiv(amount1Max, inventory0, inventory1);

            if (amount0 < amount0Max) {
                amount1 = amount1Max;
                shares = FullMath.mulDiv(amount1, _totalSupply, inventory1);
            } else {
                amount0 = amount0Max;
                amount1 = FullMath.mulDiv(amount0, inventory1, inventory0);
                shares = FullMath.mulDiv(amount0, _totalSupply, inventory0);
            }
        }
    }


    function _computeAmountsForPrimary(
        uint256 inventory0,
        uint256 inventory1,
        uint224 priceX96,
        uint24 halfWidth
    )
        internal
        pure
        returns (
            uint256 amount0,
            uint256 amount1,
            uint96 magic
        )
    {
        magic = uint96(Q96 - TickMath.getSqrtRatioAtTick(-int24(halfWidth)));
        if (FullMath.mulDiv(inventory0, priceX96, Q96) > inventory1) {
            amount1 = FullMath.mulDiv(inventory1, magic, Q96);
            amount0 = FullMath.mulDiv(amount1, Q96, priceX96);
        } else {
            amount0 = FullMath.mulDiv(inventory0, magic, Q96);
            amount1 = FullMath.mulDiv(amount0, priceX96, Q96);
        }
    }


    function _computeNextPositionWidth(uint256 sigma) internal pure returns (uint24) {
        if (sigma <= 5.024579e15) return MIN_WIDTH;
        if (sigma >= 3.000058e17) return MAX_WIDTH;
        sigma *= B; 

        unchecked {
            uint160 ratio = uint160((Q96 * (1e18 + sigma)) / (1e18 - sigma));
            return uint24(TickMath.getTickAtSqrtRatio(ratio)) >> 1;
        }
    }


    function _withdrawFractionFromUniswap(uint256 numerator, uint256 denominator)
        private
        returns (uint256 amount0, uint256 amount1)
    {
        assert(numerator < denominator);

        Uniswap.Position memory _primary = primary;
        (uint128 liquidity, , , , ) = _primary.info(UNI_POOL);
        liquidity = uint128(FullMath.mulDiv(liquidity, numerator, denominator));

        uint256 earned0;
        uint256 earned1;
        (amount0, amount1, earned0, earned1) = _primary.withdraw(UNI_POOL, liquidity);
        (earned0, earned1) = _earmarkSomeForMaintenance(earned0, earned1);


        amount0 += FullMath.mulDiv(earned0, numerator, denominator);
        amount1 += FullMath.mulDiv(earned1, numerator, denominator);


        Uniswap.Position memory _limit = limit;
        (liquidity, , , , ) = _limit.info(UNI_POOL);
        liquidity = uint128(FullMath.mulDiv(liquidity, numerator, denominator));

        if (liquidity != 0) {
            (uint256 temp0, uint256 temp1, , ) = _limit.withdraw(UNI_POOL, liquidity);
            amount0 += temp0;
            amount1 += temp1;
        }
    }


    function _earmarkSomeForMaintenance(uint256 earned0, uint256 earned1) private returns (uint256, uint256) {
        uint256 toMaintenance;

        unchecked {

            toMaintenance = earned0 / MAINTENANCE_FEE;
            earned0 -= toMaintenance;
            maintenanceBudget0 += toMaintenance;

            toMaintenance = earned1 / MAINTENANCE_FEE;
            earned1 -= toMaintenance;
            maintenanceBudget1 += toMaintenance;
        }

        return (earned0, earned1);
    }

    function pushRewardPerGas0(uint224 rewardPerGas0) private {
        unchecked {
            rewardPerGas0 /= 10;
            rewardPerGas0Accumulator =
                rewardPerGas0Accumulator +
                rewardPerGas0 -
                rewardPerGas0Array[rebalanceCount % 10];
            rewardPerGas0Array[rebalanceCount % 10] = rewardPerGas0;
        }
    }

    function pushRewardPerGas1(uint224 rewardPerGas1) private {
        unchecked {
            rewardPerGas1 /= 10;
            rewardPerGas1Accumulator =
                rewardPerGas1Accumulator +
                rewardPerGas1 -
                rewardPerGas1Array[rebalanceCount % 10];
            rewardPerGas1Array[rebalanceCount % 10] = rewardPerGas1;
        }
    }

    function _balance0() private view returns (uint256) {
        return TOKEN0.balanceOf(address(this)) - maintenanceBudget0;
    }

    function _balance1() private view returns (uint256) {
        return TOKEN1.balanceOf(address(this)) - maintenanceBudget1;
    }
}

pragma solidity ^0.8.2;

import "../../../../interfaces/IApeVault.sol";
import "../../ApeDistributor.sol";
import "../../ApeAllowanceModule.sol";
import "../../ApeRegistry.sol";
import "../../FeeRegistry.sol";
import "../../ApeRouter.sol";

import "./BaseWrapperImplementation.sol";

abstract contract OwnableImplementation {
    address internal _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == msg.sender, "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        emit OwnershipTransferred(_owner, address(0));
        _owner = address(0);
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        emit OwnershipTransferred(_owner, newOwner);
        _owner = newOwner;
    }
}

contract ApeVaultWrapperImplementation is BaseWrapperImplementation, OwnableImplementation {
	using SafeERC20 for VaultAPI;
	using SafeERC20 for IERC20;

	uint256 constant TOTAL_SHARES = 10000;

	IERC20 public simpleToken;

	mapping(address => bool) public hasAccess;

	bool internal setup;
	uint256 public underlyingValue;
	address public apeRegistry;
	VaultAPI public vault;

	ApeAllowanceModule public allowanceModule;

	function init(
		address _apeRegistry,
		address _token,
		address _registry,
		address _simpleToken,
		address _newOwner) external {
		require(!setup);
		setup = true;
		apeRegistry = _apeRegistry;
		if (_token != address(0))
			vault = VaultAPI(RegistryAPI(_registry).latestVault(_token));
		simpleToken = IERC20(_simpleToken);


        token = IERC20(_token);

        registry = RegistryAPI(_registry);
		_owner = _newOwner;
        emit OwnershipTransferred(address(0), _newOwner);
	}

	event ApeVaultFundWithdrawal(address indexed apeVault, address vault, uint256 _amount, bool underlying);

	modifier onlyDistributor() {
		require(msg.sender == ApeRegistry(apeRegistry).distributor());
		_;
	}

	modifier onlyRouter() {
		require(msg.sender == ApeRegistry(apeRegistry).router());
		_;
	}

	function _shareValue(uint256 numShares) internal view returns (uint256) {
		return vault.pricePerShare() * numShares / (10**uint256(vault.decimals()));
    }

    function _sharesForValue(uint256 amount) internal view returns (uint256) {
		return amount * (10**uint256(vault.decimals())) / vault.pricePerShare();
    }


	function profit() public view returns(uint256) {
		uint256 totalValue = _shareValue(vault.balanceOf(address(this)));
		if (totalValue <= underlyingValue)
			return 0;
		else
			return totalValue - underlyingValue;
	}



	function apeWithdrawSimpleToken(uint256 _amount) public {
		simpleToken.safeTransfer(msg.sender, _amount);
	}


	function apeWithdraw(uint256 _shareAmount, bool _underlying) external onlyOwner {
		uint256 underlyingAmount = _shareValue(_shareAmount);
		require(underlyingAmount <= underlyingValue, "underlying amount higher than vault value");

		address router = ApeRegistry(apeRegistry).router();
		underlyingValue -= underlyingAmount;
		vault.transfer(router, _shareAmount);
		ApeRouter(router).delegateWithdrawal(owner(), address(this), vault.token(), _shareAmount, _underlying);
	}


	function exitVaultToken(bool _underlying) external onlyOwner {
		underlyingValue = 0;
		uint256 totalShares = vault.balanceOf(address(this));
		address router = ApeRegistry(apeRegistry).router();
		vault.transfer(router, totalShares);
		ApeRouter(router).delegateWithdrawal(owner(), address(this), vault.token(), totalShares, _underlying);
	}


	function apeMigrate() external onlyOwner returns(uint256 migrated){
		migrated = _migrate(address(this));
		vault = VaultAPI(registry.latestVault(address(token)));
	}


	function tap(uint256 _value, uint8 _type) external onlyDistributor returns(uint256) {
		if (_type == uint8(0)) {
			_tapOnlyProfit(_value, msg.sender);
			return _value;
		}
		else if (_type == uint8(1)) {
			_tapBase(_value, msg.sender);
			return _value;
		}
		else if (_type == uint8(2))
			_tapSimpleToken(_value, msg.sender);
		return (0);
	}



	function _tapOnlyProfit(uint256 _tapValue, address _recipient) internal {
		uint256 fee = FeeRegistry(ApeRegistry(apeRegistry).feeRegistry()).getVariableFee(_tapValue, _tapValue);
		uint256 finalTapValue = _tapValue + _tapValue * fee / TOTAL_SHARES;
		require(_shareValue(finalTapValue) <= profit(), "Not enough profit to cover epoch");
		vault.safeTransfer(_recipient, _tapValue);
		vault.safeTransfer(ApeRegistry(apeRegistry).treasury(), _tapValue * fee / TOTAL_SHARES);
	}


	function _tapBase(uint256 _tapValue, address _recipient) internal {
		uint256 underlyingTapValue = _shareValue(_tapValue);
		uint256 profit_ = profit();
		uint256 fee = FeeRegistry(ApeRegistry(apeRegistry).feeRegistry()).getVariableFee(profit_, underlyingTapValue);
		uint256 finalTapValue = underlyingTapValue + underlyingTapValue * fee / TOTAL_SHARES;
		if (finalTapValue > profit_)
			underlyingValue -= finalTapValue - profit_;
		vault.transfer(_recipient, _tapValue);
		vault.transfer(ApeRegistry(apeRegistry).treasury(), _tapValue * fee / TOTAL_SHARES);
	}


	function _tapSimpleToken(uint256 _tapValue, address _recipient) internal {
		uint256 feeAmount = _tapValue * FeeRegistry(ApeRegistry(apeRegistry).feeRegistry()).staticFee() / TOTAL_SHARES;
		simpleToken.transfer(_recipient, _tapValue);
		simpleToken.transfer(ApeRegistry(apeRegistry).treasury(), feeAmount);
	}


	function syncUnderlying() external onlyOwner {
		underlyingValue = _shareValue(vault.balanceOf(address(this)));
	}


	function addFunds(uint256 _amount) external onlyRouter {
		underlyingValue += _amount;
	}


	function updateCircleAdmin(bytes32 _circle, address _admin) external onlyOwner {
		ApeDistributor(ApeRegistry(apeRegistry).distributor()).updateCircleAdmin(_circle, _admin);
	}


	function updateAllowance(
		bytes32 _circle,
		address _token,
		uint256 _amount,
		uint256 _interval,
		uint256 _epochAmount,
		uint256 _intervalStart
		) external onlyOwner {
		ApeDistributor(
			ApeRegistry(apeRegistry).distributor()
		).setAllowance(_circle, _token, _amount, _interval, _epochAmount, _intervalStart);
	}
}

