  function approve(address spender, uint256 amount) external override returns (bool) {
    _approve(_msgSender(), spender, amount);
    return true;
  }

  function transferFrom(address sender, address recipient, uint256 amount) external override returns (bool) {
    _transfer(sender, recipient, amount);
    _approve(sender, _msgSender(), _allowances[sender][_msgSender()].sub(amount, "BEP20: transfer amount exceeds allowance"));
    return true;
  }

  function increaseAllowance(address spender, uint256 addedValue) public returns (bool) {
    _approve(_msgSender(), spender, _allowances[_msgSender()][spender].add(addedValue));
    return true;
  }

  function decreaseAllowance(address spender, uint256 subtractedValue) public returns (bool) {
    _approve(_msgSender(), spender, _allowances[_msgSender()][spender].sub(subtractedValue, "BEP20: decreased allowance below zero"));
    return true;
  }

  function _transfer(address sender, address recipient, uint256 amount) internal {
    require(sender != address(0), "BEP20: transfer from the zero address");
    require(recipient != address(0), "BEP20: transfer to the zero address");
    _balances[sender] = _balances[sender].sub(amount, "BEP20: transfer amount exceeds balance");
    _balances[recipient] = _balances[recipient].add(amount);
    emit Transfer(sender, recipient, amount);
  }

  function _approve(address owner, address spender, uint256 amount) internal {
    require(owner != address(0), "BEP20: approve from the zero address");
    require(spender != address(0), "BEP20: approve to the zero address");
    _allowances[owner][spender] = amount;
    emit Approval(owner, spender, amount);
  }
}

import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";


pragma solidity 0.8.10;


interface Token {
    function balanceOf(address who) external view returns (uint256);
    function transfer(address to, uint256 value) external returns (bool);
    function transferFrom(address from, address to, uint256 value) external returns (bool);
}


contract WorthTokenTimeLock is Ownable{
    using SafeMath for uint256;


    struct Items {
        address tokenAddress;
        address withdrawalAddress;
        uint256 tokenAmount;
        uint256 unlockTime;
        bool withdrawn;
    }

    uint256 public depositId;
    uint256[] public allDepositIds;
    mapping (address => uint256[]) public depositsByWithdrawalAddress;
    mapping (uint256 => Items) public lockedToken;
    mapping (address => mapping(address => uint256)) public walletTokenBalance;

    event LogWithdrawal(address sentToAddress, uint256 amountTransferred);







    function lockTokens(address _tokenAddress, address _withdrawalAddress, uint256 _amount, uint256 _unlockTime) external returns (uint256 _id) {
        require(_amount > 0, "Amount should be greater than 0");
        require(_unlockTime <= 3217825449, "Enter a valid unlock time");


        walletTokenBalance[_tokenAddress][_withdrawalAddress] = walletTokenBalance[_tokenAddress][_withdrawalAddress].add(_amount);

        _id = ++depositId;
        lockedToken[_id].tokenAddress = _tokenAddress;
        lockedToken[_id].withdrawalAddress = _withdrawalAddress;
        lockedToken[_id].tokenAmount = _amount;
        lockedToken[_id].unlockTime = _unlockTime;
        lockedToken[_id].withdrawn = false;


        allDepositIds.push(_id);
        depositsByWithdrawalAddress[_withdrawalAddress].push(_id);


        require(Token(_tokenAddress).transferFrom(msg.sender, address(this), _amount), "Transfer Failed");
    }








    function createMultipleLocks(address _tokenAddress, address _withdrawalAddress, uint256[] memory _amounts, uint256[] memory _unlockTimes) external returns (uint256 _id) {
        require(_amounts.length > 0, "Enter at least 1 value");
        require(_amounts.length == _unlockTimes.length, "Number of amounts and number of unlock times should be equal");

        uint256 i;
        for(i=0; i<_amounts.length; i++){
            require(_amounts[i] > 0, "Amount should be greater than 0");     
            require(_unlockTimes[i] <= 3217825449, "Enter valid unlock time");


            walletTokenBalance[_tokenAddress][_withdrawalAddress] = walletTokenBalance[_tokenAddress][_withdrawalAddress].add(_amounts[i]);

            _id = ++depositId;
            lockedToken[_id].tokenAddress = _tokenAddress;
            lockedToken[_id].withdrawalAddress = _withdrawalAddress;
            lockedToken[_id].tokenAmount = _amounts[i];
            lockedToken[_id].unlockTime = _unlockTimes[i];
            lockedToken[_id].withdrawn = false;

            allDepositIds.push(_id);
            depositsByWithdrawalAddress[_withdrawalAddress].push(_id);


            require(Token(_tokenAddress).transferFrom(msg.sender, address(this), _amounts[i]), "Transfer Failed");
        }
    }





    function extendLockDuration(uint256 _id, uint256 _unlockTime) external {
        require(_unlockTime <= 3217825449, "Enter a valid unlock time");
        require(!lockedToken[_id].withdrawn, "Tokens already withdrawn");
        require(msg.sender == lockedToken[_id].withdrawalAddress,"Not the same withdrawal address");
        require(_unlockTime >= lockedToken[_id].unlockTime,"Cannot have time duration less than the previous one");


        lockedToken[_id].unlockTime = _unlockTime;
    }




    function withdrawTokens(uint256 _id) external {
        require(block.timestamp >= lockedToken[_id].unlockTime, "Unlock time not reached");
        require(msg.sender == lockedToken[_id].withdrawalAddress, "Not the same withdrawal address");
        require(!lockedToken[_id].withdrawn, "Tokens already withdrawn");

        lockedToken[_id].withdrawn = true;


        walletTokenBalance[lockedToken[_id].tokenAddress][msg.sender] = walletTokenBalance[lockedToken[_id].tokenAddress][msg.sender].sub(lockedToken[_id].tokenAmount);


        uint256 j;
        uint256 arrLength = depositsByWithdrawalAddress[lockedToken[_id].withdrawalAddress].length;
        for (j=0; j<arrLength; j++) {
            if (depositsByWithdrawalAddress[lockedToken[_id].withdrawalAddress][j] == _id) {
                depositsByWithdrawalAddress[lockedToken[_id].withdrawalAddress][j] = depositsByWithdrawalAddress[lockedToken[_id].withdrawalAddress][arrLength - 1];
                depositsByWithdrawalAddress[lockedToken[_id].withdrawalAddress].pop();
                break;
            }
        }


        require(Token(lockedToken[_id].tokenAddress).transfer(msg.sender, lockedToken[_id].tokenAmount), "Transfer Failed");
        emit LogWithdrawal(msg.sender, lockedToken[_id].tokenAmount);
    }




    function getTotalTokenBalance(address _tokenAddress) view public returns (uint256)
    {
       return Token(_tokenAddress).balanceOf(address(this));
    }





    function getTokenBalanceByAddress(address _tokenAddress, address _walletAddress) view public returns (uint256)
    {
       return walletTokenBalance[_tokenAddress][_walletAddress];
    }




    function getAllDepositIds() view public returns (uint256[] memory)
    {
        return allDepositIds;
    }




    function getDepositDetails(uint256 _id) view public returns (address _tokenAddress, address _withdrawalAddress, uint256 _tokenAmount, uint256 _unlockTime, bool _withdrawn)
    {
        return(lockedToken[_id].tokenAddress,lockedToken[_id].withdrawalAddress,lockedToken[_id].tokenAmount,
        lockedToken[_id].unlockTime,lockedToken[_id].withdrawn);
    }




    function getDepositsByWithdrawalAddress(address _withdrawalAddress) view public returns (uint256[] memory)
    {
        return depositsByWithdrawalAddress[_withdrawalAddress];
    }
}

pragma solidity =0.6.12;

interface ERC20Like {
    function decimals()                 external view returns (uint8);
    function totalSupply()              external view returns (uint256);
}

interface GUNILike {
    function token0()                               external view returns (address);
    function token1()                               external view returns (address);
    function getUnderlyingBalancesAtPrice(uint160)  external view returns (uint256,uint256);
}

interface OracleLike {
    function read() external view returns (uint256);
}


contract GUniLPOracleFactory {

    mapping(address => bool) public isOracle;

    event NewGUniLPOracle(address owner, address orcl, bytes32 wat, address indexed tok0, address indexed tok1, address orb0, address orb1);


    function build(
        address _owner,
        address _src,
        bytes32 _wat,
        address _orb0,
        address _orb1
    ) public returns (address orcl) {
        address tok0 = GUNILike(_src).token0();
        address tok1 = GUNILike(_src).token1();
        orcl = address(new GUniLPOracle(_src, _wat, _orb0, _orb1));
        GUniLPOracle(orcl).rely(_owner);
        GUniLPOracle(orcl).deny(address(this));
        isOracle[orcl] = true;
        emit NewGUniLPOracle(_owner, orcl, _wat, tok0, tok1, _orb0, _orb1);
    }
}

contract GUniLPOracle {


    mapping (address => uint256) public wards;                                       
    function rely(address _usr) external auth { wards[_usr] = 1; emit Rely(_usr); }  
    function deny(address _usr) external auth { wards[_usr] = 0; emit Deny(_usr); }  
    modifier auth {
        require(wards[msg.sender] == 1, "GUniLPOracle/not-authorized");
        _;
    }

    address public immutable src;   



    uint8   public stopped;         
    uint16  public hop = 1 hours;   
    uint232 public zph;             

    bytes32 public immutable wat;   


    mapping (address => uint256) public bud;
    modifier toll { require(bud[msg.sender] == 1, "GUniLPOracle/contract-not-whitelisted"); _; }

    struct Feed {
        uint128 val;  
        uint128 has;  
    }

    Feed    internal cur;  
    Feed    internal nxt;  


    uint256 private immutable UNIT_0;  
    uint256 private immutable UNIT_1;  
    uint256 private immutable TO_18_DEC_0;  
    uint256 private immutable TO_18_DEC_1;  

    address public            orb0;  
    address public            orb1;  



    uint256 constant WAD = 10 ** 18;

    function _add(uint256 _x, uint256 _y) internal pure returns (uint256 z) {
        require((z = _x + _y) >= _x, "GUniLPOracle/add-overflow");
    }
    function _sub(uint256 _x, uint256 _y) internal pure returns (uint256 z) {
        require((z = _x - _y) <= _x, "GUniLPOracle/sub-underflow");
    }
    function _mul(uint256 _x, uint256 _y) internal pure returns (uint256 z) {
        require(_y == 0 || (z = _x * _y) / _y == _x, "GUniLPOracle/mul-overflow");
    }
    function toUint160(uint256 x) internal pure returns (uint160 z) {
        require((z = uint160(x)) == x, "GUniLPOracle/uint160-overflow");
    }


    function sqrt(uint256 _x) private pure returns (uint128) {
        if (_x == 0) return 0;
        else {
            uint256 xx = _x;
            uint256 r = 1;
            if (xx >= 0x100000000000000000000000000000000) { xx >>= 128; r <<= 64; }
            if (xx >= 0x10000000000000000) { xx >>= 64; r <<= 32; }
            if (xx >= 0x100000000) { xx >>= 32; r <<= 16; }
            if (xx >= 0x10000) { xx >>= 16; r <<= 8; }
            if (xx >= 0x100) { xx >>= 8; r <<= 4; }
            if (xx >= 0x10) { xx >>= 4; r <<= 2; }
            if (xx >= 0x8) { r <<= 1; }
            r = (r + _x / r) >> 1;
            r = (r + _x / r) >> 1;
            r = (r + _x / r) >> 1;
            r = (r + _x / r) >> 1;
            r = (r + _x / r) >> 1;
            r = (r + _x / r) >> 1;
            r = (r + _x / r) >> 1; 
            uint256 r1 = _x / r;
            return uint128 (r < r1 ? r : r1);
        }
    }


    event Rely(address indexed usr);
    event Deny(address indexed usr);
    event Step(uint256 hop);
    event Stop();
    event Start();
    event Value(uint128 curVal, uint128 nxtVal);
    event Link(uint256 id, address orb);
    event Kiss(address a);
    event Diss(address a);


    constructor (address _src, bytes32 _wat, address _orb0, address _orb1) public {
        require(_src  != address(0),                        "GUniLPOracle/invalid-src-address");
        require(_orb0 != address(0) && _orb1 != address(0), "GUniLPOracle/invalid-oracle-address");
        wards[msg.sender] = 1;
        emit Rely(msg.sender);
        src  = _src;
        wat  = _wat;
        uint256 dec0 = uint256(ERC20Like(GUNILike(_src).token0()).decimals());
        require(dec0 <= 18, "GUniLPOracle/token0-dec-gt-18");
        UNIT_0 = 10 ** dec0;
        TO_18_DEC_0 = 10 ** (18 - dec0);
        uint256 dec1 = uint256(ERC20Like(GUNILike(_src).token1()).decimals());
        require(dec1 <= 18, "GUniLPOracle/token1-dec-gt-18");
        UNIT_1 = 10 ** dec1;
        TO_18_DEC_1 = 10 ** (18 - dec1);
        orb0 = _orb0;
        orb1 = _orb1;
    }

    function stop() external auth {
        stopped = 1;
        delete cur;
        delete nxt;
        zph = 0;
        emit Stop();
    }

    function start() external auth {
        stopped = 0;
        emit Start();
    }

    function step(uint256 _hop) external auth {
        require(_hop <= uint16(-1), "GUniLPOracle/invalid-hop");
        hop = uint16(_hop);
        emit Step(_hop);
    }

    function link(uint256 _id, address _orb) external auth {
        require(_orb != address(0), "GUniLPOracle/no-contract-0");
        if(_id == 0) {
            orb0 = _orb;
        } else if (_id == 1) {
            orb1 = _orb;
        } else {
            revert("GUniLPOracle/invalid-id");
        }
        emit Link(_id, _orb);
    }


    function zzz() external view returns (uint256) {
        if (zph == 0) return 0;  
        return _sub(zph, hop);
    }

    function pass() external view returns (bool) {
        return block.timestamp >= zph;
    }

    function seek() internal returns (uint128 quote) {

        uint256 p0 = OracleLike(orb0).read();  
        require(p0 != 0, "GUniLPOracle/invalid-oracle-0-price");
        uint256 p1 = OracleLike(orb1).read();  
        require(p1 != 0, "GUniLPOracle/invalid-oracle-1-price");
        uint160 sqrtPriceX96 = toUint160(sqrt(_mul(_mul(p0, UNIT_1), (1 << 96)) / (_mul(p1, UNIT_0))) << 48);


        (uint256 r0, uint256 r1) = GUNILike(src).getUnderlyingBalancesAtPrice(sqrtPriceX96);
        require(r0 > 0 || r1 > 0, "GUniLPOracle/invalid-balances");
        uint256 totalSupply = ERC20Like(src).totalSupply();
        require(totalSupply >= 1e9, "GUniLPOracle/total-supply-too-small"); 


        uint256 preq = _add(
            _mul(p0, _mul(r0, TO_18_DEC_0)),
            _mul(p1, _mul(r1, TO_18_DEC_1))
        ) / totalSupply;
        require(preq < 2 ** 128, "GUniLPOracle/quote-overflow");
        quote = uint128(preq);  
    }

    function poke() external {


        uint256 hop_;
        {


            uint256 stopped_;
            uint256 zph_;
            assembly {
                let slot1 := sload(1)
                stopped_  := and(slot1,         0xff  )
                hop_      := and(shr(8, slot1), 0xffff)
                zph_      := shr(24, slot1)
            }


            require(stopped_ == 0, "GUniLPOracle/is-stopped");




            require(block.timestamp >= zph_, "GUniLPOracle/not-passed");
        }

        uint128 val = seek();
        require(val != 0, "GUniLPOracle/invalid-price");
        Feed memory cur_ = nxt;  
        cur = cur_;
        nxt = Feed(val, 1);











        assembly {
            sstore(
                1,
                add(

                    shl(24, add(timestamp(), hop_)),


                    shl(8, hop_)
                )
            )
        }


        emit Value(cur_.val, val);


        assembly {
            stop()
        }
    }

    function peek() external view toll returns (bytes32,bool) {
        return (bytes32(uint256(cur.val)), cur.has == 1);
    }

    function peep() external view toll returns (bytes32,bool) {
        return (bytes32(uint256(nxt.val)), nxt.has == 1);
    }

    function read() external view toll returns (bytes32) {
        require(cur.has == 1, "GUniLPOracle/no-current-value");
        return (bytes32(uint256(cur.val)));
    }

    function kiss(address _a) external auth {
        require(_a != address(0), "GUniLPOracle/no-contract-0");
        bud[_a] = 1;
        emit Kiss(_a);
    }

    function kiss(address[] calldata _a) external auth {
        for(uint256 i = 0; i < _a.length; i++) {
            require(_a[i] != address(0), "GUniLPOracle/no-contract-0");
            bud[_a[i]] = 1;
            emit Kiss(_a[i]);
        }
    }

    function diss(address _a) external auth {
        bud[_a] = 0;
        emit Diss(_a);
    }

    function diss(address[] calldata _a) external auth {
        for(uint256 i = 0; i < _a.length; i++) {
            bud[_a[i]] = 0;
            emit Diss(_a[i]);
        }
    }
}

pragma solidity 0.8.6;





import "./libraries/Margin.sol";
import "./libraries/ReplicationMath.sol";
import "./libraries/Reserve.sol";
import "./libraries/SafeCast.sol";
import "./libraries/Transfers.sol";
import "./libraries/Units.sol";

import "./interfaces/callback/IPrimitiveCreateCallback.sol";
import "./interfaces/callback/IPrimitiveDepositCallback.sol";
import "./interfaces/callback/IPrimitiveLiquidityCallback.sol";
import "./interfaces/callback/IPrimitiveSwapCallback.sol";
import "./interfaces/IERC20.sol";
import "./interfaces/IPrimitiveEngine.sol";
import "./interfaces/IPrimitiveFactory.sol";

contract PrimitiveEngine is IPrimitiveEngine {
    using ReplicationMath for int128;
    using Units for uint256;
    using SafeCast for uint256;
    using Reserve for mapping(bytes32 => Reserve.Data);
    using Reserve for Reserve.Data;
    using Margin for mapping(address => Margin.Data);
    using Margin for Margin.Data;
    using Transfers for IERC20;







    struct Calibration {
        uint128 strike;
        uint64 sigma;
        uint32 maturity;
        uint32 lastTimestamp;
        uint32 creationTimestamp;
    }


    uint256 public constant override PRECISION = 10**18;

    uint256 public constant override GAMMA = 9985;

    uint256 public constant override BUFFER = 120 seconds;

    uint256 public immutable override MIN_LIQUIDITY;


    address public immutable override factory;

    address public immutable override risky;

    address public immutable override stable;

    uint256 public immutable override scaleFactorRisky;

    uint256 public immutable override scaleFactorStable;

    mapping(bytes32 => Calibration) public override calibrations;

    mapping(address => Margin.Data) public override margins;

    mapping(bytes32 => Reserve.Data) public override reserves;

    mapping(address => mapping(bytes32 => uint256)) public override liquidity;

    uint8 private unlocked = 1;

    modifier lock() {
        if (unlocked != 1) revert LockedError();

        unlocked = 0;
        _;
        unlocked = 1;
    }


    constructor() {
        (factory, risky, stable, scaleFactorRisky, scaleFactorStable, MIN_LIQUIDITY) = IPrimitiveFactory(msg.sender)
            .args();
    }


    function balanceRisky() private view returns (uint256) {
        (bool success, bytes memory data) = risky.staticcall(
            abi.encodeWithSelector(IERC20.balanceOf.selector, address(this))
        );
        if (!success || data.length < 32) revert BalanceError();
        return abi.decode(data, (uint256));
    }


    function balanceStable() private view returns (uint256) {
        (bool success, bytes memory data) = stable.staticcall(
            abi.encodeWithSelector(IERC20.balanceOf.selector, address(this))
        );
        if (!success || data.length < 32) revert BalanceError();
        return abi.decode(data, (uint256));
    }


    function checkRiskyBalance(uint256 expectedRisky) private view {
        uint256 actualRisky = balanceRisky();
        if (actualRisky < expectedRisky) revert RiskyBalanceError(expectedRisky, actualRisky);
    }


    function checkStableBalance(uint256 expectedStable) private view {
        uint256 actualStable = balanceStable();
        if (actualStable < expectedStable) revert StableBalanceError(expectedStable, actualStable);
    }


    function _blockTimestamp() internal view virtual returns (uint32 blockTimestamp) {

        blockTimestamp = uint32(block.timestamp);
    }


    function updateLastTimestamp(bytes32 poolId) external override lock returns (uint32 lastTimestamp) {
        lastTimestamp = _updateLastTimestamp(poolId);
    }



    function _updateLastTimestamp(bytes32 poolId) internal virtual returns (uint32 lastTimestamp) {
        Calibration storage cal = calibrations[poolId];
        if (cal.lastTimestamp == 0) revert UninitializedError();

        lastTimestamp = _blockTimestamp();
        uint32 maturity = cal.maturity;
        if (lastTimestamp > maturity) lastTimestamp = maturity; 

        cal.lastTimestamp = lastTimestamp; 
        emit UpdateLastTimestamp(poolId);
    }


    function create(
        uint256 strike,
        uint64 sigma,
        uint32 maturity,
        uint256 riskyPerLp,
        uint256 delLiquidity,
        bytes calldata data
    )
        external
        override
        lock
        returns (
            bytes32 poolId,
            uint256 delRisky,
            uint256 delStable
        )
    {
        (uint256 factor0, uint256 factor1) = (scaleFactorRisky, scaleFactorStable);
        poolId = keccak256(abi.encodePacked(address(this), strike, sigma, maturity));
        if (calibrations[poolId].lastTimestamp != 0) revert PoolDuplicateError();
        if (sigma > 1e7 || sigma < 100) revert SigmaError(sigma);
        if (strike > type(uint128).max || strike == 0) revert StrikeError(strike);
        if (delLiquidity <= MIN_LIQUIDITY) revert MinLiquidityError(delLiquidity);
        if (riskyPerLp > PRECISION / factor0 || riskyPerLp == 0) revert RiskyPerLpError(riskyPerLp);

        Calibration memory cal = Calibration({
            strike: strike.toUint128(),
            sigma: sigma,
            maturity: maturity,
            lastTimestamp: _blockTimestamp(),
            creationTimestamp: _blockTimestamp()
        });

        if (cal.lastTimestamp > cal.maturity) revert PoolExpiredError();
        uint32 tau = cal.maturity - cal.lastTimestamp; 
        delStable = ReplicationMath.getStableGivenRisky(0, factor0, factor1, riskyPerLp, cal.strike, cal.sigma, tau);
        delRisky = (riskyPerLp * delLiquidity) / PRECISION; 
        delStable = (delStable * delLiquidity) / PRECISION;
        if (delRisky == 0 || delStable == 0) revert CalibrationError(delRisky, delStable);

        calibrations[poolId] = cal; 
        liquidity[msg.sender][poolId] += delLiquidity - MIN_LIQUIDITY; 
        reserves[poolId].allocate(delRisky, delStable, delLiquidity, cal.lastTimestamp); 

        (uint256 balRisky, uint256 balStable) = (balanceRisky(), balanceStable());
        IPrimitiveCreateCallback(msg.sender).createCallback(delRisky, delStable, data);
        checkRiskyBalance(balRisky + delRisky);
        checkStableBalance(balStable + delStable);

        emit Create(msg.sender, cal.strike, cal.sigma, cal.maturity);
    }




    function deposit(
        address recipient,
        uint256 delRisky,
        uint256 delStable,
        bytes calldata data
    ) external override lock {
        if (delRisky == 0 && delStable == 0) revert ZeroDeltasError();
        margins[recipient].deposit(delRisky, delStable); 

        uint256 balRisky;
        uint256 balStable;
        if (delRisky > 0) balRisky = balanceRisky();
        if (delStable > 0) balStable = balanceStable();
        IPrimitiveDepositCallback(msg.sender).depositCallback(delRisky, delStable, data); 
        if (delRisky > 0) checkRiskyBalance(balRisky + delRisky);
        if (delStable > 0) checkStableBalance(balStable + delStable);
        emit Deposit(msg.sender, recipient, delRisky, delStable);
    }


    function withdraw(
        address recipient,
        uint256 delRisky,
        uint256 delStable
    ) external override lock {
        if (delRisky == 0 && delStable == 0) revert ZeroDeltasError();
        margins.withdraw(delRisky, delStable); 
        if (delRisky > 0) IERC20(risky).safeTransfer(recipient, delRisky);
        if (delStable > 0) IERC20(stable).safeTransfer(recipient, delStable);
        emit Withdraw(msg.sender, recipient, delRisky, delStable);
    }




    function allocate(
        bytes32 poolId,
        address recipient,
        uint256 delRisky,
        uint256 delStable,
        bool fromMargin,
        bytes calldata data
    ) external override lock returns (uint256 delLiquidity) {
        if (delRisky == 0 || delStable == 0) revert ZeroDeltasError();
        Reserve.Data storage reserve = reserves[poolId];
        if (reserve.blockTimestamp == 0) revert UninitializedError();
        uint32 timestamp = _blockTimestamp();
        if (timestamp > calibrations[poolId].maturity) revert PoolExpiredError();

        uint256 liquidity0 = (delRisky * reserve.liquidity) / uint256(reserve.reserveRisky);
        uint256 liquidity1 = (delStable * reserve.liquidity) / uint256(reserve.reserveStable);
        delLiquidity = liquidity0 < liquidity1 ? liquidity0 : liquidity1;
        if (delLiquidity == 0) revert ZeroLiquidityError();

        liquidity[recipient][poolId] += delLiquidity; 
        reserve.allocate(delRisky, delStable, delLiquidity, timestamp); 

        if (fromMargin) {
            margins.withdraw(delRisky, delStable); 
        } else {
            (uint256 balRisky, uint256 balStable) = (balanceRisky(), balanceStable());
            IPrimitiveLiquidityCallback(msg.sender).allocateCallback(delRisky, delStable, data); 
            checkRiskyBalance(balRisky + delRisky);
            checkStableBalance(balStable + delStable);
        }

        emit Allocate(msg.sender, recipient, poolId, delRisky, delStable);
    }


    function remove(bytes32 poolId, uint256 delLiquidity)
        external
        override
        lock
        returns (uint256 delRisky, uint256 delStable)
    {
        if (delLiquidity == 0) revert ZeroLiquidityError();
        Reserve.Data storage reserve = reserves[poolId];
        if (reserve.blockTimestamp == 0) revert UninitializedError();
        (delRisky, delStable) = reserve.getAmounts(delLiquidity);

        liquidity[msg.sender][poolId] -= delLiquidity; 
        reserve.remove(delRisky, delStable, delLiquidity, _blockTimestamp());
        margins[msg.sender].deposit(delRisky, delStable);

        emit Remove(msg.sender, poolId, delRisky, delStable);
    }

    struct SwapDetails {
        address recipient;
        bytes32 poolId;
        uint256 deltaIn;
        bool riskyForStable;
        bool fromMargin;
        bool toMargin;
        uint32 timestamp;
    }


    function swap(
        address recipient,
        bytes32 poolId,
        bool riskyForStable,
        uint256 deltaIn,
        bool fromMargin,
        bool toMargin,
        bytes calldata data
    ) external override lock returns (uint256 deltaOut) {
        if (deltaIn == 0) revert DeltaInError();

        SwapDetails memory details = SwapDetails({
            recipient: recipient,
            poolId: poolId,
            deltaIn: deltaIn,
            riskyForStable: riskyForStable,
            fromMargin: fromMargin,
            toMargin: toMargin,
            timestamp: _blockTimestamp()
        });

        uint32 lastTimestamp = _updateLastTimestamp(details.poolId); 
        if (details.timestamp > lastTimestamp + BUFFER) revert PoolExpiredError(); 
        int128 invariantX64 = invariantOf(details.poolId); 

        {

            Calibration memory cal = calibrations[details.poolId];
            Reserve.Data storage reserve = reserves[details.poolId];
            uint256 liq = reserve.liquidity;
            uint32 tau = cal.maturity - cal.lastTimestamp;
            uint256 deltaInWithFee = (details.deltaIn * GAMMA) / Units.PERCENTAGE; 

            if (details.riskyForStable) {
                uint256 res0 = (uint256(reserve.reserveRisky + deltaInWithFee) * PRECISION) / liq; 
                uint256 res1 = invariantX64.getStableGivenRisky(
                    scaleFactorRisky,
                    scaleFactorStable,
                    res0,
                    cal.strike,
                    cal.sigma,
                    tau
                ); 
                deltaOut = uint256(reserve.reserveStable) - (res1 * liq) / PRECISION; 
            } else {
                uint256 res1 = (uint256(reserve.reserveStable + deltaInWithFee) * PRECISION) / liq; 
                uint256 res0 = invariantX64.getRiskyGivenStable(
                    scaleFactorRisky,
                    scaleFactorStable,
                    res1,
                    cal.strike,
                    cal.sigma,
                    tau
                ); 
                deltaOut = uint256(reserve.reserveRisky) - (res0 * liq) / PRECISION; 
            }

            reserve.swap(details.riskyForStable, details.deltaIn, deltaOut, details.timestamp); 

            int128 invariantAfter = invariantOf(details.poolId);
            if (invariantX64 > invariantAfter) revert InvariantError(invariantX64, invariantAfter);
        }

        if (deltaOut == 0) revert DeltaOutError();

        if (details.riskyForStable) {
            if (details.toMargin) {
                margins[details.recipient].deposit(0, deltaOut);
            } else {
                IERC20(stable).safeTransfer(details.recipient, deltaOut); 
            }

            if (details.fromMargin) {
                margins.withdraw(deltaIn, 0); 
            } else {
                uint256 balRisky = balanceRisky();
                IPrimitiveSwapCallback(msg.sender).swapCallback(details.deltaIn, 0, data); 
                checkRiskyBalance(balRisky + details.deltaIn);
            }
        } else {
            if (details.toMargin) {
                margins[details.recipient].deposit(deltaOut, 0);
            } else {
                IERC20(risky).safeTransfer(details.recipient, deltaOut); 
            }

            if (details.fromMargin) {
                margins.withdraw(0, deltaIn); 
            } else {
                uint256 balStable = balanceStable();
                IPrimitiveSwapCallback(msg.sender).swapCallback(0, details.deltaIn, data); 
                checkStableBalance(balStable + details.deltaIn);
            }
        }

        emit Swap(msg.sender, details.recipient, details.poolId, details.riskyForStable, details.deltaIn, deltaOut);
    }




    function invariantOf(bytes32 poolId) public view override returns (int128 invariant) {
        Calibration memory cal = calibrations[poolId];
        uint32 tau = cal.maturity - cal.lastTimestamp; 
        (uint256 riskyPerLiquidity, uint256 stablePerLiquidity) = reserves[poolId].getAmounts(PRECISION); 
        invariant = ReplicationMath.calcInvariant(
            scaleFactorRisky,
            scaleFactorStable,
            riskyPerLiquidity,
            stablePerLiquidity,
            cal.strike,
            cal.sigma,
            tau
        );
    }
}

pragma solidity 0.8.6;

import "./ABDKMath64x64.sol";
import "./CumulativeNormalDistribution.sol";
import "./Units.sol";





library ReplicationMath {
    using ABDKMath64x64 for int128;
    using ABDKMath64x64 for uint256;
    using CumulativeNormalDistribution for int128;
    using Units for int128;
    using Units for uint256;

    int128 internal constant ONE_INT = 0x10000000000000000;





    function getProportionalVolatility(uint256 sigma, uint256 tau) internal pure returns (int128 vol) {
        int128 sqrtTauX64 = tau.toYears().sqrt();
        int128 sigmaX64 = sigma.percentage();
        vol = sigmaX64.mul(sqrtTauX64);
    }











    function getStableGivenRisky(
        int128 invariantLastX64,
        uint256 scaleFactorRisky,
        uint256 scaleFactorStable,
        uint256 riskyPerLiquidity,
        uint256 strike,
        uint256 sigma,
        uint256 tau
    ) internal pure returns (uint256 stablePerLiquidity) {
        int128 strikeX64 = strike.scaleToX64(scaleFactorStable);
        int128 volX64 = getProportionalVolatility(sigma, tau);
        int128 riskyX64 = riskyPerLiquidity.scaleToX64(scaleFactorRisky); 
        int128 phi = ONE_INT.sub(riskyX64).getInverseCDF();
        int128 input = phi.sub(volX64);
        int128 stableX64 = strikeX64.mul(input.getCDF()).add(invariantLastX64);
        stablePerLiquidity = stableX64.scalefromX64(scaleFactorStable);
    }












    function getRiskyGivenStable(
        int128 invariantLastX64,
        uint256 scaleFactorRisky,
        uint256 scaleFactorStable,
        uint256 stablePerLiquidity,
        uint256 strike,
        uint256 sigma,
        uint256 tau
    ) internal pure returns (uint256 riskyPerLiquidity) {
        int128 strikeX64 = strike.scaleToX64(scaleFactorStable);
        int128 volX64 = getProportionalVolatility(sigma, tau);
        int128 stableX64 = stablePerLiquidity.scaleToX64(scaleFactorStable);
        int128 phi = stableX64.sub(invariantLastX64).div(strikeX64).getInverseCDF();
        int128 input = phi.add(volX64);
        int128 riskyX64 = ONE_INT.sub(input.getCDF());
        riskyPerLiquidity = riskyX64.scalefromX64(scaleFactorRisky);
    }








    function calcInvariant(
        uint256 scaleFactorRisky,
        uint256 scaleFactorStable,
        uint256 riskyPerLiquidity,
        uint256 stablePerLiquidity,
        uint256 strike,
        uint256 sigma,
        uint256 tau
    ) internal pure returns (int128 invariantX64) {
        uint256 output = getStableGivenRisky(
            0,
            scaleFactorRisky,
            scaleFactorStable,
            riskyPerLiquidity,
            strike,
            sigma,
            tau
        );
        int128 outputX64 = output.scaleToX64(scaleFactorStable);
        int128 stableX64 = stablePerLiquidity.scaleToX64(scaleFactorStable);
        invariantX64 = stableX64.sub(outputX64);
    }
}

pragma solidity ^0.8.3;
import "@openzeppelin/contracts/utils/math/SafeMath.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/security/Pausable.sol";
import "@openzeppelin/contracts/security/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC1155/IERC1155.sol";


contract Staking is Ownable, Pausable, ReentrancyGuard {
	using SafeMath for uint256;

	struct UserInfo {
		uint256 amount; 
		uint256 createdAt; 
		uint256 lastUpdateAt; 
		uint256 pointsDebt; 
	}

	uint256 public minimumAmount = 1 * (10**18); 
	uint256 public maxAmount = 1000 * (10**18); 
	uint256 public lockTime = 1 hours;




	uint256 public emissionRate;

	IERC20 spiToken; 

	mapping(address => UserInfo) public userInfo;


	event StakeClaimed(address user, uint256 amount);
	event RewardAdded(uint256 amount);
	event EmissionRateChanged(uint256 newEmissionRate);

	constructor(IERC20 _lpToken, uint256 _emissionRate) {
		spiToken = _lpToken;
		emissionRate = _emissionRate;
	}


	function addReward(uint256 _amount) external {
		spiToken.transferFrom(msg.sender, address(this), _amount);
		emit RewardAdded(_amount);
	}


	function stake(uint256 _amount) external whenNotPaused nonReentrant {
		require(_amount >= minimumAmount, "amount below minimumAmount");
		require(_amount <= maxAmount, "amount greater than maxAmount");
		require(spiToken.transferFrom(msg.sender, address(this), _amount), "failed to transfer");


		UserInfo storage user = userInfo[msg.sender];
		if (user.amount != 0) {
			user.pointsDebt = pointsBalance(msg.sender);
		}

		user.amount = user.amount.add(_amount);
		user.lastUpdateAt = block.timestamp;
		user.createdAt = block.timestamp;
	}


	function claim() public nonReentrant {
		UserInfo storage user = userInfo[msg.sender];


		uint256 amountToTransfer = pointsBalance(msg.sender);
		user.pointsDebt = 0;
		user.lastUpdateAt = block.timestamp;

		spiToken.transfer(msg.sender, amountToTransfer);
	}

	function unstake() external {
		UserInfo storage user = userInfo[msg.sender];
		require(user.amount >= 0, "insufficient staked");
		require(user.createdAt + lockTime <= block.timestamp, "tokens are locked");


		claim();

		uint256 userAmount = user.amount;
		user.amount = 0;

		spiToken.transfer(msg.sender, userAmount);
	}


	function _unDebitedPoints(UserInfo memory user) internal view returns (uint256) {
		return block.timestamp.sub(user.lastUpdateAt).mul(emissionRate).mul(user.amount).div(1e18);
	}


	function pointsBalance(address userAddress) public view returns (uint256) {
		UserInfo memory user = userInfo[userAddress];
		return user.pointsDebt.add(_unDebitedPoints(user));
	}


	function changeEmissionRate(uint256 newEmissionRate) public onlyOwner {
		emissionRate = newEmissionRate;
		emit EmissionRateChanged(newEmissionRate);
	}


	function reclaimToken(IERC20 token, uint256 _amount) public onlyOwner {
		require(address(token) != address(0), "no 0 address");
		require(address(token) != address(spiToken), "can't withdraw the reward");
		uint256 balance = token.balanceOf(address(this));
		require(_amount <= balance, "you can't withdraw more than you have");
		token.transfer(msg.sender, _amount);
	}

	function pause() public onlyOwner {
		_pause();
	}

	function unpause() public onlyOwner {
		_unpause();
	}


	function withdraw() public onlyOwner {
		uint256 balance = address(this).balance;
		payable(msg.sender).transfer(balance);
	}
}

pragma solidity 0.5.8;

import "../STO.sol";
import "../../../interfaces/IPolymathRegistry.sol";
import "../../../interfaces/IOracle.sol";
import "../../../libraries/DecimalMath.sol";
import "openzeppelin-solidity/contracts/math/SafeMath.sol";
import "./USDTieredSTOStorage.sol";


contract USDTieredSTO is USDTieredSTOStorage, STO {
    using SafeMath for uint256;

    string internal constant POLY_ORACLE = "PolyUsdOracle";
    string internal constant ETH_ORACLE = "EthUsdOracle";





    event SetAllowBeneficialInvestments(bool _allowed);
    event SetNonAccreditedLimit(address _investor, uint256 _limit);
    event TokenPurchase(
        address indexed _purchaser,
        address indexed _beneficiary,
        uint256 _tokens,
        uint256 _usdAmount,
        uint256 _tierPrice,
        uint256 _tier
    );
    event FundsReceived(
        address indexed _purchaser,
        address indexed _beneficiary,
        uint256 _usdAmount,
        FundRaiseType _fundRaiseType,
        uint256 _receivedValue,
        uint256 _spentValue,
        uint256 _rate
    );
    event ReserveTokenMint(address indexed _owner, address indexed _wallet, uint256 _tokens, uint256 _latestTier);
    event ReserveTokenTransfer(address indexed _from, address indexed _wallet, uint256 _tokens);
    event SetAddresses(address indexed _wallet, IERC20[] _stableTokens);
    event SetLimits(uint256 _nonAccreditedLimitUSD, uint256 _minimumInvestmentUSD);
    event SetTimes(uint256 _startTime, uint256 _endTime);
    event SetTiers(
        uint256[] _ratePerTier,
        uint256[] _ratePerTierDiscountPoly,
        uint256[] _tokensPerTierTotal,
        uint256[] _tokensPerTierDiscountPoly
    );
    event SetTreasuryWallet(address _oldWallet, address _newWallet);
    event SetOracles(bytes32 _denominatedCurrency, bool _isCustomOracles);





    modifier validETH() {
        _checkZeroOracleAddress(_getOracle(bytes32("ETH")));
        require(fundRaiseTypes[uint8(FundRaiseType.ETH)], "ETH not allowed");
        _;
    }

    modifier validPOLY() {
        _checkZeroOracleAddress(_getOracle(bytes32("POLY")));
        require(fundRaiseTypes[uint8(FundRaiseType.POLY)], "POLY not allowed");
        _;
    }

    modifier validSC(address _stableToken) {
        require(fundRaiseTypes[uint8(FundRaiseType.SC)] && stableTokenEnabled[_stableToken], "Fiat not allowed");
        _;
    }





    constructor(address _securityToken, address _polyAddress) public Module(_securityToken, _polyAddress) {

    }


    function configure(
        uint256 _startTime,
        uint256 _endTime,
        uint256[] memory _ratePerTier,
        uint256[] memory _ratePerTierDiscountPoly,
        uint256[] memory _tokensPerTierTotal,
        uint256[] memory _tokensPerTierDiscountPoly,
        uint256 _nonAccreditedLimitUSD,
        uint256 _minimumInvestmentUSD,
        FundRaiseType[] memory _fundRaiseTypes,
        address payable _wallet,
        address _treasuryWallet,
        IERC20[] memory _stableTokens,
        address[] memory _customOracleAddresses,
        bytes32 _denominatedCurrency
    )
        public
        onlyFactory
    {
        require(endTime == 0, "Already configured");
        _modifyTimes(_startTime, _endTime);
        _modifyTiers(_ratePerTier, _ratePerTierDiscountPoly, _tokensPerTierTotal, _tokensPerTierDiscountPoly);

        _setFundRaiseType(_fundRaiseTypes);
        _modifyOracles(_customOracleAddresses, _denominatedCurrency);
        _modifyAddresses(_wallet, _treasuryWallet, _stableTokens);
        _modifyLimits(_nonAccreditedLimitUSD, _minimumInvestmentUSD);
    }


    function allowPreMinting() external withPerm(ADMIN) {
        _allowPreMinting(_getTotalTokensCap());
    }


    function revokePreMintFlag() external withPerm(ADMIN) {
        _revokePreMintFlag(_getTotalTokensCap());
    }

    function _getTotalTokensCap() internal view returns(uint256 totalCap) {
        for(uint256 i = 0; i < tiers.length; i++) {
            totalCap = totalCap.add(tiers[i].tokenTotal);
        }
    }


    function modifyFunding(FundRaiseType[] calldata _fundRaiseTypes) external withPerm(OPERATOR) {
        _isSTOStarted();
        _setFundRaiseType(_fundRaiseTypes);
    }


    function modifyLimits(uint256 _nonAccreditedLimitUSD, uint256 _minimumInvestmentUSD) external withPerm(OPERATOR) {
        _isSTOStarted();
        _modifyLimits(_nonAccreditedLimitUSD, _minimumInvestmentUSD);
    }


    function modifyTiers(
        uint256[] calldata _ratePerTier,
        uint256[] calldata _ratePerTierDiscountPoly,
        uint256[] calldata _tokensPerTierTotal,
        uint256[] calldata _tokensPerTierDiscountPoly
    )
        external
        withPerm(OPERATOR)
    {
        _isSTOStarted();
        _modifyTiers(_ratePerTier, _ratePerTierDiscountPoly, _tokensPerTierTotal, _tokensPerTierDiscountPoly);
    }


    function modifyTimes(uint256 _startTime, uint256 _endTime) external withPerm(OPERATOR) {
        _isSTOStarted();
        _modifyTimes(_startTime, _endTime);
    }


    function modifyAddresses(address payable _wallet, address _treasuryWallet, IERC20[] calldata _stableTokens) external {
        _onlySecurityTokenOwner();
        _modifyAddresses(_wallet, _treasuryWallet, _stableTokens);
    }


    function modifyOracles(address[] calldata _customOracleAddresses, bytes32 _denominatedCurrencySymbol) external {
        _onlySecurityTokenOwner();


        if (_denominatedCurrencySymbol != denominatedCurrency)
            _isSTOStarted();
        _modifyOracles(_customOracleAddresses, _denominatedCurrencySymbol);
    }

    function _modifyOracles(address[] memory _customOracleAddresses, bytes32 _denominatedCurrencySymbol) internal {
        if (_customOracleAddresses.length == 0 && _denominatedCurrencySymbol == bytes32(0)) {
            denominatedCurrency = bytes32("USD");
            delete customOracles[bytes32("ETH")][denominatedCurrency];
            delete customOracles[bytes32("POLY")][denominatedCurrency];
            oracleKeys[bytes32("ETH")][denominatedCurrency] = ETH_ORACLE;
            oracleKeys[bytes32("POLY")][denominatedCurrency] = POLY_ORACLE;
            emit SetOracles(denominatedCurrency, false);
        }
        else {
            require(_denominatedCurrencySymbol != bytes32(0), "Invalid currency");









            require(_customOracleAddresses.length == 2, "Invalid no. of oracles");
            if (fundRaiseTypes[uint8(FundRaiseType.ETH)]) {
                _checkZeroOracleAddress(_customOracleAddresses[0]);
            }
            if (fundRaiseTypes[uint8(FundRaiseType.POLY)]) {
                _checkZeroOracleAddress(_customOracleAddresses[1]);
            }
            denominatedCurrency = _denominatedCurrencySymbol;
            customOracles[bytes32("ETH")][denominatedCurrency] = _customOracleAddresses[0];
            customOracles[bytes32("POLY")][denominatedCurrency] = _customOracleAddresses[1];
            emit SetOracles(denominatedCurrency, true);
        }
    }

    function _checkZeroOracleAddress(address _addressForCheck) internal pure {
        require(_addressForCheck != address(0), "Invalid address");
    }

    function _modifyLimits(uint256 _nonAccreditedLimitUSD, uint256 _minimumInvestmentUSD) internal {
        minimumInvestmentUSD = _minimumInvestmentUSD;
        nonAccreditedLimitUSD = _nonAccreditedLimitUSD;
        emit SetLimits(minimumInvestmentUSD, nonAccreditedLimitUSD);
    }

    function _modifyTiers(
        uint256[] memory _ratePerTier,
        uint256[] memory _ratePerTierDiscountPoly,
        uint256[] memory _tokensPerTierTotal,
        uint256[] memory _tokensPerTierDiscountPoly
    )
        internal
    {
        require(
            _tokensPerTierTotal.length > 0 &&
            _ratePerTier.length == _tokensPerTierTotal.length &&
            _ratePerTierDiscountPoly.length == _tokensPerTierTotal.length &&
            _tokensPerTierDiscountPoly.length == _tokensPerTierTotal.length,
            "Invalid Input"
        );
        delete tiers;
        for (uint256 i = 0; i < _ratePerTier.length; i++) {
            require(_ratePerTier[i] > 0 && _tokensPerTierTotal[i] > 0, "Invalid value");
            require(_tokensPerTierDiscountPoly[i] <= _tokensPerTierTotal[i], "Too many discounted tokens");
            require(_ratePerTierDiscountPoly[i] <= _ratePerTier[i], "Invalid discount");
            tiers.push(Tier(_ratePerTier[i], _ratePerTierDiscountPoly[i], _tokensPerTierTotal[i], _tokensPerTierDiscountPoly[i], 0, 0));
        }
        if (preMintAllowed) {
            uint256 oldCap = securityToken.balanceOf(address(this));
            uint256 newCap = _getTotalTokensCap();
            if (oldCap < newCap) {
                securityToken.issue(address(this), (newCap - oldCap), "");
            } 
            else if (oldCap > newCap) {
                securityToken.redeem((oldCap - newCap), "");
            }
        }
        emit SetTiers(_ratePerTier, _ratePerTierDiscountPoly, _tokensPerTierTotal, _tokensPerTierDiscountPoly);
    }

    function _modifyTimes(uint256 _startTime, uint256 _endTime) internal {

        require((_endTime > _startTime) && (_startTime > now), "Invalid times");
        startTime = _startTime;
        endTime = _endTime;
        emit SetTimes(_startTime, _endTime);
    }

    function _modifyAddresses(address payable _wallet, address _treasuryWallet, IERC20[] memory _stableTokens) internal {
        _checkZeroOracleAddress(_wallet);
        wallet = _wallet;
        emit SetTreasuryWallet(treasuryWallet, _treasuryWallet);
        treasuryWallet = _treasuryWallet;
        _modifyStableTokens(_stableTokens);
    }

    function _modifyStableTokens(IERC20[] memory _stableTokens) internal {
        uint256 i;
        for(i = 0; i < stableTokens.length; i++) {
            stableTokenEnabled[address(stableTokens[i])] = false;
        }
        stableTokens = _stableTokens;
        for(i = 0; i < _stableTokens.length; i++) {
            require(address(_stableTokens[i]) != address(0) && _stableTokens[i] != polyToken, "Invalid USD token");
            stableTokenEnabled[address(_stableTokens[i])] = true;
        }
        emit SetAddresses(wallet, _stableTokens);
    }






    function finalize() external withPerm(ADMIN) {
        require(!isFinalized, "STO is finalized");
        isFinalized = true;
        uint256 tempReturned;
        uint256 tempSold;
        uint256 remainingTokens;
        for (uint256 i = 0; i < tiers.length; i++) {
            remainingTokens = tiers[i].tokenTotal.sub(tiers[i].totalTokensSoldInTier);
            tempReturned = tempReturned.add(remainingTokens);
            tempSold = tempSold.add(tiers[i].totalTokensSoldInTier);
            if (remainingTokens > 0) {
                tiers[i].totalTokensSoldInTier = tiers[i].tokenTotal;
            }
        }
        address walletAddress = getTreasuryWallet();
        _checkZeroOracleAddress(walletAddress);

        if (preMintAllowed) {
            if (tempReturned == securityToken.balanceOf(address(this)))
                tempReturned = securityToken.balanceOf(address(this));
        }
        uint256 granularity = securityToken.granularity();
        tempReturned = tempReturned.div(granularity);
        tempReturned = tempReturned.mul(granularity);
        if (tempReturned != uint256(0)) {
            if (preMintAllowed) {
                securityToken.transfer(walletAddress, tempReturned);
                emit ReserveTokenTransfer(address(this), walletAddress, tempReturned);
            } else {
                securityToken.issue(walletAddress, tempReturned, "");
                emit ReserveTokenMint(msg.sender, walletAddress, tempReturned, currentTier);
            }
        }
        finalAmountReturned = tempReturned;
        totalTokensSold = tempSold;
    }


    function changeNonAccreditedLimit(address[] calldata _investors, uint256[] calldata _nonAccreditedLimit) external withPerm(OPERATOR) {

        require(_investors.length == _nonAccreditedLimit.length, "Length mismatch");
        for (uint256 i = 0; i < _investors.length; i++) {
            nonAccreditedLimitUSDOverride[_investors[i]] = _nonAccreditedLimit[i];
            emit SetNonAccreditedLimit(_investors[i], _nonAccreditedLimit[i]);
        }
    }


    function getAccreditedData() external view returns (address[] memory investors, bool[] memory accredited, uint256[] memory overrides) {
        IDataStore dataStore = getDataStore();
        investors = dataStore.getAddressArray(INVESTORSKEY);
        accredited = new bool[](investors.length);
        overrides = new uint256[](investors.length);
        for (uint256 i = 0; i < investors.length; i++) {
            accredited[i] = _getIsAccredited(investors[i], dataStore);
            overrides[i] = nonAccreditedLimitUSDOverride[investors[i]];
        }
    }


    function changeAllowBeneficialInvestments(bool _allowBeneficialInvestments) external withPerm(OPERATOR) {
        require(_allowBeneficialInvestments != allowBeneficialInvestments);
        allowBeneficialInvestments = _allowBeneficialInvestments;
        emit SetAllowBeneficialInvestments(allowBeneficialInvestments);
    }






    function() external payable {
        buyWithETHRateLimited(msg.sender, 0);
    }


    function buyWithETH(address _beneficiary) external payable returns (uint256, uint256, uint256) {
        return buyWithETHRateLimited(_beneficiary, 0);
    }

    function buyWithPOLY(address _beneficiary, uint256 _investedPOLY) external returns (uint256, uint256, uint256) {
        return buyWithPOLYRateLimited(_beneficiary, _investedPOLY, 0);
    }

    function buyWithUSD(address _beneficiary, uint256 _investedSC, IERC20 _usdToken) external returns (uint256, uint256, uint256) {
        return buyWithUSDRateLimited(_beneficiary, _investedSC, 0, _usdToken);
    }


    function buyWithETHRateLimited(address _beneficiary, uint256 _minTokens) public payable validETH returns (uint256, uint256, uint256) {
        (uint256 rate, uint256 spentUSD, uint256 spentValue, uint256 initialMinted) = _getSpentvalues(_beneficiary,  msg.value, FundRaiseType.ETH, _minTokens);

        investorInvested[_beneficiary][uint8(FundRaiseType.ETH)] = investorInvested[_beneficiary][uint8(FundRaiseType.ETH)].add(spentValue);
        fundsRaised[uint8(FundRaiseType.ETH)] = fundsRaised[uint8(FundRaiseType.ETH)].add(spentValue);

        wallet.transfer(spentValue);

        msg.sender.transfer(msg.value.sub(spentValue));
        emit FundsReceived(msg.sender, _beneficiary, spentUSD, FundRaiseType.ETH, msg.value, spentValue, rate);
        return (spentUSD, spentValue, getTokensMinted().sub(initialMinted));
    }


    function buyWithPOLYRateLimited(address _beneficiary, uint256 _investedPOLY, uint256 _minTokens) public validPOLY returns (uint256, uint256, uint256) {
        return _buyWithTokens(_beneficiary, _investedPOLY, FundRaiseType.POLY, _minTokens, polyToken);
    }


    function buyWithUSDRateLimited(address _beneficiary, uint256 _investedSC, uint256 _minTokens, IERC20 _usdToken)
        public validSC(address(_usdToken)) returns (uint256, uint256, uint256)
    {
        return _buyWithTokens(_beneficiary, _investedSC, FundRaiseType.SC, _minTokens, _usdToken);
    }

    function _buyWithTokens(address _beneficiary, uint256 _tokenAmount, FundRaiseType _fundRaiseType, uint256 _minTokens, IERC20 _token) internal returns (uint256, uint256, uint256) {
        (uint256 rate, uint256 spentUSD, uint256 spentValue, uint256 initialMinted) = _getSpentvalues(_beneficiary, _tokenAmount, _fundRaiseType, _minTokens);

        investorInvested[_beneficiary][uint8(_fundRaiseType)] = investorInvested[_beneficiary][uint8(_fundRaiseType)].add(spentValue);
        fundsRaised[uint8(_fundRaiseType)] = fundsRaised[uint8(_fundRaiseType)].add(spentValue);
        if(address(_token) != address(polyToken))
            stableCoinsRaised[address(_token)] = stableCoinsRaised[address(_token)].add(spentValue);

        require(_token.transferFrom(msg.sender, wallet, spentValue), "Transfer failed");
        emit FundsReceived(msg.sender, _beneficiary, spentUSD, _fundRaiseType, _tokenAmount, spentValue, rate);
        return (spentUSD, spentValue, getTokensMinted().sub(initialMinted));
    }

    function _getSpentvalues(address _beneficiary, uint256 _amount, FundRaiseType _fundRaiseType, uint256 _minTokens) internal returns(uint256 rate, uint256 spentUSD, uint256 spentValue, uint256 initialMinted) {
        initialMinted = getTokensMinted();
        rate = getRate(_fundRaiseType);
        (spentUSD, spentValue) = _buyTokens(_beneficiary, _amount, rate, _fundRaiseType);
        require(getTokensMinted().sub(initialMinted) >= _minTokens, "Insufficient minted");
    }



    function _buyTokens(
        address _beneficiary,
        uint256 _investmentValue,
        uint256 _rate,
        FundRaiseType _fundRaiseType
    )
        internal
        whenNotPaused
        returns(uint256 spentUSD, uint256 spentValue)
    {
        if (!allowBeneficialInvestments) {
            require(_beneficiary == msg.sender, "Beneficiary != funder");
        }

        require(_canBuy(_beneficiary), "Unauthorized");

        uint256 originalUSD = DecimalMath.mul(_rate, _investmentValue);
        uint256 allowedUSD = _buyTokensChecks(_beneficiary, _investmentValue, originalUSD);

        for (uint256 i = currentTier; i < tiers.length; i++) {
            bool gotoNextTier;
            uint256 tempSpentUSD;

            if (currentTier != i)
                currentTier = i;

            if (tiers[i].totalTokensSoldInTier < tiers[i].tokenTotal) {
                (tempSpentUSD, gotoNextTier) = _calculateTier(_beneficiary, i, allowedUSD.sub(spentUSD), _fundRaiseType);
                spentUSD = spentUSD.add(tempSpentUSD);

                if (!gotoNextTier)
                    break;
            }
        }


        if (spentUSD > 0) {
            if (investorInvestedUSD[_beneficiary] == 0)
                investorCount = investorCount + 1;
            investorInvestedUSD[_beneficiary] = investorInvestedUSD[_beneficiary].add(spentUSD);
            fundsRaisedUSD = fundsRaisedUSD.add(spentUSD);
        }

        spentValue = DecimalMath.div(spentUSD, _rate);
    }

    function _buyTokensChecks(
        address _beneficiary,
        uint256 _investmentValue,
        uint256 investedUSD
    )
        internal
        view
        returns(uint256 netInvestedUSD)
    {
        require(isOpen(), "STO not open");
        require(_investmentValue > 0, "No funds sent");


        require(investedUSD.add(investorInvestedUSD[_beneficiary]) >= minimumInvestmentUSD, "Investment < min");
        netInvestedUSD = investedUSD;

        if (!_isAccredited(_beneficiary)) {
            uint256 investorLimitUSD = (nonAccreditedLimitUSDOverride[_beneficiary] == 0) ? nonAccreditedLimitUSD : nonAccreditedLimitUSDOverride[_beneficiary];
            require(investorInvestedUSD[_beneficiary] < investorLimitUSD, "Over Non-accredited investor limit");
            if (investedUSD.add(investorInvestedUSD[_beneficiary]) > investorLimitUSD)
                netInvestedUSD = investorLimitUSD.sub(investorInvestedUSD[_beneficiary]);
        }
    }

    function _calculateTier(
        address _beneficiary,
        uint256 _tier,
        uint256 _investedUSD,
        FundRaiseType _fundRaiseType
    )
        internal
        returns(uint256 spentUSD, bool gotoNextTier)
    {

        uint256 tierSpentUSD;
        uint256 tierPurchasedTokens;
        uint256 investedUSD = _investedUSD;
        Tier storage tierData = tiers[_tier];

        if ((_fundRaiseType == FundRaiseType.POLY) && (tierData.tokensDiscountPoly > tierData.soldDiscountPoly)) {
            uint256 discountRemaining = tierData.tokensDiscountPoly.sub(tierData.soldDiscountPoly);
            uint256 totalRemaining = tierData.tokenTotal.sub(tierData.totalTokensSoldInTier);
            if (totalRemaining < discountRemaining)
                (spentUSD, tierPurchasedTokens, gotoNextTier) = _purchaseTier(_beneficiary, tierData.rateDiscountPoly, totalRemaining, investedUSD, _tier);
            else
                (spentUSD, tierPurchasedTokens, gotoNextTier) = _purchaseTier(_beneficiary, tierData.rateDiscountPoly, discountRemaining, investedUSD, _tier);
            investedUSD = investedUSD.sub(spentUSD);
            tierData.soldDiscountPoly = tierData.soldDiscountPoly.add(tierPurchasedTokens);
            tierData.tokenSoldPerFundType[uint8(_fundRaiseType)] = tierData.tokenSoldPerFundType[uint8(_fundRaiseType)].add(tierPurchasedTokens);
            tierData.totalTokensSoldInTier = tierData.totalTokensSoldInTier.add(tierPurchasedTokens);
        }

        if (investedUSD > 0 &&
            tierData.tokenTotal.sub(tierData.totalTokensSoldInTier) > 0 &&
            (_fundRaiseType != FundRaiseType.POLY || tierData.tokensDiscountPoly <= tierData.soldDiscountPoly)
        ) {
            (tierSpentUSD, tierPurchasedTokens, gotoNextTier) = _purchaseTier(
                _beneficiary,
                tierData.rate,
                tierData.tokenTotal.sub(tierData.totalTokensSoldInTier),
                investedUSD,
                _tier
            );
            spentUSD = spentUSD.add(tierSpentUSD);
            tierData.tokenSoldPerFundType[uint8(_fundRaiseType)] = tierData.tokenSoldPerFundType[uint8(_fundRaiseType)].add(tierPurchasedTokens);
            tierData.totalTokensSoldInTier = tierData.totalTokensSoldInTier.add(tierPurchasedTokens);
        }
    }

    function _purchaseTier(
        address _beneficiary,
        uint256 _tierPrice,
        uint256 _tierRemaining,
        uint256 _investedUSD,
        uint256 _tier
    )
        internal
        returns(uint256 spentUSD, uint256 purchasedTokens, bool gotoNextTier)
    {
        purchasedTokens = DecimalMath.div(_investedUSD, _tierPrice);
        uint256 granularity = securityToken.granularity();

        if (purchasedTokens > _tierRemaining) {
            purchasedTokens = _tierRemaining.div(granularity);
            gotoNextTier = true;
        } else {
            purchasedTokens = purchasedTokens.div(granularity);
        }

        purchasedTokens = purchasedTokens.mul(granularity);
        spentUSD = DecimalMath.mul(purchasedTokens, _tierPrice);


        if (spentUSD > _investedUSD) {
            spentUSD = _investedUSD;
        }

        if (purchasedTokens > 0) {
            if (preMintAllowed)
                securityToken.transfer(_beneficiary, purchasedTokens);
            else
                securityToken.issue(_beneficiary, purchasedTokens, "");
            emit TokenPurchase(msg.sender, _beneficiary, purchasedTokens, spentUSD, _tierPrice, _tier);
        }
    }

    function _isAccredited(address _investor) internal view returns(bool) {
        IDataStore dataStore = getDataStore();
        return _getIsAccredited(_investor, dataStore);
    }

    function _getIsAccredited(address _investor, IDataStore dataStore) internal view returns(bool) {
        uint256 flags = dataStore.getUint256(_getKey(INVESTORFLAGS, _investor));
        uint256 flag = flags & uint256(1); 
        return flag > 0 ? true : false;
    }






    function isOpen() public view returns(bool) {

        if (isFinalized || now < startTime || now >= endTime || capReached())
            return false;
        return true;
    }


    function capReached() public view returns (bool) {
        if (isFinalized) {
            return (finalAmountReturned == 0);
        }
        return (tiers[tiers.length - 1].totalTokensSoldInTier == tiers[tiers.length - 1].tokenTotal);
    }


    function getRate(FundRaiseType _fundRaiseType) public returns (uint256) {
        if (_fundRaiseType == FundRaiseType.ETH) {
            return IOracle(_getOracle(bytes32("ETH"))).getPrice();
        } else if (_fundRaiseType == FundRaiseType.POLY) {
            return IOracle(_getOracle(bytes32("POLY"))).getPrice();
        } else if (_fundRaiseType == FundRaiseType.SC) {
            return 10**18;
        }
    }


    function getCustomOracleAddress(FundRaiseType _fundRaiseType) external view returns(address) {
        if (_fundRaiseType == FundRaiseType.ETH) {
            return customOracles[bytes32("ETH")][denominatedCurrency];
        } else if (_fundRaiseType == FundRaiseType.POLY) {
            return customOracles[bytes32("POLY")][denominatedCurrency];
        }
    }


    function convertToUSD(FundRaiseType _fundRaiseType, uint256 _amount) public returns(uint256) {
        return DecimalMath.mul(_amount, getRate(_fundRaiseType));
    }


    function convertFromUSD(FundRaiseType _fundRaiseType, uint256 _amount) public returns(uint256) {
        return DecimalMath.div(_amount, getRate(_fundRaiseType));
    }


    function getTokensSold() public view returns (uint256) {
        if (isFinalized)
            return totalTokensSold;
        return getTokensMinted();
    }


    function getTokensMinted() public view returns (uint256 tokensMinted) {
        for (uint256 i = 0; i < tiers.length; i++) {
            tokensMinted = tokensMinted.add(tiers[i].totalTokensSoldInTier);
        }
    }


    function getTokensSoldFor(FundRaiseType _fundRaiseType) external view returns (uint256 tokensSold) {
        for (uint256 i = 0; i < tiers.length; i++) {
            tokensSold = tokensSold.add(tiers[i].tokenSoldPerFundType[uint8(_fundRaiseType)]);
        }
    }


    function getTokensSoldByTier(uint256 _tier) external view returns(uint256[] memory) {
        uint256[] memory tokensMinted = new uint256[](3);
        tokensMinted[0] = tiers[_tier].tokenSoldPerFundType[uint8(FundRaiseType.ETH)];
        tokensMinted[1] = tiers[_tier].tokenSoldPerFundType[uint8(FundRaiseType.POLY)];
        tokensMinted[2] = tiers[_tier].tokenSoldPerFundType[uint8(FundRaiseType.SC)];
        return tokensMinted;
    }


    function getTotalTokensSoldByTier(uint256 _tier) external view returns (uint256) {
        uint256 tokensSold;
        tokensSold = tokensSold.add(tiers[_tier].tokenSoldPerFundType[uint8(FundRaiseType.ETH)]);
        tokensSold = tokensSold.add(tiers[_tier].tokenSoldPerFundType[uint8(FundRaiseType.POLY)]);
        tokensSold = tokensSold.add(tiers[_tier].tokenSoldPerFundType[uint8(FundRaiseType.SC)]);
        return tokensSold;
    }


    function getNumberOfTiers() external view returns (uint256) {
        return tiers.length;
    }


    function getUsdTokens() external view returns (IERC20[] memory) {
        return stableTokens;
    }


    function getPermissions() public view returns(bytes32[] memory allPermissions) {
        allPermissions = new bytes32[](2);
        allPermissions[0] = OPERATOR;
        allPermissions[1] = ADMIN;
        return allPermissions;
    }


    function getSTODetails() external view returns(uint256, uint256, uint256, uint256[] memory, uint256[] memory, uint256, uint256, uint256, bool[] memory, bool) {
        uint256[] memory cap = new uint256[](tiers.length);
        uint256[] memory rate = new uint256[](tiers.length);
        for(uint256 i = 0; i < tiers.length; i++) {
            cap[i] = tiers[i].tokenTotal;
            rate[i] = tiers[i].rate;
        }
        bool[] memory _fundRaiseTypes = new bool[](3);
        _fundRaiseTypes[0] = fundRaiseTypes[uint8(FundRaiseType.ETH)];
        _fundRaiseTypes[1] = fundRaiseTypes[uint8(FundRaiseType.POLY)];
        _fundRaiseTypes[2] = fundRaiseTypes[uint8(FundRaiseType.SC)];
        return (
            startTime,
            endTime,
            currentTier,
            cap,
            rate,
            fundsRaisedUSD,
            investorCount,
            getTokensSold(),
            _fundRaiseTypes,
            preMintAllowed
        );
    }


    function getInitFunction() public pure returns(bytes4) {
        return this.configure.selector;
    }

    function _getOracle(bytes32 _currency) internal view returns(address oracleAddress) {
        oracleAddress = customOracles[_currency][denominatedCurrency];
        if (oracleAddress == address(0) && denominatedCurrency == bytes32("USD"))
            oracleAddress =  IPolymathRegistry(securityToken.polymathRegistry()).getAddress(oracleKeys[_currency][denominatedCurrency]);
    }
}

