}








interface IERC20Metadata is IERC20 {

    function name() external view returns (string memory);


    function symbol() external view returns (string memory);


    function decimals() external view returns (uint8);
}




contract ERC20 is Context, IERC20, IERC20Metadata {
    mapping(address => uint256) private _balances;

    mapping(address => mapping(address => uint256)) private _allowances;

    uint256 private _totalSupply;

    string private _name;
    string private _symbol;


    constructor(string memory name_, string memory symbol_) {
        _name = name_;
        _symbol = symbol_;
    }


    function name() public view virtual override returns (string memory) {
        return _name;
    }


    function symbol() public view virtual override returns (string memory) {
        return _symbol;
    }


    function decimals() public view virtual override returns (uint8) {
        return 18;
    }


    function totalSupply() public view virtual override returns (uint256) {
        return _totalSupply;
    }


    function balanceOf(address account) public view virtual override returns (uint256) {
        return _balances[account];
    }


    function transfer(address recipient, uint256 amount) public virtual override returns (bool) {
        _transfer(_msgSender(), recipient, amount);
        return true;
    }


    function allowance(address owner, address spender) public view virtual override returns (uint256) {
        return _allowances[owner][spender];
    }


    function approve(address spender, uint256 amount) public virtual override returns (bool) {
        _approve(_msgSender(), spender, amount);
        return true;
    }


    function transferFrom(
        address sender,
        address recipient,
        uint256 amount
    ) public virtual override returns (bool) {
        _transfer(sender, recipient, amount);

        uint256 currentAllowance = _allowances[sender][_msgSender()];
        require(currentAllowance >= amount, "ERC20: transfer amount exceeds allowance");
        unchecked {
            _approve(sender, _msgSender(), currentAllowance - amount);
        }

        return true;
    }


    function increaseAllowance(address spender, uint256 addedValue) public virtual returns (bool) {
        _approve(_msgSender(), spender, _allowances[_msgSender()][spender] + addedValue);
        return true;
    }


    function decreaseAllowance(address spender, uint256 subtractedValue) public virtual returns (bool) {
        uint256 currentAllowance = _allowances[_msgSender()][spender];
        require(currentAllowance >= subtractedValue, "ERC20: decreased allowance below zero");
        unchecked {
            _approve(_msgSender(), spender, currentAllowance - subtractedValue);
        }

        return true;
    }


    function _transfer(
        address sender,
        address recipient,
        uint256 amount
    ) internal virtual {
        require(sender != address(0), "ERC20: transfer from the zero address");
        require(recipient != address(0), "ERC20: transfer to the zero address");

        _beforeTokenTransfer(sender, recipient, amount);

        uint256 senderBalance = _balances[sender];
        require(senderBalance >= amount, "ERC20: transfer amount exceeds balance");
        unchecked {
            _balances[sender] = senderBalance - amount;
        }
        _balances[recipient] += amount;

        emit Transfer(sender, recipient, amount);

        _afterTokenTransfer(sender, recipient, amount);
    }


    function _mint(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: mint to the zero address");

        _beforeTokenTransfer(address(0), account, amount);

        _totalSupply += amount;
        _balances[account] += amount;
        emit Transfer(address(0), account, amount);

        _afterTokenTransfer(address(0), account, amount);
    }


    function _burn(address account, uint256 amount) internal virtual {
        require(account != address(0), "ERC20: burn from the zero address");

        _beforeTokenTransfer(account, address(0), amount);

        uint256 accountBalance = _balances[account];
        require(accountBalance >= amount, "ERC20: burn amount exceeds balance");
        unchecked {
            _balances[account] = accountBalance - amount;
        }
        _totalSupply -= amount;

        emit Transfer(account, address(0), amount);

        _afterTokenTransfer(account, address(0), amount);
    }


    function _approve(
        address owner,
        address spender,
        uint256 amount
    ) internal virtual {
        require(owner != address(0), "ERC20: approve from the zero address");
        require(spender != address(0), "ERC20: approve to the zero address");

        _allowances[owner][spender] = amount;
        emit Approval(owner, spender, amount);
    }


    function _beforeTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}


    function _afterTokenTransfer(
        address from,
        address to,
        uint256 amount
    ) internal virtual {}
}



abstract contract ERC20Capped is ERC20 {
    uint256 private immutable _cap;


    constructor(uint256 cap_) {
        require(cap_ > 0, "ERC20Capped: cap is 0");
        _cap = cap_;
    }


    function cap() public view virtual returns (uint256) {
        return _cap;
    }


    function _mint(address account, uint256 amount) internal virtual override {
        require(ERC20.totalSupply() + amount <= cap(), "ERC20Capped: cap exceeded");
        super._mint(account, amount);
    }
}








abstract contract Ownable is Context {
    address private _owner;

    event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


    constructor() {
        _setOwner(_msgSender());
    }


    function owner() public view virtual returns (address) {
        return _owner;
    }


    modifier onlyOwner() {
        require(owner() == _msgSender(), "Ownable: caller is not the owner");
        _;
    }


    function renounceOwnership() public virtual onlyOwner {
        _setOwner(address(0));
    }


    function transferOwnership(address newOwner) public virtual onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        _setOwner(newOwner);
    }

    function _setOwner(address newOwner) private {
        address oldOwner = _owner;
        _owner = newOwner;
        emit OwnershipTransferred(oldOwner, newOwner);
    }
}




contract Galeon is ERC20Capped, Ownable {

    uint256 limit;

    bool limitEnabled;


    constructor() ERC20("Galeon", "GALEON") ERC20Capped(4000000000 * 10 ** decimals())  {

        _mint(0xc0B3974C64ba269A0Ebd5DD698aC496Fcb817aa9, 1056000000 * 10 ** decimals());

        limit = 85700 * 10 ** decimals();

        limitEnabled = true;
    }

    function unlockTransferLimit() public onlyOwner {

        require(limitEnabled == true, "Action can be done only once");

        limit = 2**256 - 1;

        limitEnabled = false;
    }

    function isTransferLimitEnabled() public view returns (bool) {
        return limitEnabled;
    }

    function mint(address to, uint256 amount) public onlyOwner {
        _mint(to, amount);
    }

    function burn(address from, uint256 amount) public onlyOwner {
        _burn(from, amount);
    }

    function transfer(address recipient, uint256 amount) public virtual override returns (bool) {

        if(limitEnabled) {
            require(balanceOf(recipient) + amount <= limit,"85700 GALEON limit Exceeded");
        }

        super.transfer(recipient, amount);
        return true;
    }
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/IERC721Metadata.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/IERC721Enumerable.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/Context.sol";
import "@openzeppelin/contracts/utils/Strings.sol";
import "@openzeppelin/contracts/utils/introspection/ERC165.sol";


contract ERC721A is
  Context,
  ERC165,
  IERC721,
  IERC721Metadata,
  IERC721Enumerable
{
  using Address for address;
  using Strings for uint256;

  struct TokenOwnership {
    address addr;
    uint64 startTimestamp;
  }

  struct AddressData {
    uint128 balance;
    uint128 numberMinted;
  }

  uint256 private currentIndex = 1;

  uint256 internal immutable maxBatchSize;


  string private _name;


  string private _symbol;



  mapping(uint256 => TokenOwnership) private _ownerships;


  mapping(address => AddressData) private _addressData;


  mapping(uint256 => address) private _tokenApprovals;


  mapping(address => mapping(address => bool)) private _operatorApprovals;


  constructor(
    string memory name_,
    string memory symbol_,
    uint256 maxBatchSize_
  ) {
    require(maxBatchSize_ > 0, "ERC721A: max batch size must be nonzero");
    _name = name_;
    _symbol = symbol_;
    maxBatchSize = maxBatchSize_;
  }


  function totalSupply() public view override returns (uint256) {
    return currentIndex - 1;
  }


  function tokenByIndex(uint256 index) public view override returns (uint256) {
    require(index < totalSupply(), "ERC721A: global index out of bounds");
    return index;
  }



  function tokenOfOwnerByIndex(address owner, uint256 index)
    public
    view
    override
    returns (uint256)
  {
    require(index < balanceOf(owner), "ERC721A: owner index out of bounds");
    uint256 numMintedSoFar = totalSupply();
    uint256 tokenIdsIdx = 0;
    address currOwnershipAddr = address(0);
    for (uint256 i = 0; i < numMintedSoFar; i++) {
      TokenOwnership memory ownership = _ownerships[i];
      if (ownership.addr != address(0)) {
        currOwnershipAddr = ownership.addr;
      }
      if (currOwnershipAddr == owner) {
        if (tokenIdsIdx == index) {
          return i;
        }
        tokenIdsIdx++;
      }
    }
    revert("ERC721A: unable to get token of owner by index");
  }


  function supportsInterface(bytes4 interfaceId)
    public
    view
    virtual
    override(ERC165, IERC165)
    returns (bool)
  {
    return
      interfaceId == type(IERC721).interfaceId ||
      interfaceId == type(IERC721Metadata).interfaceId ||
      interfaceId == type(IERC721Enumerable).interfaceId ||
      super.supportsInterface(interfaceId);
  }


  function balanceOf(address owner) public view override returns (uint256) {
    require(owner != address(0), "ERC721A: balance query for the zero address");
    return uint256(_addressData[owner].balance);
  }


  function _numberMinted(address owner) internal view returns (uint256) {
    require(
      owner != address(0),
      "ERC721A: number minted query for the zero address"
    );
    return uint256(_addressData[owner].numberMinted);
  }

  function ownershipOf(uint256 tokenId)
    internal
    view
    returns (TokenOwnership memory)
  {
    require(_exists(tokenId), "ERC721A: owner query for nonexistent token");

    uint256 lowestTokenToCheck;
    if (tokenId >= maxBatchSize) {
      lowestTokenToCheck = tokenId - maxBatchSize + 1;
    }

    for (uint256 curr = tokenId; curr >= lowestTokenToCheck; curr--) {
      TokenOwnership memory ownership = _ownerships[curr];
      if (ownership.addr != address(0)) {
        return ownership;
      }
    }

    revert("ERC721A: unable to determine the owner of token");
  }


  function ownerOf(uint256 tokenId) public view override returns (address) {
    return ownershipOf(tokenId).addr;
  }


  function name() public view virtual override returns (string memory) {
    return _name;
  }


  function symbol() public view virtual override returns (string memory) {
    return _symbol;
  }


  function tokenURI(uint256 tokenId)
    public
    view
    virtual
    override
    returns (string memory)
  {
    require(
      _exists(tokenId),
      "ERC721Metadata: URI query for nonexistent token"
    );

    string memory baseURI = _baseURI();
    return
      bytes(baseURI).length > 0
        ? string(abi.encodePacked(baseURI, tokenId.toString()))
        : "";
  }


  function _baseURI() internal view virtual returns (string memory) {
    return "";
  }


  function approve(address to, uint256 tokenId) public override {
    address owner = ERC721A.ownerOf(tokenId);
    require(to != owner, "ERC721A: approval to current owner");

    require(
      _msgSender() == owner || isApprovedForAll(owner, _msgSender()),
      "ERC721A: approve caller is not owner nor approved for all"
    );

    _approve(to, tokenId, owner);
  }


  function getApproved(uint256 tokenId) public view override returns (address) {
    require(_exists(tokenId), "ERC721A: approved query for nonexistent token");

    return _tokenApprovals[tokenId];
  }


  function setApprovalForAll(address operator, bool approved) public override {
    require(operator != _msgSender(), "ERC721A: approve to caller");

    _operatorApprovals[_msgSender()][operator] = approved;
    emit ApprovalForAll(_msgSender(), operator, approved);
  }


  function isApprovedForAll(address owner, address operator)
    public
    view
    virtual
    override
    returns (bool)
  {
    return _operatorApprovals[owner][operator];
  }


  function transferFrom(
    address from,
    address to,
    uint256 tokenId
  ) public override {
    _transfer(from, to, tokenId);
  }


  function safeTransferFrom(
    address from,
    address to,
    uint256 tokenId
  ) public override {
    safeTransferFrom(from, to, tokenId, "");
  }


  function safeTransferFrom(
    address from,
    address to,
    uint256 tokenId,
    bytes memory _data
  ) public override {
    _transfer(from, to, tokenId);
    require(
      _checkOnERC721Received(from, to, tokenId, _data),
      "ERC721A: transfer to non ERC721Receiver implementer"
    );
  }


  function _exists(uint256 tokenId) internal view returns (bool) {
    return tokenId < currentIndex;
  }

  function _safeMint(address to, uint256 quantity) internal {
    _safeMint(to, quantity, "");
  }


  function _safeMint(
    address to,
    uint256 quantity,
    bytes memory _data
  ) internal {
    uint256 startTokenId = currentIndex;
    require(to != address(0), "ERC721A: mint to the zero address");

    require(!_exists(startTokenId), "ERC721A: token already minted");
    require(quantity <= maxBatchSize, "ERC721A: quantity to mint too high");

    _beforeTokenTransfers(address(0), to, startTokenId, quantity);

    AddressData memory addressData = _addressData[to];
    _addressData[to] = AddressData(
      addressData.balance + uint128(quantity),
      addressData.numberMinted + uint128(quantity)
    );
    _ownerships[startTokenId] = TokenOwnership(to, uint64(block.timestamp));

    uint256 updatedIndex = startTokenId;

    for (uint256 i = 0; i < quantity; i++) {
      emit Transfer(address(0), to, updatedIndex);
      require(
        _checkOnERC721Received(address(0), to, updatedIndex, _data),
        "ERC721A: transfer to non ERC721Receiver implementer"
      );
      updatedIndex++;
    }

    currentIndex = updatedIndex;
    _afterTokenTransfers(address(0), to, startTokenId, quantity);
  }


  function _transfer(
    address from,
    address to,
    uint256 tokenId
  ) private {
    TokenOwnership memory prevOwnership = ownershipOf(tokenId);

    bool isApprovedOrOwner = (_msgSender() == prevOwnership.addr ||
      getApproved(tokenId) == _msgSender() ||
      isApprovedForAll(prevOwnership.addr, _msgSender()));

    require(
      isApprovedOrOwner,
      "ERC721A: transfer caller is not owner nor approved"
    );

    require(
      prevOwnership.addr == from,
      "ERC721A: transfer from incorrect owner"
    );
    require(to != address(0), "ERC721A: transfer to the zero address");

    _beforeTokenTransfers(from, to, tokenId, 1);


    _approve(address(0), tokenId, prevOwnership.addr);

    _addressData[from].balance -= 1;
    _addressData[to].balance += 1;
    _ownerships[tokenId] = TokenOwnership(to, uint64(block.timestamp));



    uint256 nextTokenId = tokenId + 1;
    if (_ownerships[nextTokenId].addr == address(0)) {
      if (_exists(nextTokenId)) {
        _ownerships[nextTokenId] = TokenOwnership(
          prevOwnership.addr,
          prevOwnership.startTimestamp
        );
      }
    }

    emit Transfer(from, to, tokenId);
    _afterTokenTransfers(from, to, tokenId, 1);
  }


  function _approve(
    address to,
    uint256 tokenId,
    address owner
  ) private {
    _tokenApprovals[tokenId] = to;
    emit Approval(owner, to, tokenId);
  }

  uint256 public nextOwnerToExplicitlySet = 0;



  function _setOwnersExplicit(uint256 quantity) internal {
    uint256 oldNextOwnerToSet = nextOwnerToExplicitlySet;
    require(quantity > 0, "quantity must be nonzero");
    uint256 endIndex = oldNextOwnerToSet + quantity - 1;
    if (endIndex > currentIndex - 1) {
      endIndex = currentIndex - 1;
    }

    require(_exists(endIndex), "not enough minted yet for this cleanup");
    for (uint256 i = oldNextOwnerToSet; i <= endIndex; i++) {
      if (_ownerships[i].addr == address(0)) {
        TokenOwnership memory ownership = ownershipOf(i);
        _ownerships[i] = TokenOwnership(
          ownership.addr,
          ownership.startTimestamp
        );
      }
    }
    nextOwnerToExplicitlySet = endIndex + 1;
  }


  function _checkOnERC721Received(
    address from,
    address to,
    uint256 tokenId,
    bytes memory _data
  ) private returns (bool) {
    if (to.isContract()) {
      try
        IERC721Receiver(to).onERC721Received(_msgSender(), from, tokenId, _data)
      returns (bytes4 retval) {
        return retval == IERC721Receiver(to).onERC721Received.selector;
      } catch (bytes memory reason) {
        if (reason.length == 0) {
          revert("ERC721A: transfer to non ERC721Receiver implementer");
        } else {
          assembly {
            revert(add(32, reason), mload(reason))
          }
        }
      }
    } else {
      return true;
    }
  }


  function _beforeTokenTransfers(
    address from,
    address to,
    uint256 startTokenId,
    uint256 quantity
  ) internal virtual {}


  function _afterTokenTransfers(
    address from,
    address to,
    uint256 startTokenId,
    uint256 quantity
  ) internal virtual {}
}

pragma solidity ^0.8.0;

import "@openzeppelin/contracts/token/ERC721/IERC721.sol";
import "@openzeppelin/contracts/token/ERC721/IERC721Receiver.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/IERC721Metadata.sol";
import "@openzeppelin/contracts/token/ERC721/extensions/IERC721Enumerable.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/utils/Context.sol";
import "@openzeppelin/contracts/utils/Strings.sol";
import "@openzeppelin/contracts/utils/introspection/ERC165.sol";


contract ERC721A is
  Context,
  ERC165,
  IERC721,
  IERC721Metadata,
  IERC721Enumerable
{
  using Address for address;
  using Strings for uint256;

  struct TokenOwnership {
    address addr;
    uint64 startTimestamp;
  }

  struct AddressData {
    uint128 balance;
    uint128 numberMinted;
  }

  uint256 private currentIndex = 1;

  uint256 internal immutable maxBatchSize;


  string private _name;


  string private _symbol;



  mapping(uint256 => TokenOwnership) private _ownerships;


  mapping(address => AddressData) private _addressData;


  mapping(uint256 => address) private _tokenApprovals;


  mapping(address => mapping(address => bool)) private _operatorApprovals;


  constructor(
    string memory name_,
    string memory symbol_,
    uint256 maxBatchSize_
  ) {
    require(maxBatchSize_ > 0, "ERC721A: max batch size must be nonzero");
    _name = name_;
    _symbol = symbol_;
    maxBatchSize = maxBatchSize_;
  }


  function totalSupply() public view override returns (uint256) {
    return currentIndex - 1;
  }


  function tokenByIndex(uint256 index) public view override returns (uint256) {
    require(index < totalSupply(), "ERC721A: global index out of bounds");
    return index;
  }



  function tokenOfOwnerByIndex(address owner, uint256 index)
    public
    view
    override
    returns (uint256)
  {
    require(index < balanceOf(owner), "ERC721A: owner index out of bounds");
    uint256 numMintedSoFar = totalSupply();
    uint256 tokenIdsIdx = 0;
    address currOwnershipAddr = address(0);
    for (uint256 i = 0; i < numMintedSoFar; i++) {
      TokenOwnership memory ownership = _ownerships[i];
      if (ownership.addr != address(0)) {
        currOwnershipAddr = ownership.addr;
      }
      if (currOwnershipAddr == owner) {
        if (tokenIdsIdx == index) {
          return i;
        }
        tokenIdsIdx++;
      }
    }
    revert("ERC721A: unable to get token of owner by index");
  }


  function supportsInterface(bytes4 interfaceId)
    public
    view
    virtual
    override(ERC165, IERC165)
    returns (bool)
  {
    return
      interfaceId == type(IERC721).interfaceId ||
      interfaceId == type(IERC721Metadata).interfaceId ||
      interfaceId == type(IERC721Enumerable).interfaceId ||
      super.supportsInterface(interfaceId);
  }


  function balanceOf(address owner) public view override returns (uint256) {
    require(owner != address(0), "ERC721A: balance query for the zero address");
    return uint256(_addressData[owner].balance);
  }


  function _numberMinted(address owner) internal view returns (uint256) {
    require(
      owner != address(0),
      "ERC721A: number minted query for the zero address"
    );
    return uint256(_addressData[owner].numberMinted);
  }

  function ownershipOf(uint256 tokenId)
    internal
    view
    returns (TokenOwnership memory)
  {
    require(_exists(tokenId), "ERC721A: owner query for nonexistent token");

    uint256 lowestTokenToCheck;
    if (tokenId >= maxBatchSize) {
      lowestTokenToCheck = tokenId - maxBatchSize + 1;
    }

    for (uint256 curr = tokenId; curr >= lowestTokenToCheck; curr--) {
      TokenOwnership memory ownership = _ownerships[curr];
      if (ownership.addr != address(0)) {
        return ownership;
      }
    }

    revert("ERC721A: unable to determine the owner of token");
  }


  function ownerOf(uint256 tokenId) public view override returns (address) {
    return ownershipOf(tokenId).addr;
  }


  function name() public view virtual override returns (string memory) {
    return _name;
  }


  function symbol() public view virtual override returns (string memory) {
    return _symbol;
  }


  function tokenURI(uint256 tokenId)
    public
    view
    virtual
    override
    returns (string memory)
  {
    require(
      _exists(tokenId),
      "ERC721Metadata: URI query for nonexistent token"
    );

    string memory baseURI = _baseURI();
    return
      bytes(baseURI).length > 0
        ? string(abi.encodePacked(baseURI, tokenId.toString()))
        : "";
  }


  function _baseURI() internal view virtual returns (string memory) {
    return "";
  }


  function approve(address to, uint256 tokenId) public override {
    address owner = ERC721A.ownerOf(tokenId);
    require(to != owner, "ERC721A: approval to current owner");

    require(
      _msgSender() == owner || isApprovedForAll(owner, _msgSender()),
      "ERC721A: approve caller is not owner nor approved for all"
    );

    _approve(to, tokenId, owner);
  }


  function getApproved(uint256 tokenId) public view override returns (address) {
    require(_exists(tokenId), "ERC721A: approved query for nonexistent token");

    return _tokenApprovals[tokenId];
  }


  function setApprovalForAll(address operator, bool approved) public override {
    require(operator != _msgSender(), "ERC721A: approve to caller");

    _operatorApprovals[_msgSender()][operator] = approved;
    emit ApprovalForAll(_msgSender(), operator, approved);
  }


  function isApprovedForAll(address owner, address operator)
    public
    view
    virtual
    override
    returns (bool)
  {
    return _operatorApprovals[owner][operator];
  }


  function transferFrom(
    address from,
    address to,
    uint256 tokenId
  ) public override {
    _transfer(from, to, tokenId);
  }


  function safeTransferFrom(
    address from,
    address to,
    uint256 tokenId
  ) public override {
    safeTransferFrom(from, to, tokenId, "");
  }


  function safeTransferFrom(
    address from,
    address to,
    uint256 tokenId,
    bytes memory _data
  ) public override {
    _transfer(from, to, tokenId);
    require(
      _checkOnERC721Received(from, to, tokenId, _data),
      "ERC721A: transfer to non ERC721Receiver implementer"
    );
  }


  function _exists(uint256 tokenId) internal view returns (bool) {
    return tokenId < currentIndex;
  }

  function _safeMint(address to, uint256 quantity) internal {
    _safeMint(to, quantity, "");
  }


  function _safeMint(
    address to,
    uint256 quantity,
    bytes memory _data
  ) internal {
    uint256 startTokenId = currentIndex;
    require(to != address(0), "ERC721A: mint to the zero address");

    require(!_exists(startTokenId), "ERC721A: token already minted");
    require(quantity <= maxBatchSize, "ERC721A: quantity to mint too high");

    _beforeTokenTransfers(address(0), to, startTokenId, quantity);

    AddressData memory addressData = _addressData[to];
    _addressData[to] = AddressData(
      addressData.balance + uint128(quantity),
      addressData.numberMinted + uint128(quantity)
    );
    _ownerships[startTokenId] = TokenOwnership(to, uint64(block.timestamp));

    uint256 updatedIndex = startTokenId;

    for (uint256 i = 0; i < quantity; i++) {
      emit Transfer(address(0), to, updatedIndex);
      require(
        _checkOnERC721Received(address(0), to, updatedIndex, _data),
        "ERC721A: transfer to non ERC721Receiver implementer"
      );
      updatedIndex++;
    }

    currentIndex = updatedIndex;
    _afterTokenTransfers(address(0), to, startTokenId, quantity);
  }


  function _transfer(
    address from,
    address to,
    uint256 tokenId
  ) private {
    TokenOwnership memory prevOwnership = ownershipOf(tokenId);

    bool isApprovedOrOwner = (_msgSender() == prevOwnership.addr ||
      getApproved(tokenId) == _msgSender() ||
      isApprovedForAll(prevOwnership.addr, _msgSender()));

    require(
      isApprovedOrOwner,
      "ERC721A: transfer caller is not owner nor approved"
    );

    require(
      prevOwnership.addr == from,
      "ERC721A: transfer from incorrect owner"
    );
    require(to != address(0), "ERC721A: transfer to the zero address");

    _beforeTokenTransfers(from, to, tokenId, 1);


    _approve(address(0), tokenId, prevOwnership.addr);

    _addressData[from].balance -= 1;
    _addressData[to].balance += 1;
    _ownerships[tokenId] = TokenOwnership(to, uint64(block.timestamp));



    uint256 nextTokenId = tokenId + 1;
    if (_ownerships[nextTokenId].addr == address(0)) {
      if (_exists(nextTokenId)) {
        _ownerships[nextTokenId] = TokenOwnership(
          prevOwnership.addr,
          prevOwnership.startTimestamp
        );
      }
    }

    emit Transfer(from, to, tokenId);
    _afterTokenTransfers(from, to, tokenId, 1);
  }


  function _approve(
    address to,
    uint256 tokenId,
    address owner
  ) private {
    _tokenApprovals[tokenId] = to;
    emit Approval(owner, to, tokenId);
  }

  uint256 public nextOwnerToExplicitlySet = 0;



  function _setOwnersExplicit(uint256 quantity) internal {
    uint256 oldNextOwnerToSet = nextOwnerToExplicitlySet;
    require(quantity > 0, "quantity must be nonzero");
    uint256 endIndex = oldNextOwnerToSet + quantity - 1;
    if (endIndex > currentIndex - 1) {
      endIndex = currentIndex - 1;
    }

    require(_exists(endIndex), "not enough minted yet for this cleanup");
    for (uint256 i = oldNextOwnerToSet; i <= endIndex; i++) {
      if (_ownerships[i].addr == address(0)) {
        TokenOwnership memory ownership = ownershipOf(i);
        _ownerships[i] = TokenOwnership(
          ownership.addr,
          ownership.startTimestamp
        );
      }
    }
    nextOwnerToExplicitlySet = endIndex + 1;
  }


  function _checkOnERC721Received(
    address from,
    address to,
    uint256 tokenId,
    bytes memory _data
  ) private returns (bool) {
    if (to.isContract()) {
      try
        IERC721Receiver(to).onERC721Received(_msgSender(), from, tokenId, _data)
      returns (bytes4 retval) {
        return retval == IERC721Receiver(to).onERC721Received.selector;
      } catch (bytes memory reason) {
        if (reason.length == 0) {
          revert("ERC721A: transfer to non ERC721Receiver implementer");
        } else {
          assembly {
            revert(add(32, reason), mload(reason))
          }
        }
      }
    } else {
      return true;
    }
  }


  function _beforeTokenTransfers(
    address from,
    address to,
    uint256 startTokenId,
    uint256 quantity
  ) internal virtual {}


  function _afterTokenTransfers(
    address from,
    address to,
    uint256 startTokenId,
    uint256 quantity
  ) internal virtual {}
}

pragma solidity ^0.8.4;

import { Ownable } from "@openzeppelin/contracts/access/Ownable.sol";
import { IERC20 } from "@openzeppelin/contracts/token/ERC20/IERC20.sol";

import "hardhat/console.sol";

contract GovStakingStorage is Ownable {
    IERC20 public gogo;
    uint256 totalLockedGogo;
    uint256 totalRewardRates;
    uint256 totalRewardMultiplier;

    struct UserInfo {
        uint256 amount; 
        uint256 lockStart; 
        uint256 lockPeriod; 
        uint256 lastClaimed; 
        uint256 unclaimedAmount; 
        uint256 rewardRate; 
        uint256 rewardMultiplier; 
        uint256 userRewardPerTokenPaid; 
        uint256 index;
    }

    mapping(address => UserInfo) public userInfo;
    address[] public userList;
    mapping(address => bool) public allowed;

    modifier isAllowed() {
        require(allowed[msg.sender], "sender is not allowed to write");
        _;
    }

    constructor(address gogoAddress) {
        gogo = IERC20(gogoAddress);
    }

    function addLockedGogo(uint256 amount) external isAllowed {
        totalLockedGogo += amount;
    }

    function removeLockedGogo(uint256 amount) external isAllowed {
        totalLockedGogo -= amount;
    }

    function addRewardRate(uint256 amount) external isAllowed {
        totalRewardRates += amount;
    }

    function removeRewardRate(uint256 amount) external isAllowed {
        totalRewardRates -= amount;
    }

    function updateRewardRate(uint256 oldRate, uint256 newRate)
        external
        isAllowed
    {
        totalRewardRates = totalRewardRates + newRate - oldRate;
    }

    function writeUser(
        address user,
        uint256 amount,
        uint256 lockStart,
        uint256 lockPeriod,
        uint256 lastClaimed,
        uint256 unclaimedAmount, 
        uint256 rewardRate
    ) external isAllowed {
        UserInfo storage info = userInfo[user];
        info.amount = amount;
        info.lockStart = lockStart;
        info.lockPeriod = lockPeriod;
        info.lastClaimed = lastClaimed;
        info.unclaimedAmount = unclaimedAmount;
        info.rewardRate = rewardRate;
        if (userInfo[user].index == 0) {
            info.index = userList.length;
            userList.push(user);
        }
        userInfo[user] = info;
    }

    function removeUser(address user) external isAllowed {
        require(userInfo[user].index != 0, "user does not exist");
        if (userList.length > 1) {
            address lastAddress = userList[userList.length - 1];
            uint256 oldIndex = userInfo[user].index;
            userList[oldIndex] = lastAddress;
            userInfo[lastAddress].index = oldIndex;
        }
        userList.pop();
        totalRewardMultiplier -= userInfo[user].rewardMultiplier;
        delete userInfo[user];
    }

    function transferGogo(address to, uint256 amount) external isAllowed {
        gogo.transfer(to, amount);
    }

    function updateRewardMultiplier(
        address user,
        uint256 oldRate,
        uint256 newRate,
        uint256 passedTime,
        uint256 oldLockPeriod,
        uint256 newLockPeriod,
        uint256 oldAmount,
        uint256 newAmount
    ) external isAllowed {
        UserInfo storage info = userInfo[user];
        uint256 toRemove = ((((oldLockPeriod - passedTime) / 1 weeks) *
            oldRate) * oldAmount) / 100000;
        uint256 toAdd = (((newLockPeriod / 1 weeks) * newRate) * newAmount) /
            100000;
        info.rewardMultiplier = info.rewardMultiplier + toAdd - toRemove;
        totalRewardMultiplier = totalRewardMultiplier + toAdd - toRemove;
    }

    function addRewardMultiplier(
        address user,
        uint256 rate,
        uint256 period,
        uint256 amount
    ) external isAllowed {
        UserInfo storage info = userInfo[user];
        info.rewardMultiplier +=
            ((((rate * period) / 1 weeks) * amount)) /
            100000;
        totalRewardMultiplier +=
            ((((rate * period) / 1 weeks) * amount)) /
            100000;
    }

    function removeRewardMultiplier(address user) public isAllowed {
        UserInfo storage info = userInfo[user];
        totalRewardMultiplier -= info.rewardMultiplier;
        info.rewardMultiplier = 0;
    }

    function addUserRewardPerTokenPaid(address user, uint256 amount)
        external
        isAllowed
    {
        UserInfo storage info = userInfo[user];
        info.userRewardPerTokenPaid += amount;
    }


    function getTotalLockedGogo() external view returns (uint256) {
        return totalLockedGogo;
    }

    function getTotalRewardRates() external view returns (uint256) {
        return totalRewardRates;
    }

    function getUserMultiplier(address user) public view returns (uint256) {
        return userInfo[user].rewardMultiplier;
    }

    function getUserInformation(address user)
        external
        view
        returns (UserInfo memory)
    {
        return userInfo[user];
    }

    function getUserListLength() external view returns (uint256) {
        return userList.length;
    }

    function getAmount(address user) public view returns (uint256) {
        return userInfo[user].amount;
    }

    function getUserRewardPerTokenPaid(address user)
        public
        view
        returns (uint256)
    {
        return userInfo[user].userRewardPerTokenPaid;
    }

    function setUserRewardPerTokenPaid(address user, uint256 amount)
        external
        isAllowed
    {
        UserInfo storage info = userInfo[user];
        info.userRewardPerTokenPaid = amount;
    }


    function getUserInfoByIndex(uint256 from, uint256 to)
        external
        view
        returns (UserInfo[] memory)
    {
        uint256 to_ = to > userList.length ? userList.length : to;
        UserInfo[] memory result = new UserInfo[](to - from);
        for (uint256 i = 0; i < to_ - from; i++) {
            result[i] = userInfo[userList[i + from]];
        }
        return result;
    }

    function getRewardMultiplier() public view returns (uint256) {
        return totalRewardMultiplier;
    }

    function getLockDate(address user) public view returns (uint256) {
        return (userInfo[user].lockStart + userInfo[user].lockPeriod);
    }


    function setWriteAllowance(address to, bool flag) external onlyOwner {
        allowed[to] = flag;
    }

    function emergencyWithdraw() external onlyOwner {
        gogo.transfer(owner(), gogo.balanceOf(address(this)));
    }
}

pragma solidity ^0.8.4;





import "@openzeppelin/contracts/token/ERC1155/presets/ERC1155PresetMinterPauser.sol";
import "@openzeppelin/contracts/token/ERC20/presets/ERC20PresetMinterPauser.sol";
import "hardhat/console.sol";

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";

contract IDO is Ownable {
    IERC20 public GZT;

    bool public idoStatus;

    uint256 public idoStart;
    uint256 public idoFinish;

    uint256 public cooldownToClaim;
    uint256 public allowedAmountToClaim;

    address[] public _allowedTokens;

    struct WhitelistInstance {
        uint256 maxAmountToClaim;
        bool isWhitelisted;
    }

    struct IDOParticipant {
        uint256 start;
        uint256 amountToClaim;
        uint256 claimedLastTime;
        uint256 claimedAmount;
        bool hasClaimed;
    }

    mapping(address => WhitelistInstance) public whitelist;
    mapping(address => IDOParticipant) public pool;

    mapping(IERC20 => bool) public allowedTokens;
    mapping(IERC20 => uint256[2]) public rates; 

    event UserIsWhitelisted(address indexed user, uint256 indexed amount);
    event NewIDOParticipant(IERC20 indexed token, address indexed user, uint256 amount);

    constructor(IERC20 _IDO_TOKEN) {
        GZT = _IDO_TOKEN;
    }

    function participate(uint256 amountToSpent, IERC20 token) external {
        uint256[2] memory rate = rates[token];
        uint256 amountToClaim = ((amountToSpent * rate[0]) / rate[1]);

        require(idoStatus, "The IDO is not started!");
        require(block.timestamp < idoFinish, "The IDO is already finished!");
        require(pool[msg.sender].start == 0, "You're already participating in IDO");
        require(token.balanceOf(msg.sender) >= amountToSpent, "You don't have enough money!");
        require(whitelist[msg.sender].maxAmountToClaim >= amountToClaim, "You're not permited to claim this amount!");
        require(whitelist[msg.sender].isWhitelisted, "You're not whitelisted");

        require(allowedTokens[token], "This token is not allowed to participate");

        token.transferFrom(msg.sender, address(this), amountToSpent);

        pool[msg.sender] = IDOParticipant({
            start: block.timestamp,
            amountToClaim: amountToClaim,
            claimedLastTime: 0,
            claimedAmount: 0,
            hasClaimed: false
        });

        emit NewIDOParticipant(token, msg.sender, amountToSpent);
    }



    function claim() external {
        require(block.timestamp > idoFinish, "The IDO is not finished yet");
        require(pool[msg.sender].start != 0, "You're not participating in IDO");
        require(
            (block.timestamp - pool[msg.sender].claimedLastTime) > cooldownToClaim,
            "You are not allowed to claime more at this time"
        );
        require(!pool[msg.sender].hasClaimed, "You already claimed");

        if (
            (pool[msg.sender].claimedAmount < pool[msg.sender].amountToClaim) &&
            ((pool[msg.sender].amountToClaim - pool[msg.sender].claimedAmount) >= allowedAmountToClaim)
        ) {

            GZT.transfer(msg.sender, allowedAmountToClaim);
            pool[msg.sender].claimedLastTime = block.timestamp;
        } else if (
            (pool[msg.sender].claimedAmount < pool[msg.sender].amountToClaim) &&
            ((pool[msg.sender].amountToClaim - pool[msg.sender].claimedAmount) < allowedAmountToClaim)
        ) {
            GZT.transfer(msg.sender, (pool[msg.sender].amountToClaim - pool[msg.sender].claimedAmount));
            pool[msg.sender].claimedLastTime = block.timestamp;
            pool[msg.sender].hasClaimed = true;
        }
    }

    function addUsersToWhitelist(address[] memory users, uint256[] memory amounts) external onlyOwner {
        require(users.length == amounts.length, "invalid array lengths");
        for (uint256 i = 0; i < amounts.length; i++) {
            whitelist[users[i]] = WhitelistInstance({maxAmountToClaim: amounts[i], isWhitelisted: true});
            emit UserIsWhitelisted(users[i], amounts[i]);
        }
    }

    function allowToken(
        IERC20 token,
        uint256 rateNumerator,
        uint256 rateDenominator
    ) external onlyOwner {
        allowedTokens[token] = true;
        rates[token] = [rateNumerator, rateDenominator];
        _allowedTokens.push(address(token));
    }

    function disallowTokens(IERC20 token) external onlyOwner {
        allowedTokens[token] = false;
    }

    function setIDO(
        uint256 start,
        uint256 finish,
        uint256 cooldown,
        uint256 _allowedAmountToClaim
    ) external onlyOwner {
        idoStatus = true;
        idoStart = start;
        idoFinish = finish;

        cooldownToClaim = cooldown;
        allowedAmountToClaim = _allowedAmountToClaim;
    }


    function claimTheInvestments(IERC20 token, uint256 amount) external onlyOwner {
        require(block.timestamp > idoFinish, "The IDO is not finished yet");


        token.transfer(msg.sender, amount);
    }

    function infoBundler(address user)
        external
        view
        onlyOwner
        returns (
            WhitelistInstance memory whitelistInstance,
            IDOParticipant memory icoParticipantInstance,
            uint256[] memory _balancesOfAUser
        )
    {
        uint256[] memory balancesOfAUser;
        for (uint256 i = 0; i < _allowedTokens.length; i++) {
            IERC20 token = IERC20(_allowedTokens[i]);
            balancesOfAUser[i] = token.balanceOf(user);
        }

        return (whitelist[user], pool[user], balancesOfAUser);
    }
