contract PowerBombFtmCurveGeist is PowerBombAvaxCurve {
    using SafeERC20Upgradeable for IERC20Upgradeable;

    IERC20Upgradeable constant fUSDT = IERC20Upgradeable(0x049d68029688eAbF473097a2fC38ef61633A3C7A);
