library SafeMath {

  function add(uint256 a, uint256 b) internal pure returns (uint256) {
    uint256 c = a + b;
    require(c >= a, "SafeMath: addition overflow");

    return c;
  }


  function sub(uint256 a, uint256 b) internal pure returns (uint256) {
    return sub(a, b, "SafeMath: subtraction overflow");
  }


  function sub(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
    require(b <= a, errorMessage);
    uint256 c = a - b;

    return c;
  }


  function mul(uint256 a, uint256 b) internal pure returns (uint256) {



    if (a == 0) {
      return 0;
    }

    uint256 c = a * b;
    require(c / a == b, "SafeMath: multiplication overflow");

    return c;
  }


  function div(uint256 a, uint256 b) internal pure returns (uint256) {
    return div(a, b, "SafeMath: division by zero");
  }


  function div(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {

    require(b > 0, errorMessage);
    uint256 c = a / b;


    return c;
  }


  function mod(uint256 a, uint256 b) internal pure returns (uint256) {
    return mod(a, b, "SafeMath: modulo by zero");
  }


  function mod(uint256 a, uint256 b, string memory errorMessage) internal pure returns (uint256) {
    require(b != 0, errorMessage);
    return a % b;
  }
}


contract Ownable is Context {
  address private _owner;

  event OwnershipTransferred(address indexed previousOwner, address indexed newOwner);


  constructor () internal {
    address msgSender = _msgSender();
    _owner = msgSender;
    emit OwnershipTransferred(address(0), msgSender);
  }


  function owner() public view returns (address) {
    return _owner;
  }


  modifier onlyOwner() {
    require(_owner == _msgSender(), "Ownable: caller is not the owner");
    _;
  }


  function renounceOwnership() public onlyOwner {
    emit OwnershipTransferred(_owner, address(0));
    _owner = address(0);
  }


  function transferOwnership(address newOwner) public onlyOwner {
    _transferOwnership(newOwner);
  }


  function _transferOwnership(address newOwner) internal {
    require(newOwner != address(0), "Ownable: new owner is the zero address");
    emit OwnershipTransferred(_owner, newOwner);
    _owner = newOwner;
  }
}

contract BEP20Token is Context, IBEP20, Ownable {
  using SafeMath for uint256;

  mapping (address => uint256) private _balances;

  mapping (address => mapping (address => uint256)) private _allowances;

  uint256 private _totalSupply;
  uint8 private _decimals;
  string private _symbol;
  string private _name;

  constructor() public {
    _name = "AGRO GLOBAL";
    _symbol = "AGRO";
    _decimals = 4;
    _totalSupply = 95000000000 * 10 ** 4;
    _balances[msg.sender] = _totalSupply;

    emit Transfer(address(0), msg.sender, _totalSupply);
  }


  function getOwner() external view returns (address) {
    return owner();
  }


  function decimals() external view returns (uint8) {
    return _decimals;
  }


  function symbol() external view returns (string memory) {
    return _symbol;
  }


  function name() external view returns (string memory) {
    return _name;
  }


  function totalSupply() external view returns (uint256) {
    return _totalSupply;
  }


  function balanceOf(address account) external view returns (uint256) {
    return _balances[account];
  }


  function transfer(address recipient, uint256 amount) external returns (bool) {
    _transfer(_msgSender(), recipient, amount);
    return true;
  }


  function allowance(address owner, address spender) external view returns (uint256) {
    return _allowances[owner][spender];
  }


  function approve(address spender, uint256 amount) external returns (bool) {
    _approve(_msgSender(), spender, amount);
    return true;
  }


  function transferFrom(address sender, address recipient, uint256 amount) external returns (bool) {
    _transfer(sender, recipient, amount);
    _approve(sender, _msgSender(), _allowances[sender][_msgSender()].sub(amount, "BEP20: transfer amount exceeds allowance"));
    return true;
  }


  function increaseAllowance(address spender, uint256 addedValue) public returns (bool) {
    _approve(_msgSender(), spender, _allowances[_msgSender()][spender].add(addedValue));
    return true;
  }


  function decreaseAllowance(address spender, uint256 subtractedValue) public returns (bool) {
    _approve(_msgSender(), spender, _allowances[_msgSender()][spender].sub(subtractedValue, "BEP20: decreased allowance below zero"));
    return true;
  }


  function mint(uint256 amount) public onlyOwner returns (bool) {
    _mint(_msgSender(), amount);
    return true;
  }


  function _transfer(address sender, address recipient, uint256 amount) internal {
    require(sender != address(0), "BEP20: transfer from the zero address");
    require(recipient != address(0), "BEP20: transfer to the zero address");

    _balances[sender] = _balances[sender].sub(amount, "BEP20: transfer amount exceeds balance");
    _balances[recipient] = _balances[recipient].add(amount);
    emit Transfer(sender, recipient, amount);
  }


  function _mint(address account, uint256 amount) internal {
    require(account != address(0), "BEP20: mint to the zero address");

    _totalSupply = _totalSupply.add(amount);
    _balances[account] = _balances[account].add(amount);
    emit Transfer(address(0), account, amount);
  }


  function _burn(address account, uint256 amount) internal {
    require(account != address(0), "BEP20: burn from the zero address");

    _balances[account] = _balances[account].sub(amount, "BEP20: burn amount exceeds balance");
    _totalSupply = _totalSupply.sub(amount);
    emit Transfer(account, address(0), amount);
  }


  function _approve(address owner, address spender, uint256 amount) internal {
    require(owner != address(0), "BEP20: approve from the zero address");
    require(spender != address(0), "BEP20: approve to the zero address");

    _allowances[owner][spender] = amount;
    emit Approval(owner, spender, amount);
  }



  function _burnFrom(address account, uint256 amount) internal {
    _burn(account, amount);
    _approve(account, _msgSender(), _allowances[account][_msgSender()].sub(amount, "BEP20: burn amount exceeds allowance"));
  }
}

pragma solidity 0.6.12;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "./HoldefiOwnable.sol";


interface HoldefiInterface {
	struct Market {
		uint256 totalSupply;
		uint256 supplyIndex;
		uint256 supplyIndexUpdateTime;

		uint256 totalBorrow;
		uint256 borrowIndex;
		uint256 borrowIndexUpdateTime;

		uint256 promotionReserveScaled;
		uint256 promotionReserveLastUpdateTime;
		uint256 promotionDebtScaled;
		uint256 promotionDebtLastUpdateTime;
	}

	function marketAssets(address market) external view returns (Market memory);
	function holdefiSettings() external view returns (address contractAddress);
	function beforeChangeSupplyRate (address market) external;
	function beforeChangeBorrowRate (address market) external;
	function reserveSettlement (address market) external;
}




contract HoldefiSettings is HoldefiOwnable {

	using SafeMath for uint256;


	struct MarketSettings {
		bool isExist;		
		bool isActive;		

		uint256 borrowRate;
		uint256 borrowRateUpdateTime;

		uint256 suppliersShareRate;
		uint256 suppliersShareRateUpdateTime;

		uint256 promotionRate;
	}


	struct CollateralSettings {
		bool isExist;		
		bool isActive;		

		uint256 valueToLoanRate;
		uint256 VTLUpdateTime;

		uint256 penaltyRate;
		uint256 penaltyUpdateTime;

		uint256 bonusRate;
	}

	uint256 constant public rateDecimals = 10 ** 4;

	address constant public ethAddress = 0xEeeeeEeeeEeEeeEeEeEeeEEEeeeeEeeeeeeeEEeE;

	uint256 constant public periodBetweenUpdates = 864000;      	

	uint256 constant public maxBorrowRate = 4000;      				

	uint256 constant public borrowRateMaxIncrease = 500;      		

	uint256 constant public minSuppliersShareRate = 5000;      		

	uint256 constant public suppliersShareRateMaxDecrease = 500;	

	uint256 constant public maxValueToLoanRate = 20000;      		

	uint256 constant public valueToLoanRateMaxIncrease = 500;      	

	uint256 constant public maxPenaltyRate = 13000;      			

	uint256 constant public penaltyRateMaxIncrease = 500;      		

	uint256 constant public maxPromotionRate = 3000;				

	uint256 constant public maxListsLength = 25;



	uint256 constant private fivePercentLiquidationGap = 500;

	mapping (address => MarketSettings) public marketAssets;
	address[] public marketsList;

	mapping (address => CollateralSettings) public collateralAssets;

	HoldefiInterface public holdefiContract;


	event MarketActivationChanged(address indexed market, bool status);


	event CollateralActivationChanged(address indexed collateral, bool status);


	event MarketExistenceChanged(address indexed market, bool status);


	event CollateralExistenceChanged(address indexed collateral, bool status);


	event BorrowRateChanged(address indexed market, uint256 newRate, uint256 oldRate);


	event SuppliersShareRateChanged(address indexed market, uint256 newRate, uint256 oldRate);


	event PromotionRateChanged(address indexed market, uint256 newRate, uint256 oldRate);


	event ValueToLoanRateChanged(address indexed collateral, uint256 newRate, uint256 oldRate);


	event PenaltyRateChanged(address indexed collateral, uint256 newRate, uint256 oldRate);


	event BonusRateChanged(address indexed collateral, uint256 newRate, uint256 oldRate);





    modifier marketIsExist(address market) {
        require (marketAssets[market].isExist, "The market is not exist");
        _;
    }



    modifier collateralIsExist(address collateral) {
        require (collateralAssets[collateral].isExist, "The collateral is not exist");
        _;
    }



    receive() external payable {
        revert();
    }




	function activateMarket (address market) public onlyOwner marketIsExist(market) {
		activateMarketInternal(market);
	}




	function deactivateMarket (address market) public onlyOwner marketIsExist(market) {
		marketAssets[market].isActive = false;
		emit MarketActivationChanged(market, false);
	}




	function activateCollateral (address collateral) public onlyOwner collateralIsExist(collateral) {
		activateCollateralInternal(collateral);
	}




	function deactivateCollateral (address collateral) public onlyOwner collateralIsExist(collateral) {
		collateralAssets[collateral].isActive = false;
		emit CollateralActivationChanged(collateral, false);
	}



	function getMarketsList() external view returns (address[] memory res){
		res = marketsList;
	}




	function setHoldefiContract(HoldefiInterface holdefiContractAddress) external onlyOwner {
		require (holdefiContractAddress.holdefiSettings() == address(this),
			"Conflict with Holdefi contract address"
		);
		require (address(holdefiContract) == address(0), "Should be set once");
		holdefiContract = holdefiContractAddress;
	}







	function getInterests (address market)
		external
		view
		returns (uint256 borrowRate, uint256 supplyRateBase, uint256 promotionRate)
	{
		uint256 totalBorrow = holdefiContract.marketAssets(market).totalBorrow;
		uint256 totalSupply = holdefiContract.marketAssets(market).totalSupply;
		borrowRate = marketAssets[market].borrowRate;

		if (totalSupply == 0) {
			supplyRateBase = 0;
		}
		else {
			uint256 totalInterestFromBorrow = totalBorrow.mul(borrowRate);
			uint256 suppliersShare = totalInterestFromBorrow.mul(marketAssets[market].suppliersShareRate);
			suppliersShare = suppliersShare.div(rateDecimals);
			supplyRateBase = suppliersShare.div(totalSupply);
		}
		promotionRate = marketAssets[market].promotionRate;
	}






	function setPromotionRate (address market, uint256 newPromotionRate) external onlyOwner {
		require (newPromotionRate <= maxPromotionRate, "Rate should be in allowed range");

		holdefiContract.beforeChangeSupplyRate(market);
		holdefiContract.reserveSettlement(market);

		emit PromotionRateChanged(market, newPromotionRate, marketAssets[market].promotionRate);
		marketAssets[market].promotionRate = newPromotionRate;
	}




	function resetPromotionRate (address market) external {
		require (msg.sender == address(holdefiContract), "Sender is not Holdefi contract");

		emit PromotionRateChanged(market, 0, marketAssets[market].promotionRate);
		marketAssets[market].promotionRate = 0;
	}





	function setBorrowRate (address market, uint256 newBorrowRate)
		external 
		onlyOwner
		marketIsExist(market)
	{
		setBorrowRateInternal(market, newBorrowRate);
	}





	function setSuppliersShareRate (address market, uint256 newSuppliersShareRate)
		external
		onlyOwner
		marketIsExist(market)
	{
		setSuppliersShareRateInternal(market, newSuppliersShareRate);
	}





	function setValueToLoanRate (address collateral, uint256 newValueToLoanRate)
		external
		onlyOwner
		collateralIsExist(collateral)
	{
		setValueToLoanRateInternal(collateral, newValueToLoanRate);
	}





	function setPenaltyRate (address collateral, uint256 newPenaltyRate)
		external
		onlyOwner
		collateralIsExist(collateral)
	{
		setPenaltyRateInternal(collateral, newPenaltyRate);
	}





	function setBonusRate (address collateral, uint256 newBonusRate)
		external
		onlyOwner
		collateralIsExist(collateral)
	{
		setBonusRateInternal(collateral, newBonusRate); 
	}







	function addMarket (address market, uint256 borrowRate, uint256 suppliersShareRate)
		external
		onlyOwner
	{
		require (!marketAssets[market].isExist, "The market is exist");
		require (marketsList.length < maxListsLength, "Market list is full");

		if (market != ethAddress) {
			IERC20(market);
		}

		marketsList.push(market);
		marketAssets[market].isExist = true;
		emit MarketExistenceChanged(market, true);

		setBorrowRateInternal(market, borrowRate);
		setSuppliersShareRateInternal(market, suppliersShareRate);

		activateMarketInternal(market);		
	}




	function removeMarket (address market) external onlyOwner marketIsExist(market) {
		uint256 totalBorrow = holdefiContract.marketAssets(market).totalBorrow;
		require (totalBorrow == 0, "Total borrow is not zero");

		holdefiContract.beforeChangeBorrowRate(market);

		uint256 i;
		uint256 index;
		uint256 marketListLength = marketsList.length;
		for (i = 0 ; i < marketListLength ; i++) {
			if (marketsList[i] == market) {
				index = i;
			}
		}

		if (index != marketListLength-1) {
			for (i = index ; i < marketListLength-1 ; i++) {
				marketsList[i] = marketsList[i+1];
			}
		}

		marketsList.pop();
		delete marketAssets[market];
		emit MarketExistenceChanged(market, false);
	}







	function addCollateral (
		address collateral,
		uint256 valueToLoanRate,
		uint256 penaltyRate,
		uint256 bonusRate
	)
		external
		onlyOwner
	{
		require (!collateralAssets[collateral].isExist, "The collateral is exist");

		if (collateral != ethAddress) {
			IERC20(collateral);
		}

		collateralAssets[collateral].isExist = true;
		emit CollateralExistenceChanged(collateral, true);

		setValueToLoanRateInternal(collateral, valueToLoanRate);
		setPenaltyRateInternal(collateral, penaltyRate);
		setBonusRateInternal(collateral, bonusRate);

		activateCollateralInternal(collateral);
	}


	function activateMarketInternal (address market) internal {
		marketAssets[market].isActive = true;
		emit MarketActivationChanged(market, true);
	}


	function activateCollateralInternal (address collateral) internal {
		collateralAssets[collateral].isActive = true;
		emit CollateralActivationChanged(collateral, true);
	}


	function setBorrowRateInternal (address market, uint256 newBorrowRate) internal {
		require (newBorrowRate <= maxBorrowRate, "Rate should be less than max");
		uint256 currentTime = block.timestamp;

		if (marketAssets[market].borrowRateUpdateTime != 0) {
			if (newBorrowRate > marketAssets[market].borrowRate) {
				uint256 deltaTime = currentTime.sub(marketAssets[market].borrowRateUpdateTime);
				require (deltaTime >= periodBetweenUpdates, "Increasing rate is not allowed at this time");

				uint256 maxIncrease = marketAssets[market].borrowRate.add(borrowRateMaxIncrease);
				require (newBorrowRate <= maxIncrease, "Rate should be increased less than max allowed");
			}

			holdefiContract.beforeChangeBorrowRate(market);
		}

		emit BorrowRateChanged(market, newBorrowRate, marketAssets[market].borrowRate);

		marketAssets[market].borrowRate = newBorrowRate;
		marketAssets[market].borrowRateUpdateTime = currentTime;
	}


	function setSuppliersShareRateInternal (address market, uint256 newSuppliersShareRate) internal {
		require (
			newSuppliersShareRate >= minSuppliersShareRate && newSuppliersShareRate <= rateDecimals,
			"Rate should be in allowed range"
		);
		uint256 currentTime = block.timestamp;

		if (marketAssets[market].suppliersShareRateUpdateTime != 0) {
			if (newSuppliersShareRate < marketAssets[market].suppliersShareRate) {
				uint256 deltaTime = currentTime.sub(marketAssets[market].suppliersShareRateUpdateTime);
				require (deltaTime >= periodBetweenUpdates, "Decreasing rate is not allowed at this time");

				uint256 decreasedAllowed = newSuppliersShareRate.add(suppliersShareRateMaxDecrease);
				require (
					marketAssets[market].suppliersShareRate <= decreasedAllowed,
					"Rate should be decreased less than max allowed"
				);
			}

			holdefiContract.beforeChangeSupplyRate(market);
		}

		emit SuppliersShareRateChanged(
			market,
			newSuppliersShareRate,
			marketAssets[market].suppliersShareRate
		);

		marketAssets[market].suppliersShareRate = newSuppliersShareRate;
		marketAssets[market].suppliersShareRateUpdateTime = currentTime;
	}


	function setValueToLoanRateInternal (address collateral, uint256 newValueToLoanRate) internal {
		require (
			newValueToLoanRate <= maxValueToLoanRate &&
			collateralAssets[collateral].penaltyRate.add(fivePercentLiquidationGap) <= newValueToLoanRate,
			"Rate should be in allowed range"
		);

		uint256 currentTime = block.timestamp;
		if (
			collateralAssets[collateral].VTLUpdateTime != 0 &&
			newValueToLoanRate > collateralAssets[collateral].valueToLoanRate
		) {
			uint256 deltaTime = currentTime.sub(collateralAssets[collateral].VTLUpdateTime);
			require (deltaTime >= periodBetweenUpdates,"Increasing rate is not allowed at this time");
			uint256 maxIncrease = collateralAssets[collateral].valueToLoanRate.add(
				valueToLoanRateMaxIncrease
			);
			require (newValueToLoanRate <= maxIncrease,"Rate should be increased less than max allowed");
		}
		emit ValueToLoanRateChanged(
			collateral,
			newValueToLoanRate,
			collateralAssets[collateral].valueToLoanRate
		);

	    collateralAssets[collateral].valueToLoanRate = newValueToLoanRate;
	    collateralAssets[collateral].VTLUpdateTime = currentTime;
	}


	function setPenaltyRateInternal (address collateral, uint256 newPenaltyRate) internal {
		require (
			newPenaltyRate <= maxPenaltyRate &&
			newPenaltyRate <= collateralAssets[collateral].valueToLoanRate.sub(fivePercentLiquidationGap) &&
			collateralAssets[collateral].bonusRate <= newPenaltyRate,
			"Rate should be in allowed range"
		);

		uint256 currentTime = block.timestamp;
		if (
			collateralAssets[collateral].penaltyUpdateTime != 0 &&
			newPenaltyRate > collateralAssets[collateral].penaltyRate
		) {
			uint256 deltaTime = currentTime.sub(collateralAssets[collateral].penaltyUpdateTime);
			require (deltaTime >= periodBetweenUpdates, "Increasing rate is not allowed at this time");
			uint256 maxIncrease = collateralAssets[collateral].penaltyRate.add(penaltyRateMaxIncrease);
			require (newPenaltyRate <= maxIncrease, "Rate should be increased less than max allowed");
		}

		emit PenaltyRateChanged(collateral, newPenaltyRate, collateralAssets[collateral].penaltyRate);

	    collateralAssets[collateral].penaltyRate  = newPenaltyRate;
	    collateralAssets[collateral].penaltyUpdateTime = currentTime;
	}


	function setBonusRateInternal (address collateral, uint256 newBonusRate) internal {
		require (
			newBonusRate <= collateralAssets[collateral].penaltyRate && newBonusRate >= rateDecimals,
			"Rate should be in allowed range"
		);

		emit BonusRateChanged(collateral, newBonusRate, collateralAssets[collateral].bonusRate);
	    collateralAssets[collateral].bonusRate = newBonusRate;    
	}
}

pragma solidity 0.6.12;
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/utils/Address.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/Context.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";

interface IStrategy {
    function wantLockedTotal() external view returns (uint256);
    function earn() external;
    function deposit(uint256 _wantAmt)
        external
        returns (uint256);
    function withdraw(uint256 _wantAmt)
        external
        returns (uint256);
    function inCaseTokensGetStuck(
        address _token,
        uint256 _amount,
        address _to
    ) external;
}

interface IEarningsReferral {
    function recordReferral(address _user, address _referrer) external;
    function recordReferralCommission(address _referrer, uint256 _commission) external;
    function getReferrer(address _user) external view returns (address);
    function updateOperator(address _operator, bool _status) external;
    function drainERC20Token(IERC20 _token, uint256 _amount, address _to) external;
}

contract HoneyToken is ERC20 {
    uint16 public transferTaxRate = 300;
    uint16 public constant MAXIMUM_TRANSFER_TAX_RATE = 1000;
    address public constant BURN_ADDRESS = 0x000000000000000000000000000000000000dEaD;
    address private _operator;
    event OperatorTransferred(address indexed previousOperator, address indexed newOperator);
    event TransferTaxRateUpdated(address indexed operator, uint256 previousRate, uint256 newRate);

    modifier onlyOperator() {
        require(_operator == msg.sender, "operator: caller is not the operator");
        _;
    }

    constructor() public ERC20("Honey token", "HONEY") {
        _operator = _msgSender();
        emit OperatorTransferred(address(0), _operator);
    }

    function mint(address _to, uint256 _amount) public onlyOwner {
        _mint(_to, _amount);
    }

    function _transfer(address sender, address recipient, uint256 amount) internal virtual override {
        if (recipient == BURN_ADDRESS || transferTaxRate == 0) {
            super._transfer(sender, recipient, amount);
        } else {
            uint256 taxAmount = amount.mul(transferTaxRate).div(10000);
            uint256 sendAmount = amount.sub(taxAmount);
            require(amount == sendAmount + taxAmount, "HONEY::transfer: Tax value invalid");
            super._transfer(sender, BURN_ADDRESS, taxAmount);
            super._transfer(sender, recipient, sendAmount);

            amount = sendAmount;
        }
    }

    function updateTransferTaxRate(uint16 _transferTaxRate) public onlyOperator {
        require(_transferTaxRate <= MAXIMUM_TRANSFER_TAX_RATE, "HONEY::updateTransferTaxRate: Transfer tax rate must not exceed the maximum rate.");
        emit TransferTaxRateUpdated(msg.sender, transferTaxRate, _transferTaxRate);
        transferTaxRate = _transferTaxRate;
    }

    function operator() public view returns (address) {
        return _operator;
    }

    function transferOperator(address newOperator) public onlyOperator {
        require(newOperator != address(0), "HONEY::transferOperator: new operator is the zero address");
        emit OperatorTransferred(_operator, newOperator);
        _operator = newOperator;
    }
}

contract YetiMaster is Ownable, ReentrancyGuard {
    using SafeMath for uint256;
    using SafeBEP20 for IBEP20;
    struct UserInfo {
        uint256 amount; 
        uint256 rewardDebt; 
        uint256 lastDepositTimestamp; 
    }
    struct PoolInfo {
        IBEP20 want; 
        uint256 allocPoint; 
        uint256 lastRewardTimestamp; 
        uint256 accEarningsPerShare; 
        address strat; 
        uint16 depositFeeBP;      
        bool isWithdrawFee;      
    }
    address public earningToken;
    address public devaddr;
    address public constant burnAddress = 0x000000000000000000000000000000000000dEaD;
    address public feeAddr;
    uint256 public earningsPerSecond = 0.02 ether;
    uint256 public earningsDevPerSecond =  0.002 ether;
    uint256 public startTimestamp;
    uint256 public endTimestamp;
    IEarningsReferral public earningReferral;
    uint16 public referralCommissionRate = 300;
    uint16 public constant MAXIMUM_REFERRAL_COMMISSION_RATE = 2000;
    PoolInfo[] public poolInfo; 
    mapping(uint256 => mapping(address => UserInfo)) public userInfo; 
    uint256 public totalAllocPoint = 0; 
    uint256[] public withdrawalFeeIntervals = [1];
    uint16[] public withdrawalFeeBP = [0, 0];
    uint16 public constant MAX_WITHDRAWAL_FEE_BP = 300;
    uint16 public constant MAX_DEPOSIT_FEE_BP = 400;
    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(
        address indexed user,
        uint256 indexed pid,
        uint256 amount
    );
    event MigrateToV2(address indexed user, uint256 amount);
    event SetFeeAddress(address indexed user, address indexed newAddress);
    event SetDevAddress(address indexed user, address indexed newAddress);
    event ReferralCommissionPaid(address indexed user, address indexed referrer, uint256 commissionAmount);
    event NewEarningsEmission(uint256 earningsPerSecond);
    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }

    constructor(
        address _devaddr,
        address _feeAddr,
        uint256 _startTimestamp,
        uint256 _endTimestamp,
        address _earningToken
    ) public {
        devaddr = _devaddr;
        feeAddr = _feeAddr;
        startTimestamp = _startTimestamp;
        endTimestamp = _endTimestamp;
        earningToken = _earningToken;
    }

    modifier poolExists(uint256 pid) {
        require(pid < poolInfo.length, "pool inexistent");
        _;
    }

    function add(
        uint256 _allocPoint,
        IBEP20 _want,
        bool _withUpdate,
        address _strat,
        uint16 _depositFeeBP,
        bool _isWithdrawFee
    ) public onlyOwner {
        require(_depositFeeBP <= MAX_DEPOSIT_FEE_BP, "add: invalid deposit fee basis points");
        if (_withUpdate) {
            massUpdatePools();
        }
        uint256 lastRewardTimestamp =
            block.timestamp > startTimestamp ? block.timestamp : startTimestamp;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        poolInfo.push(
            PoolInfo({
                want: _want,
                allocPoint: _allocPoint,
                lastRewardTimestamp: lastRewardTimestamp,
                accEarningsPerShare: 0,
                strat: _strat,
                depositFeeBP : _depositFeeBP,
                isWithdrawFee: _isWithdrawFee
            })
        );
    }

    function set(
        uint256 _pid,
        uint256 _allocPoint,
        bool _withUpdate,
        uint16 _depositFeeBP,
        bool _isWithdrawFee
    ) public onlyOwner poolExists(_pid) {
        require(_depositFeeBP <= MAX_DEPOSIT_FEE_BP, "set: invalid deposit fee basis points");
        if (_withUpdate) {
            massUpdatePools();
        }
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(
            _allocPoint
        );
        poolInfo[_pid].allocPoint = _allocPoint;
        poolInfo[_pid].depositFeeBP = _depositFeeBP;
        poolInfo[_pid].isWithdrawFee = _isWithdrawFee;
    }

    function getMultiplier(uint256 _from, uint256 _to)
        public
        view
        returns (uint256)
    {
        if (_from > _to)
            return 0;
        return _to.sub(_from);
    }

    function pendingEarnings(uint256 _pid, address _user)
        external
        view
        returns (uint256)
    {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accEarningsPerShare = pool.accEarningsPerShare;
        uint256 wantLockedTotal = IStrategy(pool.strat).wantLockedTotal();
        uint256 lastTimestamp = endTimestamp < block.timestamp ? endTimestamp : block.timestamp;
        if (lastTimestamp > pool.lastRewardTimestamp && wantLockedTotal != 0) {
            uint256 multiplier =
                getMultiplier(pool.lastRewardTimestamp, lastTimestamp);
            uint256 earningsReward =
                multiplier.mul(earningsPerSecond).mul(pool.allocPoint).div(
                    totalAllocPoint
                );
            accEarningsPerShare = accEarningsPerShare.add(
                earningsReward.mul(1e12).div(wantLockedTotal)
            );
        }
        return user.amount.mul(accEarningsPerShare).div(1e12).sub(user.rewardDebt);
    }

    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }

    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.timestamp <= pool.lastRewardTimestamp) {
            return;
        }
        uint256 lastTimestamp = endTimestamp < block.timestamp ? endTimestamp : block.timestamp;
        uint256 wantLockedTotal = IStrategy(pool.strat).wantLockedTotal();
        if (wantLockedTotal == 0) {
            pool.lastRewardTimestamp = lastTimestamp;
            return;
        }

        uint256 multiplier = getMultiplier(pool.lastRewardTimestamp, lastTimestamp);
        if (multiplier <= 0) {
            return;
        }
        uint256 earningsReward =  multiplier.mul(earningsPerSecond).mul(pool.allocPoint).div(totalAllocPoint);

        HoneyToken(earningToken).mint(
            devaddr,
            multiplier.mul(earningsDevPerSecond).mul(pool.allocPoint).div(
                totalAllocPoint
            )
        );

        HoneyToken(earningToken).mint(
            address(this),
            earningsReward
        );

        pool.accEarningsPerShare = pool.accEarningsPerShare.add(
            earningsReward.mul(1e12).div(wantLockedTotal)
        );
        pool.lastRewardTimestamp = lastTimestamp;
    }

    function deposit(uint256 _pid,uint256 _wantAmt, address _referrer) public nonReentrant poolExists(_pid){
        updatePool(_pid);
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        if (_wantAmt > 0 && address(earningReferral) != address(0) && _referrer != address(0) && _referrer != msg.sender) {
            earningReferral.recordReferral(msg.sender, _referrer);
        }
        if (user.amount > 0) {
            uint256 pending =
                user.amount.mul(pool.accEarningsPerShare).div(1e12).sub(
                    user.rewardDebt
                );
            if (pending > 0) {
                safeEarningsTransfer(msg.sender, pending);
                payReferralCommission(msg.sender, pending);
            }
        }
        if (_wantAmt > 0) {
            uint256 wantBalBefore = IBEP20(pool.want).balanceOf(address(this));
            pool.want.safeTransferFrom(address(msg.sender), address(this), _wantAmt);
            uint256 wantBalAfter = IBEP20(pool.want).balanceOf(address(this));
            _wantAmt = wantBalAfter.sub(wantBalBefore);

            uint256 amount = _wantAmt;
            if (pool.depositFeeBP > 0) {
                uint256 depositFee = _wantAmt.mul(pool.depositFeeBP).div(10000);
                pool.want.safeTransfer(feeAddr, depositFee);
                amount = (_wantAmt).sub(depositFee);
            }
            pool.want.safeIncreaseAllowance(pool.strat, amount);
            uint256 amountDeposit =
                IStrategy(poolInfo[_pid].strat).deposit(amount);
            user.amount = user.amount.add(amountDeposit);
            user.lastDepositTimestamp = block.timestamp;
        }
        user.rewardDebt = user.amount.mul(pool.accEarningsPerShare).div(1e12);
        emit Deposit(msg.sender, _pid, _wantAmt);
    }

    function withdraw(uint256 _pid, uint256 _wantAmt) public nonReentrant poolExists(_pid){
        updatePool(_pid);

        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        uint256 total = IStrategy(pool.strat).wantLockedTotal();

        require(user.amount > 0, "user.amount is 0");
        require(total > 0, "Total is 0");


        uint256 pending =
            user.amount.mul(pool.accEarningsPerShare).div(1e12).sub(
                user.rewardDebt
            );

        if (pending > 0) {
            safeEarningsTransfer(msg.sender, pending);
            payReferralCommission(msg.sender, pending);
        }


        uint256 amount = user.amount;
        if (_wantAmt > amount) {
            _wantAmt = amount;
        }
        if (_wantAmt > 0) {
            uint256 amountRemove =
                IStrategy(pool.strat).withdraw(_wantAmt);

            if (amountRemove > user.amount) {
                user.amount = 0;
            } else {
                user.amount = user.amount.sub(amountRemove);
            }

            uint256 wantBal = IBEP20(pool.want).balanceOf(address(this));
            if (wantBal < _wantAmt) {
                _wantAmt = wantBal;
            }

            if (pool.isWithdrawFee) {
                uint16 withdrawFeeBP = getWithdrawFee(_pid, msg.sender);
                if (withdrawFeeBP > 0) {
                    uint256 withdrawFee = _wantAmt.mul(withdrawFeeBP).div(10000);
                    pool.want.safeTransfer(feeAddr, withdrawFee);
                    _wantAmt = (_wantAmt).sub(withdrawFee);
                }
            }

            pool.want.safeTransfer(address(msg.sender), _wantAmt);
        }
        user.rewardDebt = user.amount.mul(pool.accEarningsPerShare).div(1e12);
        emit Withdraw(msg.sender, _pid, _wantAmt);
    }

    function emergencyWithdraw(uint256 _pid) public nonReentrant poolExists(_pid){
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];

        uint256 amount = user.amount;
        amount = IStrategy(pool.strat).withdraw(amount);

        if (pool.isWithdrawFee) {
            uint16 withdrawFeeBP = getWithdrawFee(_pid, msg.sender);
            if (withdrawFeeBP > 0) {
                uint256 withdrawFee = amount.mul(withdrawFeeBP).div(10000);
                pool.want.safeTransfer(feeAddr, withdrawFee);
                amount = (amount).sub(withdrawFee);
            }
        }

        user.amount = 0;
        user.rewardDebt = 0;
        pool.want.safeTransfer(address(msg.sender), amount);
        emit EmergencyWithdraw(msg.sender, _pid, amount);
    }

    function safeEarningsTransfer(address _to, uint256 _EarningsAmt) internal {
        uint256 EarningsBal = IBEP20(earningToken).balanceOf(address(this));
        if (_EarningsAmt > EarningsBal) {
            IBEP20(earningToken).transfer(_to, EarningsBal);
        } else {
            IBEP20(earningToken).transfer(_to, _EarningsAmt);
        }
    }

    function inCaseTokensGetStuck(address _token, uint256 _amount)
        public
        onlyOwner
    {
        require(_token != earningToken, "!safe");
        IBEP20(_token).safeTransfer(msg.sender, _amount);
    }

    function setDevAddress(address _devaddr) public onlyOwner {
        devaddr = _devaddr;
        emit SetDevAddress(msg.sender, _devaddr);
    }

    function setFeeAddress(address _feeAddress) public onlyOwner {
        feeAddr = _feeAddress;
        emit SetFeeAddress(msg.sender, _feeAddress);
    }

    function setEarningsReferral(IEarningsReferral _earningReferral) public onlyOwner {
        earningReferral = _earningReferral;
    }

    function setReferralCommissionRate(uint16 _referralCommissionRate) public onlyOwner {
        require(_referralCommissionRate <= MAXIMUM_REFERRAL_COMMISSION_RATE, "setReferralCommissionRate: invalid referral commission rate basis points");
        referralCommissionRate = _referralCommissionRate;
    }

    function payReferralCommission(address _user, uint256 _pending) internal {
        if (address(earningReferral) != address(0) && referralCommissionRate > 0) {
            address referrer = earningReferral.getReferrer(_user);
            uint256 commissionAmount = _pending.mul(referralCommissionRate).div(10000);

            if (referrer != address(0) && commissionAmount > 0) {
                HoneyToken(earningToken).mint(referrer, commissionAmount);
                earningReferral.recordReferralCommission(referrer, commissionAmount);
                emit ReferralCommissionPaid(_user, referrer, commissionAmount);
            }
        }
    }

    function transferEarningTokenOwnership(address newOwner) public onlyOwner {
        require(newOwner != address(0), "Ownable: new owner is the zero address");
        Ownable(earningToken).transferOwnership(newOwner);
    }

    function getWithdrawFee(uint256 _pid, address _user) public view returns (uint16) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        if (!pool.isWithdrawFee)
            return 0;
        uint256 TimeElapsed = block.timestamp - user.lastDepositTimestamp;
        uint i = 0;
        for (; i < withdrawalFeeIntervals.length; i++) {
            if (TimeElapsed < withdrawalFeeIntervals[i])
                break;
        }
        return withdrawalFeeBP[i];
    }

    function setWithdrawFee(uint256[] memory _withdrawalFeeIntervals, uint16[] memory _withdrawalFeeBP) public onlyOwner {
        require (_withdrawalFeeIntervals.length + 1 == _withdrawalFeeBP.length, 'setWithdrawFee: _withdrawalFeeBP length is one more than _withdrawalFeeIntervals length');
        require (_withdrawalFeeBP.length > 0, 'setWithdrawFee: _withdrawalFeeBP length is one more than 0');
        for (uint i = 0; i < _withdrawalFeeIntervals.length - 1; i++) {
            require (_withdrawalFeeIntervals[i] < _withdrawalFeeIntervals[i + 1], 'setWithdrawFee: The interval must be ascending');
        }
        for (uint i = 0; i < _withdrawalFeeBP.length; i++) {
            require (_withdrawalFeeBP[i] <= MAX_WITHDRAWAL_FEE_BP, 'setWithdrawFee: invalid withdrawal fee basis points');
        }
        withdrawalFeeIntervals = _withdrawalFeeIntervals;
        withdrawalFeeBP = _withdrawalFeeBP;
    }

    function setEarningsPerSecond(uint256 _earningsPerSecond) external onlyOwner {
      earningsPerSecond = _earningsPerSecond;
      earningsDevPerSecond = _earningsPerSecond.div(10);

      emit NewEarningsEmission(_earningsPerSecond);
    }

    function setStartTimestamp(uint256 _startTimestamp) external onlyOwner {
        require(block.timestamp < startTimestamp, 'setStartTimestamp: The farming has already started');
        require(block.timestamp < _startTimestamp, 'setStartTimestamp: _startTimestamp must be larger than now');
        require(_startTimestamp < endTimestamp, 'setStartTimestamp: _startTimestamp must be smaller than endTimestamp');
        startTimestamp = _startTimestamp;
    }

    function setEndTimestamp(uint256 _endTimestamp) external onlyOwner {
        require(startTimestamp < _endTimestamp, 'setEndTimestamp: _endTimestamp must be larger than startTimestamp');
        require(block.timestamp < _endTimestamp, 'setEndTimestamp: _endTimestamp must be larger than now');
        endTimestamp = _endTimestamp;
    }
}

pragma solidity ^0.5.16;

import "../interfaces/IronControllerInterface.sol";
import "../interfaces/RTokenInterfaces.sol";
import "../interest/InterestRateModel.sol";
import "../interfaces/EIP20Interface.sol";
import "../common/ErrorReporter.sol";
import "../common/Exponential.sol";



contract RToken is RTokenInterface, Exponential, TokenErrorReporter {

    function initialize(IronControllerInterface ironController_,
                        InterestRateModel interestRateModel_,
                        uint initialExchangeRateMantissa_,
                        string memory name_,
                        string memory symbol_,
                        uint8 decimals_) public {
        require(msg.sender == admin, "only admin may initialize the market");
        require(accrualBlockNumber == 0 && borrowIndex == 0, "market may only be initialized once");


        initialExchangeRateMantissa = initialExchangeRateMantissa_;
        require(initialExchangeRateMantissa > 0, "initial exchange rate must be greater than zero.");


        uint err = _setIronController(ironController_);
        require(err == uint(Error.NO_ERROR), "setting ironController failed");


        accrualBlockNumber = getBlockNumber();
        borrowIndex = mantissaOne;


        err = _setInterestRateModelFresh(interestRateModel_);
        require(err == uint(Error.NO_ERROR), "setting interest rate model failed");

        name = name_;
        symbol = symbol_;
        decimals = decimals_;


        _notEntered = true;
    }


    function transfeRTokens(address spender, address src, address dst, uint tokens) internal returns (uint) {

        uint allowed = ironController.transferAllowed(address(this), src, dst, tokens);
        if (allowed != 0) {
            return failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.TRANSFER_IRON_CONTROLLER_REJECTION, allowed);
        }


        if (src == dst) {
            return fail(Error.BAD_INPUT, FailureInfo.TRANSFER_NOT_ALLOWED);
        }


        uint startingAllowance = 0;
        if (spender == src) {
            startingAllowance = uint(-1);
        } else {
            startingAllowance = transferAllowances[src][spender];
        }


        MathError mathErr;
        uint allowanceNew;
        uint srRTokensNew;
        uint dstTokensNew;

        (mathErr, allowanceNew) = subUInt(startingAllowance, tokens);
        if (mathErr != MathError.NO_ERROR) {
            return fail(Error.MATH_ERROR, FailureInfo.TRANSFER_NOT_ALLOWED);
        }

        (mathErr, srRTokensNew) = subUInt(accountTokens[src], tokens);
        if (mathErr != MathError.NO_ERROR) {
            return fail(Error.MATH_ERROR, FailureInfo.TRANSFER_NOT_ENOUGH);
        }

        (mathErr, dstTokensNew) = addUInt(accountTokens[dst], tokens);
        if (mathErr != MathError.NO_ERROR) {
            return fail(Error.MATH_ERROR, FailureInfo.TRANSFER_TOO_MUCH);
        }





        accountTokens[src] = srRTokensNew;
        accountTokens[dst] = dstTokensNew;


        if (startingAllowance != uint(-1)) {
            transferAllowances[src][spender] = allowanceNew;
        }


        emit Transfer(src, dst, tokens);




        return uint(Error.NO_ERROR);
    }


    function transfer(address dst, uint256 amount) external nonReentrant returns (bool) {
        return transfeRTokens(msg.sender, msg.sender, dst, amount) == uint(Error.NO_ERROR);
    }


    function transferFrom(address src, address dst, uint256 amount) external nonReentrant returns (bool) {
        return transfeRTokens(msg.sender, src, dst, amount) == uint(Error.NO_ERROR);
    }


    function approve(address spender, uint256 amount) external returns (bool) {
        address src = msg.sender;
        transferAllowances[src][spender] = amount;
        emit Approval(src, spender, amount);
        return true;
    }


    function allowance(address owner, address spender) external view returns (uint256) {
        return transferAllowances[owner][spender];
    }


    function balanceOf(address owner) external view returns (uint256) {
        return accountTokens[owner];
    }


    function balanceOfUnderlying(address owner) external returns (uint) {
        Exp memory exchangeRate = Exp({mantissa: exchangeRateCurrent()});
        (MathError mErr, uint balance) = mulScalarTruncate(exchangeRate, accountTokens[owner]);
        require(mErr == MathError.NO_ERROR, "balance could not be calculated");
        return balance;
    }


    function getAccountSnapshot(address account) external view returns (uint, uint, uint, uint) {
        uint RTokenBalance = accountTokens[account];
        uint borrowBalance;
        uint exchangeRateMantissa;

        MathError mErr;

        (mErr, borrowBalance) = borrowBalanceStoredInternal(account);
        if (mErr != MathError.NO_ERROR) {
            return (uint(Error.MATH_ERROR), 0, 0, 0);
        }

        (mErr, exchangeRateMantissa) = exchangeRateStoredInternal();
        if (mErr != MathError.NO_ERROR) {
            return (uint(Error.MATH_ERROR), 0, 0, 0);
        }

        return (uint(Error.NO_ERROR), RTokenBalance, borrowBalance, exchangeRateMantissa);
    }


    function getBlockNumber() internal view returns (uint) {
        return block.number;
    }


    function borrowRatePerBlock() external view returns (uint) {
        return interestRateModel.getBorrowRate(getCashPrior(), totalBorrows, totalReserves);
    }


    function supplyRatePerBlock() external view returns (uint) {
        return interestRateModel.getSupplyRate(getCashPrior(), totalBorrows, totalReserves, reserveFactorMantissa);
    }


    function totalBorrowsCurrent() external nonReentrant returns (uint) {
        require(accrueInterest() == uint(Error.NO_ERROR), "accrue interest failed");
        return totalBorrows;
    }


    function borrowBalanceCurrent(address account) external nonReentrant returns (uint) {
        require(accrueInterest() == uint(Error.NO_ERROR), "accrue interest failed");
        return borrowBalanceStored(account);
    }


    function borrowBalanceStored(address account) public view returns (uint) {
        (MathError err, uint result) = borrowBalanceStoredInternal(account);
        require(err == MathError.NO_ERROR, "borrowBalanceStored: borrowBalanceStoredInternal failed");
        return result;
    }


    function borrowBalanceStoredInternal(address account) internal view returns (MathError, uint) {

        MathError mathErr;
        uint principalTimesIndex;
        uint result;


        BorrowSnapshot storage borrowSnapshot = accountBorrows[account];


        if (borrowSnapshot.principal == 0) {
            return (MathError.NO_ERROR, 0);
        }


        (mathErr, principalTimesIndex) = mulUInt(borrowSnapshot.principal, borrowIndex);
        if (mathErr != MathError.NO_ERROR) {
            return (mathErr, 0);
        }

        (mathErr, result) = divUInt(principalTimesIndex, borrowSnapshot.interestIndex);
        if (mathErr != MathError.NO_ERROR) {
            return (mathErr, 0);
        }

        return (MathError.NO_ERROR, result);
    }


    function exchangeRateCurrent() public nonReentrant returns (uint) {
        require(accrueInterest() == uint(Error.NO_ERROR), "accrue interest failed");
        return exchangeRateStored();
    }


    function exchangeRateStored() public view returns (uint) {
        (MathError err, uint result) = exchangeRateStoredInternal();
        require(err == MathError.NO_ERROR, "exchangeRateStored: exchangeRateStoredInternal failed");
        return result;
    }


    function exchangeRateStoredInternal() internal view returns (MathError, uint) {
        uint _totalSupply = totalSupply;
        if (_totalSupply == 0) {

            return (MathError.NO_ERROR, initialExchangeRateMantissa);
        } else {

            uint totalCash = getCashPrior();
            uint cashPlusBorrowsMinusReserves;
            Exp memory exchangeRate;
            MathError mathErr;

            (mathErr, cashPlusBorrowsMinusReserves) = addThenSubUInt(totalCash, totalBorrows, totalReserves);
            if (mathErr != MathError.NO_ERROR) {
                return (mathErr, 0);
            }

            (mathErr, exchangeRate) = getExp(cashPlusBorrowsMinusReserves, _totalSupply);
            if (mathErr != MathError.NO_ERROR) {
                return (mathErr, 0);
            }

            return (MathError.NO_ERROR, exchangeRate.mantissa);
        }
    }


    function getCash() external view returns (uint) {
        return getCashPrior();
    }


    function accrueInterest() public returns (uint) {

        uint currentBlockNumber = getBlockNumber();
        uint accrualBlockNumberPrior = accrualBlockNumber;


        if (accrualBlockNumberPrior == currentBlockNumber) {
            return uint(Error.NO_ERROR);
        }


        uint cashPrior = getCashPrior();
        uint borrowsPrior = totalBorrows;
        uint reservesPrior = totalReserves;
        uint borrowIndexPrior = borrowIndex;


        uint borrowRateMantissa = interestRateModel.getBorrowRate(cashPrior, borrowsPrior, reservesPrior);
        require(borrowRateMantissa <= borrowRateMaxMantissa, "borrow rate is absurdly high");


        (MathError mathErr, uint blockDelta) = subUInt(currentBlockNumber, accrualBlockNumberPrior);
        require(mathErr == MathError.NO_ERROR, "could not calculate block delta");



        Exp memory simpleInterestFactor;
        uint interestAccumulated;
        uint totalBorrowsNew;
        uint totalReservesNew;
        uint borrowIndexNew;

        (mathErr, simpleInterestFactor) = mulScalar(Exp({mantissa: borrowRateMantissa}), blockDelta);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.ACCRUE_INTEREST_SIMPLE_INTEREST_FACTOR_CALCULATION_FAILED, uint(mathErr));
        }

        (mathErr, interestAccumulated) = mulScalarTruncate(simpleInterestFactor, borrowsPrior);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.ACCRUE_INTEREST_ACCUMULATED_INTEREST_CALCULATION_FAILED, uint(mathErr));
        }

        (mathErr, totalBorrowsNew) = addUInt(interestAccumulated, borrowsPrior);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.ACCRUE_INTEREST_NEW_TOTAL_BORROWS_CALCULATION_FAILED, uint(mathErr));
        }

        (mathErr, totalReservesNew) = mulScalarTruncateAddUInt(Exp({mantissa: reserveFactorMantissa}), interestAccumulated, reservesPrior);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.ACCRUE_INTEREST_NEW_TOTAL_RESERVES_CALCULATION_FAILED, uint(mathErr));
        }

        (mathErr, borrowIndexNew) = mulScalarTruncateAddUInt(simpleInterestFactor, borrowIndexPrior, borrowIndexPrior);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.ACCRUE_INTEREST_NEW_BORROW_INDEX_CALCULATION_FAILED, uint(mathErr));
        }






        accrualBlockNumber = currentBlockNumber;
        borrowIndex = borrowIndexNew;
        totalBorrows = totalBorrowsNew;
        totalReserves = totalReservesNew;


        emit AccrueInterest(cashPrior, interestAccumulated, borrowIndexNew, totalBorrowsNew);

        return uint(Error.NO_ERROR);
    }


    function mintInternal(uint mintAmount) internal nonReentrant returns (uint, uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return (fail(Error(error), FailureInfo.MINT_ACCRUE_INTEREST_FAILED), 0);
        }

        return mintFresh(msg.sender, mintAmount);
    }

    struct MintLocalVars {
        Error err;
        MathError mathErr;
        uint exchangeRateMantissa;
        uint mintTokens;
        uint totalSupplyNew;
        uint accountTokensNew;
        uint actualMintAmount;
    }


    function mintFresh(address minter, uint mintAmount) internal returns (uint, uint) {

        uint allowed = ironController.mintAllowed(address(this), minter, mintAmount);
        if (allowed != 0) {
            return (failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.MINT_IRON_CONTROLLER_REJECTION, allowed), 0);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return (fail(Error.MARKET_NOT_FRESH, FailureInfo.MINT_FRESHNESS_CHECK), 0);
        }

        MintLocalVars memory vars;

        (vars.mathErr, vars.exchangeRateMantissa) = exchangeRateStoredInternal();
        if (vars.mathErr != MathError.NO_ERROR) {
            return (failOpaque(Error.MATH_ERROR, FailureInfo.MINT_EXCHANGE_RATE_READ_FAILED, uint(vars.mathErr)), 0);
        }






        vars.actualMintAmount = doTransferIn(minter, mintAmount);



        (vars.mathErr, vars.mintTokens) = divScalarByExpTruncate(vars.actualMintAmount, Exp({mantissa: vars.exchangeRateMantissa}));
        require(vars.mathErr == MathError.NO_ERROR, "MINT_EXCHANGE_CALCULATION_FAILED");


        (vars.mathErr, vars.totalSupplyNew) = addUInt(totalSupply, vars.mintTokens);
        require(vars.mathErr == MathError.NO_ERROR, "MINT_NEW_TOTAL_SUPPLY_CALCULATION_FAILED");

        (vars.mathErr, vars.accountTokensNew) = addUInt(accountTokens[minter], vars.mintTokens);
        require(vars.mathErr == MathError.NO_ERROR, "MINT_NEW_ACCOUNT_BALANCE_CALCULATION_FAILED");


        totalSupply = vars.totalSupplyNew;
        accountTokens[minter] = vars.accountTokensNew;


        emit Mint(minter, vars.actualMintAmount, vars.mintTokens);
        emit Transfer(address(this), minter, vars.mintTokens);





        return (uint(Error.NO_ERROR), vars.actualMintAmount);
    }


    function redeemInternal(uint redeemTokens) internal nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.REDEEM_ACCRUE_INTEREST_FAILED);
        }

        return redeemFresh(msg.sender, redeemTokens, 0);
    }


    function redeemUnderlyingInternal(uint redeemAmount) internal nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.REDEEM_ACCRUE_INTEREST_FAILED);
        }

        return redeemFresh(msg.sender, 0, redeemAmount);
    }

    struct RedeemLocalVars {
        Error err;
        MathError mathErr;
        uint exchangeRateMantissa;
        uint redeemTokens;
        uint redeemAmount;
        uint totalSupplyNew;
        uint accountTokensNew;
    }


    function redeemFresh(address payable redeemer, uint redeemTokensIn, uint redeemAmountIn) internal returns (uint) {
        require(redeemTokensIn == 0 || redeemAmountIn == 0, "one of redeemTokensIn or redeemAmountIn must be zero");

        RedeemLocalVars memory vars;


        (vars.mathErr, vars.exchangeRateMantissa) = exchangeRateStoredInternal();
        if (vars.mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.REDEEM_EXCHANGE_RATE_READ_FAILED, uint(vars.mathErr));
        }


        if (redeemTokensIn > 0) {

            vars.redeemTokens = redeemTokensIn;

            (vars.mathErr, vars.redeemAmount) = mulScalarTruncate(Exp({mantissa: vars.exchangeRateMantissa}), redeemTokensIn);
            if (vars.mathErr != MathError.NO_ERROR) {
                return failOpaque(Error.MATH_ERROR, FailureInfo.REDEEM_EXCHANGE_TOKENS_CALCULATION_FAILED, uint(vars.mathErr));
            }
        } else {


            (vars.mathErr, vars.redeemTokens) = divScalarByExpTruncate(redeemAmountIn, Exp({mantissa: vars.exchangeRateMantissa}));
            if (vars.mathErr != MathError.NO_ERROR) {
                return failOpaque(Error.MATH_ERROR, FailureInfo.REDEEM_EXCHANGE_AMOUNT_CALCULATION_FAILED, uint(vars.mathErr));
            }

            vars.redeemAmount = redeemAmountIn;
        }


        uint allowed = ironController.redeemAllowed(address(this), redeemer, vars.redeemTokens);
        if (allowed != 0) {
            return failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.REDEEM_IRON_CONTROLLER_REJECTION, allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return fail(Error.MARKET_NOT_FRESH, FailureInfo.REDEEM_FRESHNESS_CHECK);
        }


        (vars.mathErr, vars.totalSupplyNew) = subUInt(totalSupply, vars.redeemTokens);
        if (vars.mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.REDEEM_NEW_TOTAL_SUPPLY_CALCULATION_FAILED, uint(vars.mathErr));
        }

        (vars.mathErr, vars.accountTokensNew) = subUInt(accountTokens[redeemer], vars.redeemTokens);
        if (vars.mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.REDEEM_NEW_ACCOUNT_BALANCE_CALCULATION_FAILED, uint(vars.mathErr));
        }


        if (getCashPrior() < vars.redeemAmount) {
            return fail(Error.TOKEN_INSUFFICIENT_CASH, FailureInfo.REDEEM_TRANSFER_OUT_NOT_POSSIBLE);
        }






        doTransferOut(redeemer, vars.redeemAmount);


        totalSupply = vars.totalSupplyNew;
        accountTokens[redeemer] = vars.accountTokensNew;


        emit Transfer(redeemer, address(this), vars.redeemTokens);
        emit Redeem(redeemer, vars.redeemAmount, vars.redeemTokens);


        ironController.redeemVerify(address(this), redeemer, vars.redeemAmount, vars.redeemTokens);

        return uint(Error.NO_ERROR);
    }


    function borrowInternal(uint borrowAmount) internal nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.BORROW_ACCRUE_INTEREST_FAILED);
        }

        return borrowFresh(msg.sender, borrowAmount);
    }

    struct BorrowLocalVars {
        MathError mathErr;
        uint accountBorrows;
        uint accountBorrowsNew;
        uint totalBorrowsNew;
    }


    function borrowFresh(address payable borrower, uint borrowAmount) internal returns (uint) {

        uint allowed = ironController.borrowAllowed(address(this), borrower, borrowAmount);
        if (allowed != 0) {
            return failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.BORROW_IRON_CONTROLLER_REJECTION, allowed);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return fail(Error.MARKET_NOT_FRESH, FailureInfo.BORROW_FRESHNESS_CHECK);
        }


        if (getCashPrior() < borrowAmount) {
            return fail(Error.TOKEN_INSUFFICIENT_CASH, FailureInfo.BORROW_CASH_NOT_AVAILABLE);
        }

        BorrowLocalVars memory vars;


        (vars.mathErr, vars.accountBorrows) = borrowBalanceStoredInternal(borrower);
        if (vars.mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.BORROW_ACCUMULATED_BALANCE_CALCULATION_FAILED, uint(vars.mathErr));
        }

        (vars.mathErr, vars.accountBorrowsNew) = addUInt(vars.accountBorrows, borrowAmount);
        if (vars.mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.BORROW_NEW_ACCOUNT_BORROW_BALANCE_CALCULATION_FAILED, uint(vars.mathErr));
        }

        (vars.mathErr, vars.totalBorrowsNew) = addUInt(totalBorrows, borrowAmount);
        if (vars.mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.BORROW_NEW_TOTAL_BALANCE_CALCULATION_FAILED, uint(vars.mathErr));
        }






        doTransferOut(borrower, borrowAmount);


        accountBorrows[borrower].principal = vars.accountBorrowsNew;
        accountBorrows[borrower].interestIndex = borrowIndex;
        totalBorrows = vars.totalBorrowsNew;


        emit Borrow(borrower, borrowAmount, vars.accountBorrowsNew, vars.totalBorrowsNew);





        return uint(Error.NO_ERROR);
    }


    function repayBorrowInternal(uint repayAmount) internal nonReentrant returns (uint, uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return (fail(Error(error), FailureInfo.REPAY_BORROW_ACCRUE_INTEREST_FAILED), 0);
        }

        return repayBorrowFresh(msg.sender, msg.sender, repayAmount);
    }


    function repayBorrowBehalfInternal(address borrower, uint repayAmount) internal nonReentrant returns (uint, uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return (fail(Error(error), FailureInfo.REPAY_BEHALF_ACCRUE_INTEREST_FAILED), 0);
        }

        return repayBorrowFresh(msg.sender, borrower, repayAmount);
    }

    struct RepayBorrowLocalVars {
        Error err;
        MathError mathErr;
        uint repayAmount;
        uint borrowerIndex;
        uint accountBorrows;
        uint accountBorrowsNew;
        uint totalBorrowsNew;
        uint actualRepayAmount;
    }


    function repayBorrowFresh(address payer, address borrower, uint repayAmount) internal returns (uint, uint) {

        uint allowed = ironController.repayBorrowAllowed(address(this), payer, borrower, repayAmount);
        if (allowed != 0) {
            return (failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.REPAY_BORROW_IRON_CONTROLLER_REJECTION, allowed), 0);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return (fail(Error.MARKET_NOT_FRESH, FailureInfo.REPAY_BORROW_FRESHNESS_CHECK), 0);
        }

        RepayBorrowLocalVars memory vars;


        vars.borrowerIndex = accountBorrows[borrower].interestIndex;


        (vars.mathErr, vars.accountBorrows) = borrowBalanceStoredInternal(borrower);
        if (vars.mathErr != MathError.NO_ERROR) {
            return (failOpaque(Error.MATH_ERROR, FailureInfo.REPAY_BORROW_ACCUMULATED_BALANCE_CALCULATION_FAILED, uint(vars.mathErr)), 0);
        }


        if (repayAmount == uint(-1)) {
            vars.repayAmount = vars.accountBorrows;
        } else {
            vars.repayAmount = repayAmount;
        }






        vars.actualRepayAmount = doTransferIn(payer, vars.repayAmount);


        (vars.mathErr, vars.accountBorrowsNew) = subUInt(vars.accountBorrows, vars.actualRepayAmount);
        require(vars.mathErr == MathError.NO_ERROR, "REPAY_BORROW_NEW_ACCOUNT_BORROW_BALANCE_CALCULATION_FAILED");

        (vars.mathErr, vars.totalBorrowsNew) = subUInt(totalBorrows, vars.actualRepayAmount);
        require(vars.mathErr == MathError.NO_ERROR, "REPAY_BORROW_NEW_TOTAL_BALANCE_CALCULATION_FAILED");


        accountBorrows[borrower].principal = vars.accountBorrowsNew;
        accountBorrows[borrower].interestIndex = borrowIndex;
        totalBorrows = vars.totalBorrowsNew;


        emit RepayBorrow(payer, borrower, vars.actualRepayAmount, vars.accountBorrowsNew, vars.totalBorrowsNew);





        return (uint(Error.NO_ERROR), vars.actualRepayAmount);
    }


    function liquidateBorrowInternal(address borrower, uint repayAmount, RTokenInterface RTokenCollateral) internal nonReentrant returns (uint, uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return (fail(Error(error), FailureInfo.LIQUIDATE_ACCRUE_BORROW_INTEREST_FAILED), 0);
        }

        error = RTokenCollateral.accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return (fail(Error(error), FailureInfo.LIQUIDATE_ACCRUE_COLLATERAL_INTEREST_FAILED), 0);
        }


        return liquidateBorrowFresh(msg.sender, borrower, repayAmount, RTokenCollateral);
    }


    function liquidateBorrowFresh(address liquidator, address borrower, uint repayAmount, RTokenInterface RTokenCollateral) internal returns (uint, uint) {

        uint allowed = ironController.liquidateBorrowAllowed(address(this), address(RTokenCollateral), liquidator, borrower, repayAmount);
        if (allowed != 0) {
            return (failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.LIQUIDATE_IRON_CONTROLLER_REJECTION, allowed), 0);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return (fail(Error.MARKET_NOT_FRESH, FailureInfo.LIQUIDATE_FRESHNESS_CHECK), 0);
        }


        if (RTokenCollateral.accrualBlockNumber() != getBlockNumber()) {
            return (fail(Error.MARKET_NOT_FRESH, FailureInfo.LIQUIDATE_COLLATERAL_FRESHNESS_CHECK), 0);
        }


        if (borrower == liquidator) {
            return (fail(Error.INVALID_ACCOUNT_PAIR, FailureInfo.LIQUIDATE_LIQUIDATOR_IS_BORROWER), 0);
        }


        if (repayAmount == 0) {
            return (fail(Error.INVALID_CLOSE_AMOUNT_REQUESTED, FailureInfo.LIQUIDATE_CLOSE_AMOUNT_IS_ZERO), 0);
        }


        if (repayAmount == uint(-1)) {
            return (fail(Error.INVALID_CLOSE_AMOUNT_REQUESTED, FailureInfo.LIQUIDATE_CLOSE_AMOUNT_IS_UINT_MAX), 0);
        }



        (uint repayBorrowError, uint actualRepayAmount) = repayBorrowFresh(liquidator, borrower, repayAmount);
        if (repayBorrowError != uint(Error.NO_ERROR)) {
            return (fail(Error(repayBorrowError), FailureInfo.LIQUIDATE_REPAY_BORROW_FRESH_FAILED), 0);
        }






        (uint amountSeizeError, uint seizeTokens) = ironController.liquidateCalculateSeizeTokens(address(this), address(RTokenCollateral), actualRepayAmount);
        require(amountSeizeError == uint(Error.NO_ERROR), "LIQUIDATE_IRON_CONTROLLER_CALCULATE_AMOUNT_SEIZE_FAILED");


        require(RTokenCollateral.balanceOf(borrower) >= seizeTokens, "LIQUIDATE_SEIZE_TOO_MUCH");


        uint seizeError;
        if (address(RTokenCollateral) == address(this)) {
            seizeError = seizeInternal(address(this), liquidator, borrower, seizeTokens);
        } else {
            seizeError = RTokenCollateral.seize(liquidator, borrower, seizeTokens);
        }


        require(seizeError == uint(Error.NO_ERROR), "token seizure failed");


        emit LiquidateBorrow(liquidator, borrower, actualRepayAmount, address(RTokenCollateral), seizeTokens);





        return (uint(Error.NO_ERROR), actualRepayAmount);
    }


    function seize(address liquidator, address borrower, uint seizeTokens) external nonReentrant returns (uint) {
        return seizeInternal(msg.sender, liquidator, borrower, seizeTokens);
    }


    function seizeInternal(address seizeRToken, address liquidator, address borrower, uint seizeTokens) internal returns (uint) {

        uint allowed = ironController.seizeAllowed(address(this), seizeRToken, liquidator, borrower, seizeTokens);
        if (allowed != 0) {
            return failOpaque(Error.IRON_CONTROLLER_REJECTION, FailureInfo.LIQUIDATE_SEIZE_IRON_CONTROLLER_REJECTION, allowed);
        }


        if (borrower == liquidator) {
            return fail(Error.INVALID_ACCOUNT_PAIR, FailureInfo.LIQUIDATE_SEIZE_LIQUIDATOR_IS_BORROWER);
        }

        MathError mathErr;
        uint borroweRTokensNew;
        uint liquidatoRTokensNew;


        (mathErr, borroweRTokensNew) = subUInt(accountTokens[borrower], seizeTokens);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.LIQUIDATE_SEIZE_BALANCE_DECREMENT_FAILED, uint(mathErr));
        }

        (mathErr, liquidatoRTokensNew) = addUInt(accountTokens[liquidator], seizeTokens);
        if (mathErr != MathError.NO_ERROR) {
            return failOpaque(Error.MATH_ERROR, FailureInfo.LIQUIDATE_SEIZE_BALANCE_INCREMENT_FAILED, uint(mathErr));
        }






        accountTokens[borrower] = borroweRTokensNew;
        accountTokens[liquidator] = liquidatoRTokensNew;


        emit Transfer(borrower, liquidator, seizeTokens);





        return uint(Error.NO_ERROR);
    }





    function _setPendingAdmin(address payable newPendingAdmin) external returns (uint) {

        if (msg.sender != admin) {
            return fail(Error.UNAUTHORIZED, FailureInfo.SET_PENDING_ADMIN_OWNER_CHECK);
        }


        address oldPendingAdmin = pendingAdmin;


        pendingAdmin = newPendingAdmin;


        emit NewPendingAdmin(oldPendingAdmin, newPendingAdmin);

        return uint(Error.NO_ERROR);
    }


    function _acceptAdmin() external returns (uint) {


        if (msg.sender != pendingAdmin || msg.sender == address(0)) {
            return fail(Error.UNAUTHORIZED, FailureInfo.ACCEPT_ADMIN_PENDING_ADMIN_CHECK);
        }


        address oldAdmin = admin;
        address oldPendingAdmin = pendingAdmin;


        admin = pendingAdmin;


        pendingAdmin = address(0);

        emit NewAdmin(oldAdmin, admin);
        emit NewPendingAdmin(oldPendingAdmin, pendingAdmin);

        return uint(Error.NO_ERROR);
    }


    function _setIronController(IronControllerInterface newIronController) public returns (uint) {

        if (msg.sender != admin) {
            return fail(Error.UNAUTHORIZED, FailureInfo.SET_IRON_CONTROLLER_OWNER_CHECK);
        }

        IronControllerInterface oldIronController = ironController;

        require(newIronController.isIronController(), "marker method returned false");


        ironController = newIronController;


        emit NewIronController(oldIronController, newIronController);

        return uint(Error.NO_ERROR);
    }


    function _setReserveFactor(uint newReserveFactorMantissa) external nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.SET_RESERVE_FACTOR_ACCRUE_INTEREST_FAILED);
        }

        return _setReserveFactorFresh(newReserveFactorMantissa);
    }


    function _setReserveFactorFresh(uint newReserveFactorMantissa) internal returns (uint) {

        if (msg.sender != admin) {
            return fail(Error.UNAUTHORIZED, FailureInfo.SET_RESERVE_FACTOR_ADMIN_CHECK);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return fail(Error.MARKET_NOT_FRESH, FailureInfo.SET_RESERVE_FACTOR_FRESH_CHECK);
        }


        if (newReserveFactorMantissa > reserveFactorMaxMantissa) {
            return fail(Error.BAD_INPUT, FailureInfo.SET_RESERVE_FACTOR_BOUNDS_CHECK);
        }

        uint oldReserveFactorMantissa = reserveFactorMantissa;
        reserveFactorMantissa = newReserveFactorMantissa;

        emit NewReserveFactor(oldReserveFactorMantissa, newReserveFactorMantissa);

        return uint(Error.NO_ERROR);
    }


    function _addReservesInternal(uint addAmount) internal nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.ADD_RESERVES_ACCRUE_INTEREST_FAILED);
        }


        (error, ) = _addReservesFresh(addAmount);
        return error;
    }


    function _addReservesFresh(uint addAmount) internal returns (uint, uint) {

        uint totalReservesNew;
        uint actualAddAmount;


        if (accrualBlockNumber != getBlockNumber()) {
            return (fail(Error.MARKET_NOT_FRESH, FailureInfo.ADD_RESERVES_FRESH_CHECK), actualAddAmount);
        }







        actualAddAmount = doTransferIn(msg.sender, addAmount);

        totalReservesNew = totalReserves + actualAddAmount;


        require(totalReservesNew >= totalReserves, "add reserves unexpected overflow");


        totalReserves = totalReservesNew;


        emit ReservesAdded(msg.sender, actualAddAmount, totalReservesNew);


        return (uint(Error.NO_ERROR), actualAddAmount);
    }



    function _reduceReserves(uint reduceAmount) external nonReentrant returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.REDUCE_RESERVES_ACCRUE_INTEREST_FAILED);
        }

        return _reduceReservesFresh(reduceAmount);
    }


    function _reduceReservesFresh(uint reduceAmount) internal returns (uint) {

        uint totalReservesNew;


        if (msg.sender != admin) {
            return fail(Error.UNAUTHORIZED, FailureInfo.REDUCE_RESERVES_ADMIN_CHECK);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return fail(Error.MARKET_NOT_FRESH, FailureInfo.REDUCE_RESERVES_FRESH_CHECK);
        }


        if (getCashPrior() < reduceAmount) {
            return fail(Error.TOKEN_INSUFFICIENT_CASH, FailureInfo.REDUCE_RESERVES_CASH_NOT_AVAILABLE);
        }


        if (reduceAmount > totalReserves) {
            return fail(Error.BAD_INPUT, FailureInfo.REDUCE_RESERVES_VALIDATION);
        }





        totalReservesNew = totalReserves - reduceAmount;

        require(totalReservesNew <= totalReserves, "reduce reserves unexpected underflow");


        totalReserves = totalReservesNew;


        doTransferOut(admin, reduceAmount);

        emit ReservesReduced(admin, reduceAmount, totalReservesNew);

        return uint(Error.NO_ERROR);
    }


    function _setInterestRateModel(InterestRateModel newInterestRateModel) public returns (uint) {
        uint error = accrueInterest();
        if (error != uint(Error.NO_ERROR)) {

            return fail(Error(error), FailureInfo.SET_INTEREST_RATE_MODEL_ACCRUE_INTEREST_FAILED);
        }

        return _setInterestRateModelFresh(newInterestRateModel);
    }


    function _setInterestRateModelFresh(InterestRateModel newInterestRateModel) internal returns (uint) {


        InterestRateModel oldInterestRateModel;


        if (msg.sender != admin) {
            return fail(Error.UNAUTHORIZED, FailureInfo.SET_INTEREST_RATE_MODEL_OWNER_CHECK);
        }


        if (accrualBlockNumber != getBlockNumber()) {
            return fail(Error.MARKET_NOT_FRESH, FailureInfo.SET_INTEREST_RATE_MODEL_FRESH_CHECK);
        }


        oldInterestRateModel = interestRateModel;


        require(newInterestRateModel.isInterestRateModel(), "marker method returned false");


        interestRateModel = newInterestRateModel;


        emit NewMarketInterestRateModel(oldInterestRateModel, newInterestRateModel);

        return uint(Error.NO_ERROR);
    }




    function getCashPrior() internal view returns (uint);


    function doTransferIn(address from, uint amount) internal returns (uint);


    function doTransferOut(address payable to, uint amount) internal;





    modifier nonReentrant() {
        require(_notEntered, "re-entered");
        _notEntered = false;
        _;
        _notEntered = true; 
    }
}

pragma solidity 0.8.7;

import "./Kaoya.sol";

import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";
import "@openzeppelin/contracts/utils/structs/EnumerableSet.sol";


interface IMigratorChef {









    function migrate(IERC20 token) external returns (IERC20);
}








contract MasterChef is Ownable {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;


    struct UserInfo {
        uint256 amount;     
        uint256 rewardDebt; 











    }


    struct PoolInfo {
        IERC20 lpToken;           
        uint256 allocPoint;       
        uint256 lastRewardBlock;  
        uint256 accKaoyaPerShare; 
    }


    Kaoya public kaoya;


    uint256 public bonusEndBlock;

    uint256 public kaoyaPerBlock;

    uint256 public constant BONUS_MULTIPLIER = 10;

    IMigratorChef public migrator;


    PoolInfo[] public poolInfo;

    mapping (uint256 => mapping (address => UserInfo)) public userInfo;

    uint256 public totalAllocPoint = 0;

    uint256 public startBlock;

    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);

    constructor(
        Kaoya _kaoya,
        uint256 _kaoyaPerBlock,
        uint256 _startBlock,
        uint256 _bonusEndBlock
    ) public {
        kaoya = _kaoya;
        kaoyaPerBlock = _kaoyaPerBlock;
        bonusEndBlock = _bonusEndBlock;
        startBlock = _startBlock;
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }




    function add(uint256 _allocPoint, IERC20 _lpToken, bool _withUpdate) public onlyOwner {
        if (_withUpdate) {
            massUpdatePools();
        }
        uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        poolInfo.push(PoolInfo({
            lpToken: _lpToken,
            allocPoint: _allocPoint,
            lastRewardBlock: lastRewardBlock,
            accKaoyaPerShare: 0
        }));
    }


    function set(uint256 _pid, uint256 _allocPoint, bool _withUpdate) public onlyOwner {
        if (_withUpdate) {
            massUpdatePools();
        }
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(_allocPoint);
        poolInfo[_pid].allocPoint = _allocPoint;
    }


    function setMigrator(IMigratorChef _migrator) public onlyOwner {
        migrator = _migrator;
    }


    function migrate(uint256 _pid) public {
        require(address(migrator) != address(0), "migrate: no migrator");
        PoolInfo storage pool = poolInfo[_pid];
        IERC20 lpToken = pool.lpToken;
        uint256 bal = lpToken.balanceOf(address(this));
        lpToken.safeApprove(address(migrator), bal);
        IERC20 newLpToken = migrator.migrate(lpToken);
        require(bal == newLpToken.balanceOf(address(this)), "migrate: bad");
        pool.lpToken = newLpToken;
    }


    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {
        if (_to <= bonusEndBlock) {
            return _to.sub(_from).mul(BONUS_MULTIPLIER);
        } else if (_from >= bonusEndBlock) {
            return _to.sub(_from);
        } else {
            return bonusEndBlock.sub(_from).mul(BONUS_MULTIPLIER).add(
                _to.sub(bonusEndBlock)
            );
        }
    }


    function pendingKaoya(uint256 _pid, address _user) external view returns (uint256) {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accKaoyaPerShare = pool.accKaoyaPerShare;
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 kaoyaReward = multiplier.mul(kaoyaPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accKaoyaPerShare = accKaoyaPerShare.add(kaoyaReward.mul(1e12).div(lpSupply));
        }
        return user.amount.mul(accKaoyaPerShare).div(1e12).sub(user.rewardDebt);
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 kaoyaReward = multiplier.mul(kaoyaPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
        pool.accKaoyaPerShare = pool.accKaoyaPerShare.add(kaoyaReward.mul(1e12).div(lpSupply));
        pool.lastRewardBlock = block.number;
    }



    function deposit(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        updatePool(_pid);
        if (user.amount > 0) {
            uint256 pending = user.amount.mul(pool.accKaoyaPerShare).div(1e12).sub(user.rewardDebt);
            safeKaoyaTransfer(msg.sender, pending);
        }
        pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
        user.amount = user.amount.add(_amount);
        user.rewardDebt = user.amount.mul(pool.accKaoyaPerShare).div(1e12);
        emit Deposit(msg.sender, _pid, _amount);
    }


    function withdraw(uint256 _pid, uint256 _amount) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(_pid);
        uint256 pending = user.amount.mul(pool.accKaoyaPerShare).div(1e12).sub(user.rewardDebt);
        safeKaoyaTransfer(msg.sender, pending);
        user.amount = user.amount.sub(_amount);
        user.rewardDebt = user.amount.mul(pool.accKaoyaPerShare).div(1e12);
        pool.lpToken.safeTransfer(address(msg.sender), _amount);
        emit Withdraw(msg.sender, _pid, _amount);
    }


    function emergencyWithdraw(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount);
        user.amount = 0;
        user.rewardDebt = 0;
    }


    function safeKaoyaTransfer(address _to, uint256 _amount) internal {
        uint256 kaoyaBal = kaoya.balanceOf(address(this));
        if (_amount > kaoyaBal) {
            kaoya.transfer(_to, kaoyaBal);
        } else {
            kaoya.transfer(_to, _amount);
        }
    }
}

pragma solidity 0.6.12;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "./libs/IBEP20.sol";
import "./libs/SafeBEP20.sol";
import "./libs/ILuckyChipReferral.sol";
import "./libs/IMasterChef.sol";
import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";

import "./LCToken.sol";








contract MasterChef is Ownable, ReentrancyGuard, IMasterChef {
    using SafeMath for uint256;
    using SafeBEP20 for IBEP20;

    struct UserInfo {
        uint256 amount; 
        uint256 rewardDebt; 











    }


    struct PoolInfo {
        IBEP20 lpToken; 
        uint256 allocPoint; 
        uint256 bonusPoint; 
        uint256 lastRewardBlock; 
        uint256 accLCPerShare; 
    }

    struct BonusInfo {
        IBEP20 bonusToken;
		uint256 lastBalance;
        uint256 lastRewardBlock;
    }


    LCToken public LC;

    uint256 public percentDec = 1000000;

    uint256 public stakingPercent;

    uint256 public dev0Percent;

    uint256 public dev1Percent;

    uint256 public dev2Percent;

    uint256 public safuPercent;

    address public dev0addr;

    address public dev1addr;

    address public dev2addr;

    address public treasuryaddr;

    address public safuaddr;

    uint256 public lastBlockDevWithdraw;

    uint256 public LCPerBlock;

    uint256 public BONUS_MULTIPLIER = 1;

    PoolInfo[] public poolInfo;

    BonusInfo[] public bonusInfo;

    mapping(uint256 => uint256[]) public poolBonusPerShare;

    mapping(uint256 => mapping(address => uint256)) public userBonusDebt;

    mapping(uint256 => mapping(address => UserInfo)) public userInfo;

    uint256 public totalAllocPoint = 0;

    uint256 public totalBonusPoint = 0;

    uint256 public startBlock;


    ILuckyChipReferral public luckychipReferral;

    uint16 public referralCommissionRate = 100;

    uint16 public constant MAXIMUM_REFERRAL_COMMISSION_RATE = 1000;

    event Deposit(address indexed user, uint256 indexed pid, uint256 amount);
    event Withdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 indexed pid, uint256 amount);
    event EmissionRateUpdated(address indexed caller, uint256 previousAmount, uint256 newAmount);
    event ReferralCommissionPaid(address indexed user, address indexed referrer, uint256 commissionAmount);

    constructor(
        LCToken _LC,
        address _dev0addr,
        address _dev1addr,
        address _dev2addr,
        address _safuaddr,
        address _treasuryaddr,
        uint256 _LCPerBlock,
        uint256 _startBlock,
        uint256 _stakingPercent,
        uint256 _dev0Percent,
        uint256 _dev1Percent,
        uint256 _dev2Percent,
        uint256 _safuPercent
    ) public {
        LC = _LC;
        dev0addr = _dev0addr;
        dev1addr = _dev1addr;
        dev2addr = _dev2addr;
        safuaddr = _safuaddr;
        treasuryaddr = _treasuryaddr;
        LCPerBlock = _LCPerBlock;
        startBlock = _startBlock;
        stakingPercent = _stakingPercent;
        dev0Percent = _dev0Percent;
        dev1Percent = _dev1Percent;
        dev2Percent = _dev2Percent;
        safuPercent = _safuPercent;
        lastBlockDevWithdraw = _startBlock;
    }

    function updateMultiplier(uint256 multiplierNumber) public onlyOwner {
        BONUS_MULTIPLIER = multiplierNumber;
    }

    function poolLength() external view returns (uint256) {
        return poolInfo.length;
    }

    function bonusLength() external view returns (uint256) {
        return bonusInfo.length;
    }

    function withdrawDevFee() public{
        require(lastBlockDevWithdraw < block.number, 'wait for new block');
        uint256 multiplier = getMultiplier(lastBlockDevWithdraw, block.number);
        uint256 LCReward = multiplier.mul(LCPerBlock);
        LC.mint(dev0addr, LCReward.mul(dev0Percent).div(percentDec));
        LC.mint(dev1addr, LCReward.mul(dev1Percent).div(percentDec));
        LC.mint(dev2addr, LCReward.mul(dev2Percent).div(percentDec));
        LC.mint(safuaddr, LCReward.mul(safuPercent).div(percentDec));
        lastBlockDevWithdraw = block.number;
    }




    function add(uint256 _allocPoint, uint256 _bonusPoint, IBEP20 _lpToken, bool _withUpdate) public onlyOwner {
        if (_withUpdate) {
            massUpdatePools();
        }
        uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
        totalAllocPoint = totalAllocPoint.add(_allocPoint);
        totalBonusPoint = totalBonusPoint.add(_bonusPoint);

        poolInfo.push(
            PoolInfo({
                lpToken: _lpToken,
                allocPoint: _allocPoint,
                bonusPoint: _bonusPoint,
                lastRewardBlock: lastRewardBlock,
                accLCPerShare: 0
            })
        );
    }

    function addBonus(IBEP20 _bonusToken) public onlyOwner {
        uint256 lastRewardBlock = block.number > startBlock ? block.number : startBlock;
        bonusInfo.push(BonusInfo({bonusToken: _bonusToken, lastBalance: 0, lastRewardBlock: lastRewardBlock}));
        for(uint256 i = 0; i < poolInfo.length; i ++){
            PoolInfo storage pool = poolInfo[i];
            if (pool.bonusPoint > 0){
                poolBonusPerShare[i].push(0);
            }
        }
    }


    function set( uint256 _pid, uint256 _allocPoint, bool _withUpdate) public onlyOwner {
        if (_withUpdate) {
            massUpdatePools();
        }
        totalAllocPoint = totalAllocPoint.sub(poolInfo[_pid].allocPoint).add(_allocPoint);
        poolInfo[_pid].allocPoint = _allocPoint;
    }


    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {
         return _to.sub(_from).mul(BONUS_MULTIPLIER);
    }


    function pendingLC(uint256 _pid, address _user) external view returns (uint256){
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 accLCPerShare = pool.accLCPerShare;
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 LCReward = multiplier.mul(LCPerBlock).mul(pool.allocPoint).div(totalAllocPoint).mul(stakingPercent).div(percentDec);
            accLCPerShare = accLCPerShare.add(LCReward.mul(1e12).div(lpSupply));
        }
        return user.amount.mul(accLCPerShare).div(1e12).sub(user.rewardDebt);
    }


    function pendingBonus(uint256 _pid, address _user) external view returns (uint256[] memory){
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256[] memory values = new uint256[](bonusInfo.length);
        if (pool.bonusPoint > 0){
            for(uint256 i = 0; i < bonusInfo.length; i ++) {
                values[i] = user.amount.mul(poolBonusPerShare[_pid][i]).div(1e12).sub(userBonusDebt[i][_user]);
            }
        }
        return values;
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.lpToken.balanceOf(address(this));
        if (lpSupply <= 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
        uint256 LCReward = multiplier.mul(LCPerBlock).mul(pool.allocPoint).div(totalAllocPoint).mul(stakingPercent).div(percentDec);
        LC.mint(address(this), LCReward);
        pool.accLCPerShare = pool.accLCPerShare.add(LCReward.mul(1e12).div(lpSupply));
        pool.lastRewardBlock = block.number;
    }


    function updateBonus(uint256 _pid) external override {
		require(_pid < bonusInfo.length, "_pid must be less than bonusInfo length");
        BonusInfo storage bonusPool = bonusInfo[_pid];
		uint256 currentBalance = bonusPool.bonusToken.balanceOf(address(this));
		if(currentBalance > bonusPool.lastBalance){
			uint256 amount = currentBalance.sub(bonusPool.lastBalance);
            for(uint256 i = 0; i < poolInfo.length; i ++){
                PoolInfo storage pool = poolInfo[i];
                uint256 lpSupply = pool.lpToken.balanceOf(address(this));
                if(lpSupply <= 0){
                    continue;
                }
                if (pool.bonusPoint > 0){
                    poolBonusPerShare[i][_pid] = poolBonusPerShare[i][_pid].add(amount.mul(pool.bonusPoint).div(totalBonusPoint).mul(1e12).div(lpSupply));
                }
            }
			bonusPool.lastBalance = currentBalance;
			bonusPool.lastRewardBlock = block.number;
		}
    }


    function payPendingLC(uint256 _pid, address _user) internal {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        uint256 pending = user.amount.mul(pool.accLCPerShare).div(1e12).sub(user.rewardDebt);
        if (pending > 0) {

            safeLCTransfer(_user, pending);
            payReferralCommission(_user, pending);
        }
    }


    function payPendingBonus(uint256 _pid, address _user) internal {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][_user];
        if (pool.bonusPoint > 0){
			require(poolBonusPerShare[_pid].length == bonusInfo.length, "poolBonusPerShare.length must equal to bonusInof length");
            for(uint256 i = 0; i < bonusInfo.length; i ++) {  
                uint256 pending = user.amount.mul(poolBonusPerShare[_pid][i]).div(1e12).sub(userBonusDebt[i][_user]);
                if (pending > 0) {
                    BonusInfo storage bonusPool = bonusInfo[i];
					bonusPool.lastBalance = bonusPool.lastBalance.sub(pending);
                    bonusPool.bonusToken.safeTransfer(address(_user), pending);
                }
            }
        }
    }


    function deposit(uint256 _pid, uint256 _amount, address _referrer) public nonReentrant {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        updatePool(_pid);
        if(_amount > 0 && address(luckychipReferral) != address(0) && _referrer != address(0) && _referrer != msg.sender){
            luckychipReferral.recordReferral(msg.sender, _referrer);
        }
        payPendingLC(_pid, msg.sender);
        if (pool.bonusPoint > 0){
            payPendingBonus(_pid, msg.sender);
		}
        if(_amount > 0){
            pool.lpToken.safeTransferFrom(address(msg.sender), address(this), _amount);
            user.amount = user.amount.add(_amount);
        }
        user.rewardDebt = user.amount.mul(pool.accLCPerShare).div(1e12);
        if (pool.bonusPoint > 0){
            for(uint256 i = 0; i < bonusInfo.length; i ++) {  
				userBonusDebt[i][msg.sender] = user.amount.mul(poolBonusPerShare[_pid][i]).div(1e12);
            }
        }

        emit Deposit(msg.sender, _pid, _amount);
    }


    function withdraw(uint256 _pid, uint256 _amount) public nonReentrant {

        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        require(user.amount >= _amount, "withdraw: not good");
        updatePool(_pid);
        payPendingLC(_pid, msg.sender);
        if (pool.bonusPoint > 0){
            payPendingBonus(_pid, msg.sender);
		}
        if(_amount > 0){
            user.amount = user.amount.sub(_amount);
            pool.lpToken.safeTransfer(address(msg.sender), _amount);
        } 
        user.rewardDebt = user.amount.mul(pool.accLCPerShare).div(1e12);
        if (pool.bonusPoint > 0){
            for(uint256 i = 0; i < bonusInfo.length; i ++) {  
				userBonusDebt[i][msg.sender] = user.amount.mul(poolBonusPerShare[_pid][i]).div(1e12);
            }
        }
        emit Withdraw(msg.sender, _pid, _amount);
    }


    function emergencyWithdraw(uint256 _pid) public nonReentrant {
        PoolInfo storage pool = poolInfo[_pid];
        UserInfo storage user = userInfo[_pid][msg.sender];
        pool.lpToken.safeTransfer(address(msg.sender), user.amount);
        emit EmergencyWithdraw(msg.sender, _pid, user.amount);
        user.amount = 0;
        user.rewardDebt = 0;
		if(pool.bonusPoint > 0){

		}
    }


    function safeLCTransfer(address _to, uint256 _amount) internal {
        uint256 LCBal = LC.balanceOf(address(this));
        if (_amount > LCBal) {
            LC.transfer(_to, LCBal);
        } else {
            LC.transfer(_to, _amount);
        }
    }

    function setDevAddress(address _dev0addr,address _dev1addr,address _dev2addr) public onlyOwner {
        dev0addr = _dev0addr;
        dev1addr = _dev1addr;
        dev2addr = _dev2addr;
    }
    function setSafuAddress(address _safuaddr) public onlyOwner{
        safuaddr = _safuaddr;
    }
    function setTreasuryAddress(address _treasuryaddr) public onlyOwner{
        treasuryaddr = _treasuryaddr;
    }
    function updateLcPerBlock(uint256 newAmount) public onlyOwner {
        require(newAmount <= 100 * 1e18, 'Max per block 100 LC');
        require(newAmount >= 1 * 1e15, 'Min per block 0.001 LC');
        LCPerBlock = newAmount;
    }

    function setReferralCommissionRate(uint16 _referralCommissionRate) public onlyOwner {
        require(_referralCommissionRate <= MAXIMUM_REFERRAL_COMMISSION_RATE, "setReferralCommissionRate: invalid referral commission rate basis points");
        referralCommissionRate = _referralCommissionRate;
    }


    function payReferralCommission(address _user, uint256 _pending) internal {
        if (referralCommissionRate > 0) {
            if (address(luckychipReferral) != address(0)){
                address referrer = luckychipReferral.getReferrer(_user);
                uint256 commissionAmount = _pending.mul(referralCommissionRate).div(10000);

                if (commissionAmount > 0) {
                    if (referrer != address(0)){
                        LC.mint(referrer, commissionAmount);
                        luckychipReferral.recordReferralCommission(referrer, commissionAmount);
                        emit ReferralCommissionPaid(_user, referrer, commissionAmount);
                    }else{
                        LC.mint(treasuryaddr, commissionAmount);
                        luckychipReferral.recordReferralCommission(treasuryaddr, commissionAmount);
                        emit ReferralCommissionPaid(_user, treasuryaddr, commissionAmount);
                    }
                }
            }else{
                uint256 commissionAmount = _pending.mul(referralCommissionRate).div(10000);
                if (commissionAmount > 0){
                    LC.mint(treasuryaddr, commissionAmount);
                    emit ReferralCommissionPaid(_user, treasuryaddr, commissionAmount);
                }
            }
        }
    }
}

pragma solidity 0.8.7;

import '@openzeppelin/contracts/token/ERC20/ERC20.sol';
import '@openzeppelin/contracts/access/Ownable.sol';

contract LuckyToken is ERC20, Ownable {

    string private _name = "Lucky";
    string private _symbol = "LUCKY";

    uint256 private constant FAIR_LAUNCH = 1 * 1000000 * 10**18; 
    uint256 private constant WAR_CHEST = 5 * 1000000 * 10**18;
    uint256 private constant ECOSYSTEM = 20 * 1000000 * 10**18;
    uint256 private constant CAP = 100 * 1000000 * 10**18; 

    address Owner;
    address WarChest;
    address Ecosystem;

    constructor (address _Owner, address _Warchest, address _Ecosystem) ERC20(_name, _symbol) { 

        Owner = _Owner;
        WarChest = _Warchest;
        Ecosystem = _Ecosystem;


        _mint(Owner, FAIR_LAUNCH);

        _mint(WarChest, WAR_CHEST);

        _mint(Ecosystem, ECOSYSTEM);

        transferOwnership(_Owner);
    }


    function cap() public view virtual returns (uint256) {
        return CAP;
    }

    function mint(address _to, uint256 _amount) external onlyOwner {
        _mint(_to, _amount);
    }




    function _mint(address _to, uint256 _amount) internal virtual onlyOwner override {
        require(ERC20.totalSupply() + _amount <= cap(), "ERC20Capped: cap exceeded");
        super._mint(_to, _amount);
    }
}

pragma solidity =0.6.12;
pragma experimental ABIEncoderV2;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/utils/EnumerableSet.sol";
import "@openzeppelin/contracts/math/SafeMath.sol";
import "../interfaces/IERC20Metadata.sol";
import "./PoolVault.sol";
import "../base/BasicMetaTransaction.sol";


contract MutiRewardPool is Ownable, IERC20, BasicMetaTransaction {
    using SafeMath for uint256;
    using SafeERC20 for IERC20;

    using EnumerableSet for EnumerableSet.UintSet;

    using EnumerableSet for EnumerableSet.AddressSet;
    EnumerableSet.AddressSet private _callers;


    struct UserInfo {
        EnumerableSet.UintSet stakingIds;
    }

    struct StakingInfo {
        uint256 pid;
        uint256 amount;     
        uint256 token0RewardDebt; 
        uint256 token1RewardDebt; 
        uint256 time; 
    }

    struct StakingView {
        uint256 pid;
        uint256 stakingId;
        uint256 amount;     
        uint256 token0UnclaimedRewards;
        uint256 token1UnclaimedRewards;
        uint256 time; 
        uint256 unlockTime;
    }


    struct PoolInfo {
        IERC20 lpToken;           
        uint256 totalDeposit;
        uint256 duration;           
        uint256 allocPoint;       
        uint256 lastRewardBlock;  
        uint256 token0AccRewardsPerShare; 
        uint256 token1AccRewardsPerShare; 
        uint256 token0AccAdditionalRewardsPerShare; 
        uint256 token1AccAdditionalRewardsPerShare; 
        uint256 token0AccDonateAmount;
        uint256 token1AccDonateAmount;
    }

    struct PoolView {
        uint256 pid;
        address lpToken;
        uint256 totalDeposit;
        uint256 duration; 
        uint256 allocPoint;       
        uint256 lastRewardBlock;  
        uint256 token0AccRewardsPerShare; 
        uint256 token1AccRewardsPerShare; 
        uint256 token0AccAdditionalRewardsPerShare; 
        uint256 token1AccAdditionalRewardsPerShare; 
        uint256 token0AccDonateAmount;
        uint256 token1AccDonateAmount;
        uint256 token0RewardsPerBlock;
        uint256 token1RewardsPerBlock;
        uint256 token0AdditionalRewardPerBlock;
        uint256 token1AdditionalRewardPerBlock;
        string lpSymbol;
        string lpName;
        uint8 lpDecimals;
        string rewardToken0Symbol;
        string rewardToken0Name;
        uint8 rewardToken0Decimals;
        string rewardToken1Symbol;
        string rewardToken1Name;
        uint8 rewardToken1Decimals;
    }

    IERC20 public depositToken;
    IERC20 public rewardToken0;
    IERC20 public rewardToken1;
    PoolVault public poolVault;




    uint256 public token0RewardPerBlock;
    uint256 public token1RewardPerBlock;


    uint256 public token0AdditionalRewardPerBlock;
    uint256 public token1AdditionalRewardPerBlock;


    uint256 public token0AdditionalRewardEndBlock;
    uint256 public token1AdditionalRewardEndBlock;


    uint256 public BONUS_MULTIPLIER = 1;


    PoolInfo[] public poolInfo;


    mapping (address => UserInfo) private userInfo;
    mapping (uint256 => StakingInfo) public stakingInfo;

    uint256 private lastStakingId;


    uint256 private totalAllocPoint = 0;



    uint256 public startBlock;

    uint256 public bonusEndBlock;

    event Deposit(address indexed user, uint256 pid, uint256 stakingId, uint256 amount);
    event Withdraw(address indexed user, uint256 pid, uint256 stakingId, uint256 amount);
    event EmergencyWithdraw(address indexed user, uint256 pid, uint256 stakingId, uint256 amount);
    event Harvest(address indexed user, uint256 pid, uint256 stakingId, uint256 reward0Amount, uint256 reward1Amount);
    event Donate(address indexed user, uint256 pid, address donteToken, uint256 donateAmount, uint256 realAmount);

    constructor(
        IERC20 _depositToken,
        IERC20 _rewardToken0,
        IERC20 _rewardToken1,
        uint256 _token0RewardPerBlock,
        uint256 _token1RewardPerBlock,
        uint256 _startBlock,
        uint256 _bonusEndBlock
    ) public {
        depositToken = _depositToken;
        rewardToken0 = _rewardToken0;
        rewardToken1 = _rewardToken1;
        token0RewardPerBlock = _token0RewardPerBlock;
        token1RewardPerBlock = _token1RewardPerBlock;
        startBlock = _startBlock;
        bonusEndBlock = _bonusEndBlock;

        poolVault = new PoolVault();
        poolVault.approve(address(depositToken));
    }







    function getMultiplier(uint256 _from, uint256 _to) public view returns (uint256) {
        if (_to <= bonusEndBlock) {
            return _to.sub(_from).mul(BONUS_MULTIPLIER);
        } else if (_from >= bonusEndBlock) {
            return 0;
        } else {
            return bonusEndBlock.sub(_from).mul(BONUS_MULTIPLIER);
        }
    }

    function updateMultiplier(uint256 multiplierNumber) public onlyOwner {
        massUpdatePools();
        BONUS_MULTIPLIER = multiplierNumber;
    }

    function addPool(
        uint256 _stakingDuration,
        uint256 _allocPoint
    ) public onlyOwner {
        massUpdatePools();


        poolInfo.push(PoolInfo({
            lpToken: depositToken,
            totalDeposit: 0,
            duration: _stakingDuration,
            allocPoint: _allocPoint,
            lastRewardBlock: block.number > startBlock? block.number: startBlock,
            token0AccRewardsPerShare: 0,
            token1AccRewardsPerShare: 0,
            token0AccAdditionalRewardsPerShare: 0,
            token1AccAdditionalRewardsPerShare: 0,
            token0AccDonateAmount: 0,
            token1AccDonateAmount: 0
        }));

        totalAllocPoint = totalAllocPoint.add(_allocPoint);
    }


    function token0PendingReward(uint256 _stakingId) public view returns (uint256) {

        StakingInfo storage user = stakingInfo[_stakingId];
        PoolInfo storage pool = poolInfo[user.pid];
        uint256 lpSupply = pool.totalDeposit;

        if (user.amount == 0) {
            return 0;
        }

        uint256 amount;
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {

            uint256 accRewardsPerShare = pool.token0AccRewardsPerShare;
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 tokenReward = multiplier.mul(token0RewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accRewardsPerShare = accRewardsPerShare.add(tokenReward.mul(1e12).div(lpSupply));
            amount = user.amount.mul(accRewardsPerShare);

            uint256 endBlock = block.number > token0AdditionalRewardEndBlock? token0AdditionalRewardEndBlock : block.number;
            uint256 accAdditionalRewardsPerShare = pool.token0AccAdditionalRewardsPerShare;
            if (endBlock > pool.lastRewardBlock) {
                uint256 additionalMultiplier = getMultiplier(pool.lastRewardBlock, endBlock);
                uint256 additionalTokenReward = additionalMultiplier.mul(token0AdditionalRewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
                accAdditionalRewardsPerShare = accAdditionalRewardsPerShare.add(additionalTokenReward.mul(1e12).div(lpSupply));
            }
            amount = amount.add(user.amount.mul(accAdditionalRewardsPerShare));
        }

        return amount.div(1e12).sub(user.token0RewardDebt);
    }


    function token1PendingReward(uint256 _stakingId) public view returns (uint256) {
        StakingInfo storage user = stakingInfo[_stakingId];
        PoolInfo storage pool = poolInfo[user.pid];
        uint256 lpSupply = pool.totalDeposit;

        if (user.amount == 0) {
            return 0;
        }

        uint256 amount;
        if (block.number > pool.lastRewardBlock && lpSupply != 0) {

            uint256 accRewardsPerShare = pool.token1AccRewardsPerShare;
            uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);
            uint256 tokenReward = multiplier.mul(token1RewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
            accRewardsPerShare = accRewardsPerShare.add(tokenReward.mul(1e12).div(lpSupply));
            amount = user.amount.mul(accRewardsPerShare);

            uint256 endBlock = block.number > token1AdditionalRewardEndBlock? token1AdditionalRewardEndBlock : block.number;
            uint256 accAdditionalRewardsPerShare = pool.token1AccAdditionalRewardsPerShare;
            if (endBlock > pool.lastRewardBlock) {
                uint256 additionalMultiplier = getMultiplier(pool.lastRewardBlock, endBlock);
                uint256 additionalTokenReward = additionalMultiplier.mul(token1AdditionalRewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
                accAdditionalRewardsPerShare = accAdditionalRewardsPerShare.add(additionalTokenReward.mul(1e12).div(lpSupply));
            }
            amount = amount.add(user.amount.mul(accAdditionalRewardsPerShare));
        }

        return amount.div(1e12).sub(user.token1RewardDebt);
    }


    function updatePool(uint256 _pid) public {
        PoolInfo storage pool = poolInfo[_pid];
        if (block.number <= pool.lastRewardBlock) {
            return;
        }
        uint256 lpSupply = pool.totalDeposit;
        if (lpSupply == 0) {
            pool.lastRewardBlock = block.number;
            return;
        }
        uint256 multiplier = getMultiplier(pool.lastRewardBlock, block.number);

        uint256 token0Reward = multiplier.mul(token0RewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
        pool.token0AccRewardsPerShare = pool.token0AccRewardsPerShare.add(token0Reward.mul(1e12).div(lpSupply));
        {
            uint256 endBlock = block.number > token0AdditionalRewardEndBlock? token0AdditionalRewardEndBlock : block.number;
            if (endBlock > pool.lastRewardBlock) {
                uint256 additionalMultiplier = getMultiplier(pool.lastRewardBlock, endBlock);
                uint256 additionalTokenReward = additionalMultiplier.mul(token0AdditionalRewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
                pool.token0AccAdditionalRewardsPerShare = pool.token0AccAdditionalRewardsPerShare.add(additionalTokenReward.mul(1e12).div(lpSupply));
            }

            if (block.number >= token0AdditionalRewardEndBlock) {
                token0AdditionalRewardPerBlock = 0;
            }
        }

        uint256 token1Reward = multiplier.mul(token1RewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
        pool.token1AccRewardsPerShare = pool.token1AccRewardsPerShare.add(token1Reward.mul(1e12).div(lpSupply));
        {
            uint256 endBlock = block.number > token1AdditionalRewardEndBlock? token1AdditionalRewardEndBlock : block.number;
            if (endBlock > pool.lastRewardBlock) {
                uint256 additionalMultiplier = getMultiplier(pool.lastRewardBlock, endBlock);
                uint256 additionalTokenReward = additionalMultiplier.mul(token1AdditionalRewardPerBlock).mul(pool.allocPoint).div(totalAllocPoint);
                pool.token1AccAdditionalRewardsPerShare = pool.token1AccAdditionalRewardsPerShare.add(additionalTokenReward.mul(1e12).div(lpSupply));
            }

            if (block.number >= token1AdditionalRewardEndBlock) {
                token1AdditionalRewardPerBlock = 0;
            }
        }

        pool.lastRewardBlock = block.number;
    }


    function massUpdatePools() public {
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);
        }
    }


    function deposit(uint256 pid, uint256 _amount) public {
        require(_amount > 0, "bad amount");

        PoolInfo storage pool = poolInfo[pid];
        UserInfo storage user = userInfo[msgSender()];



        updatePool(pid);

        uint256 oldBal = pool.lpToken.balanceOf(address(poolVault));
        pool.lpToken.safeTransferFrom(address(msgSender()), address(poolVault), _amount);
        _amount = pool.lpToken.balanceOf(address(poolVault)).sub(oldBal);

        lastStakingId++;
        pool.totalDeposit = pool.totalDeposit.add(_amount);

        stakingInfo[lastStakingId] = StakingInfo({
            pid: pid,
            amount: _amount,
            token0RewardDebt: _amount.mul(pool.token0AccRewardsPerShare).add(_amount.mul(pool.token0AccAdditionalRewardsPerShare)).div(1e12),
            token1RewardDebt: _amount.mul(pool.token1AccRewardsPerShare).add(_amount.mul(pool.token1AccAdditionalRewardsPerShare)).div(1e12),
            time: block.timestamp
        });
        user.stakingIds.add(lastStakingId);

        emit Deposit(msgSender(), pid, lastStakingId, _amount);
        emit Transfer(address(0), msgSender(), _amount);
    }

    function harvestAll() public {
        UserInfo storage user = userInfo[msgSender()];

        uint256 len = user.stakingIds.length();

        for(uint256 i = 0; i < len; ++i) {
            harvest(user.stakingIds.at(i));
        }
    }

    function harvestPool(uint256 pid) public {
        UserInfo storage user = userInfo[msgSender()];

        uint256 len = user.stakingIds.length();

        for(uint256 i = 0; i < len; ++i) {
            uint256 id = user.stakingIds.at(i);
            if (stakingInfo[id].pid != pid) {
                continue;
            }
            harvest(id);
        }
    }

    function harvest(uint256 _stakingId) public {

        UserInfo storage user = userInfo[msgSender()];
        require(user.stakingIds.contains(_stakingId), "not the staking owner");
        StakingInfo storage staking = stakingInfo[_stakingId];
        PoolInfo storage pool = poolInfo[staking.pid];

        updatePool(staking.pid);

        uint256 reward0;
        uint256 reward1;
        if (staking.amount > 0) {
            {
                uint256 pending = staking.amount.mul(pool.token0AccRewardsPerShare).add(staking.amount.mul(pool.token0AccAdditionalRewardsPerShare)).div(1e12).sub(staking.token0RewardDebt);
                if(pending > 0) {
                    uint256 bal = rewardToken0.balanceOf(address(this));
                    if(bal >= pending) {
                        reward0 = pending;
                    } else {
                        reward0 = bal;
                    }
                }
            }

            {
                uint256 pending = staking.amount.mul(pool.token1AccRewardsPerShare).add(staking.amount.mul(pool.token1AccAdditionalRewardsPerShare)).div(1e12).sub(staking.token1RewardDebt);
                if(pending > 0) {
                    uint256 bal = rewardToken1.balanceOf(address(this));
                    if(bal >= pending) {
                        reward1 = pending;
                    } else {
                        reward1 = bal;
                    }
                }
            }
        }

        staking.token0RewardDebt = staking.amount.mul(pool.token0AccRewardsPerShare).add(staking.amount.mul(pool.token0AccAdditionalRewardsPerShare)).div(1e12);
        staking.token1RewardDebt = staking.amount.mul(pool.token1AccRewardsPerShare).add(staking.amount.mul(pool.token1AccAdditionalRewardsPerShare)).div(1e12);

        if (reward0 > 0) {
            rewardToken0.safeTransfer(address(msgSender()), reward0);
        }

         if (reward1 > 0) {
            rewardToken1.safeTransfer(address(msgSender()), reward1);
        }

        emit Harvest(msgSender(), staking.pid, _stakingId, reward0, reward1);
    }


    function withdraw(uint256 _stakingId) public {
        UserInfo storage user = userInfo[msgSender()];
        require(user.stakingIds.contains(_stakingId), "not the staking owner");
        StakingInfo storage staking = stakingInfo[_stakingId];
        PoolInfo storage pool = poolInfo[staking.pid];

        require(block.timestamp.sub(staking.time) >= pool.duration, "not time");

        harvest(_stakingId);

        uint256 _amount = staking.amount;
        staking.amount = 0;
        pool.totalDeposit = pool.totalDeposit.sub(_amount);
        pool.lpToken.safeTransferFrom(address(poolVault), address(msgSender()), _amount);

        staking.token0RewardDebt = _amount.mul(pool.token0AccRewardsPerShare).add(_amount.mul(pool.token0AccAdditionalRewardsPerShare)).div(1e12);
        staking.token1RewardDebt = _amount.mul(pool.token1AccRewardsPerShare).add(_amount.mul(pool.token1AccAdditionalRewardsPerShare)).div(1e12);

        user.stakingIds.remove(_stakingId);

        emit Withdraw(msgSender(), staking.pid, _stakingId, _amount);
        emit Transfer(msgSender(), address(0), _amount);
    }


    function emergencyWithdraw(uint256 _stakingId) public {
        UserInfo storage user = userInfo[msgSender()];
        require(user.stakingIds.contains(_stakingId), "not the staking owner");
        StakingInfo storage staking = stakingInfo[_stakingId];
        PoolInfo storage pool = poolInfo[staking.pid];
        require(block.number.sub(staking.time) >= pool.duration, "not time");

        uint256 amount = staking.amount;

        if(pool.totalDeposit >= staking.amount) {
            pool.totalDeposit = pool.totalDeposit.sub(staking.amount);
        } else {
            pool.totalDeposit = 0;
        }
        staking.amount = 0;
        staking.token0RewardDebt = 0;
        staking.token1RewardDebt = 0;

        user.stakingIds.remove(_stakingId);

        pool.lpToken.safeTransferFrom(address(poolVault), address(msgSender()), amount);

        emit EmergencyWithdraw(msgSender(),  staking.pid, _stakingId, amount);
        emit Transfer(msgSender(), address(0), amount);
    }


    function emergencyRewardWithdrawToken0(uint256 _amount) public onlyOwner {
        require(_amount <= rewardToken0.balanceOf(address(this)), 'not enough token');
        rewardToken0.safeTransfer(address(msgSender()), _amount);
    }


    function emergencyRewardWithdrawToken1(uint256 _amount) public onlyOwner {
        require(_amount <= rewardToken1.balanceOf(address(this)), 'not enough token');
        rewardToken1.safeTransfer(address(msgSender()), _amount);
    }

    function totalStaking(address account) public view returns(uint256 amount) {
        UserInfo storage user = userInfo[account];
        uint ln = user.stakingIds.length();

        for (uint i = 0; i < ln; ++i) {
            amount = amount.add(stakingInfo[user.stakingIds.at(i)].amount);
        }
    }

    function donate(IERC20 token, uint256 donateAmount) public {
        require(token == rewardToken0 || token == rewardToken1, "not support token");

        uint256 oldBal = IERC20(token).balanceOf(address(this));
        IERC20(token).safeTransferFrom(msgSender(), address(this), donateAmount);
        uint256 realAmount = IERC20(token).balanceOf(address(this)) - oldBal;

        bool isToken0 = token == rewardToken0 ? true : false;
        uint256 length = poolInfo.length;
        for (uint256 pid = 0; pid < length; ++pid) {
            updatePool(pid);

            PoolInfo storage pool = poolInfo[pid];
            if(pool.allocPoint == 0) {
                continue;
            }

            if(pool.totalDeposit == 0) {
                continue;
            }

            uint256 tokenReward = realAmount.mul(1e12).mul(pool.allocPoint).div(totalAllocPoint);
            if (isToken0) {
                pool.token0AccRewardsPerShare = pool.token0AccRewardsPerShare.add(tokenReward.div(pool.totalDeposit));
                pool.token0AccDonateAmount = pool.token0AccDonateAmount.add(tokenReward);
            } else {
                pool.token1AccRewardsPerShare = pool.token1AccRewardsPerShare.add(tokenReward.div(pool.totalDeposit));
                pool.token1AccDonateAmount = pool.token1AccDonateAmount.add(tokenReward);
            }
            emit Donate(msgSender(), pid, address(token), tokenReward.div(1e12), tokenReward.div(1e12));
        }
    }

    function addAdditionalRewards(IERC20 token, uint256 amount, uint256 rewardsBlocks) public onlyCaller {
        require(token == rewardToken0 || token == rewardToken1, "not support token");

        massUpdatePools();

        uint256 oldBal = IERC20(token).balanceOf(address(this));
        IERC20(token).safeTransferFrom(msgSender(), address(this), amount);
        uint256 realAmount = IERC20(token).balanceOf(address(this)).sub(oldBal);

        if (token == rewardToken0) {
            uint256 remainingBlocks = token0AdditionalRewardEndBlock > block.number ? token0AdditionalRewardEndBlock.sub(block.number) : 0;
            uint256 remainingBal = token0AdditionalRewardPerBlock.mul(remainingBlocks);

            if(remainingBal > 0) {
                rewardsBlocks = rewardsBlocks.add(remainingBlocks);
            }
            remainingBal = remainingBal.add(realAmount);

            token0AdditionalRewardPerBlock = remainingBal.div(rewardsBlocks);

            if(block.number >= startBlock) {
                token0AdditionalRewardEndBlock = block.number.add(rewardsBlocks);
            } else {
                token0AdditionalRewardEndBlock = startBlock.add(rewardsBlocks);
            }
        } else {
            uint256 remainingBlocks = token1AdditionalRewardEndBlock > block.number ? token1AdditionalRewardEndBlock.sub(block.number) : 0;
            uint256 remainingBal = token1AdditionalRewardPerBlock.mul(remainingBlocks);

            if(remainingBal > 0) {
                rewardsBlocks = rewardsBlocks.add(remainingBlocks);
            }
            remainingBal = remainingBal.add(realAmount);

            token1AdditionalRewardPerBlock = remainingBal.div(rewardsBlocks);

            if(block.number >= startBlock) {
                token1AdditionalRewardEndBlock = block.number.add(rewardsBlocks);
            } else {
                token1AdditionalRewardEndBlock = startBlock.add(rewardsBlocks);
            }
        }
    }

    function getBaseInfo() public view 
    returns (
        address depositToken_, 
        address rewardToken0_, 
        address rewardToken1_, 
        uint256 token0RewardPerBlock_,
        uint256 token1RewardPerBlock_,
        uint256 token0AdditionalRewardPerBlock_,
        uint256 token1AdditionalRewardPerBlock_,
        uint256 token0AdditionalRewardEndBlock_,
        uint256 token1AdditionalRewardEndBlock_,
        uint256 totalAllocPoint_,
        uint256 startBlock_,
        uint256 bonusEndBlock_
    ) {
        depositToken_ = address(depositToken);
        rewardToken0_ = address(rewardToken0);
        rewardToken1_ = address(rewardToken1);
        token0RewardPerBlock_ = token0RewardPerBlock;
        token1RewardPerBlock_ = token1RewardPerBlock;
        token0AdditionalRewardPerBlock_ = token0AdditionalRewardPerBlock;
        token1AdditionalRewardPerBlock_ = token1AdditionalRewardPerBlock;
        token0AdditionalRewardEndBlock_ = token0AdditionalRewardEndBlock;
        token1AdditionalRewardEndBlock_ = token1AdditionalRewardEndBlock;
        totalAllocPoint_ = totalAllocPoint;
        startBlock_ = startBlock;
        bonusEndBlock_ = bonusEndBlock;
    }

    function getPoolView(uint256 pid) public view returns(PoolView memory) {
        require(pid < poolInfo.length, "MutiRewardPool: pid out of range");

        PoolInfo memory pool = poolInfo[pid];

        string memory symbol = IERC20Metadata(address(pool.lpToken)).symbol();
        string memory name = IERC20Metadata(address(pool.lpToken)).name();
        uint8 decimals = IERC20Metadata(address(pool.lpToken)).decimals();

        uint256 rewardsPerBlock0 = pool.allocPoint.mul(token0RewardPerBlock).div(totalAllocPoint);
        uint256 rewardsPerBlock1 = pool.allocPoint.mul(token1RewardPerBlock).div(totalAllocPoint);

        uint256 additionalRewardsPerBlock0 = pool.allocPoint.mul(token0AdditionalRewardPerBlock).div(totalAllocPoint);
        uint256 additionalRewardsPerBlock1 = pool.allocPoint.mul(token1AdditionalRewardPerBlock).div(totalAllocPoint);

        return
            PoolView({
                pid: pid,
                lpToken: address(pool.lpToken),
                totalDeposit: pool.totalDeposit,
                duration: pool.duration,
                allocPoint: pool.allocPoint,
                lastRewardBlock: pool.lastRewardBlock,
                token0AccRewardsPerShare: pool.token0AccRewardsPerShare,
                token1AccRewardsPerShare: pool.token1AccRewardsPerShare,
                token0AccAdditionalRewardsPerShare: pool.token0AccAdditionalRewardsPerShare,
                token1AccAdditionalRewardsPerShare: pool.token1AccAdditionalRewardsPerShare,
                token0AccDonateAmount: pool.token0AccDonateAmount,
                token1AccDonateAmount: pool.token1AccDonateAmount,
                token0RewardsPerBlock: rewardsPerBlock0,
                token1RewardsPerBlock: rewardsPerBlock1,
                token0AdditionalRewardPerBlock: additionalRewardsPerBlock0,
                token1AdditionalRewardPerBlock: additionalRewardsPerBlock1,
                lpSymbol: symbol,
                lpName: name,
                lpDecimals: decimals,
                rewardToken0Symbol: IERC20Metadata(address(rewardToken0)).symbol(),
                rewardToken0Name: IERC20Metadata(address(rewardToken0)).name(),
                rewardToken0Decimals: IERC20Metadata(address(rewardToken0)).decimals(),
                rewardToken1Symbol: IERC20Metadata(address(rewardToken1)).symbol(),
                rewardToken1Name: IERC20Metadata(address(rewardToken1)).name(),
                rewardToken1Decimals: IERC20Metadata(address(rewardToken1)).decimals()
            });
    }

    function getAllPoolViews() external view returns (PoolView[] memory) {
        PoolView[] memory views = new PoolView[](poolInfo.length);
        for (uint256 i = 0; i < poolInfo.length; i++) {
            views[i] = getPoolView(i);
        }
        return views;
    }

    function getStakingView(uint256 stakingId) public view returns(StakingView memory) {
        StakingInfo memory staking = stakingInfo[stakingId];

        uint256 token0UnclaimedRewards = token0PendingReward(stakingId);
        uint256 token1UnclaimedRewards = token1PendingReward(stakingId);

        return StakingView({
            pid: staking.pid,
            stakingId: stakingId,
            amount: staking.amount,
            token0UnclaimedRewards: token0UnclaimedRewards,
            token1UnclaimedRewards: token1UnclaimedRewards,
            time: staking.time,
            unlockTime: poolInfo[staking.pid].duration.add(staking.time)
        });

    }

    function getStakingViews(address account) public view returns(StakingView[] memory) {
        UserInfo storage user = userInfo[account];

        uint256 len = user.stakingIds.length();

        StakingView[] memory views = new StakingView[](len);

        for (uint i = 0; i < len; ++i) {
            views[i] = getStakingView(user.stakingIds.at(i));
        }
        return views;
    }



    function name() public view virtual returns (string memory) {
        return string( abi.encodePacked( "Staked ", IERC20Metadata(address(depositToken)).symbol() ));
    }

    function symbol() public view virtual returns (string memory) {
        return string( abi.encodePacked( "ve", IERC20Metadata(address(depositToken)).symbol() ));
    }

    function decimals() public view virtual returns (uint8) {
        return IERC20Metadata(address(depositToken)).decimals();
    }

    function totalSupply() public view override returns (uint256) {
        uint256 totalDeposit;
        for(uint i = 0; i < poolInfo.length; ++i) {
            totalDeposit = totalDeposit.add(poolInfo[i].totalDeposit.mul(poolInfo[i].allocPoint));
        }
        return totalDeposit;
    }

    function balanceOf(address account) public view override returns (uint256) {

        UserInfo storage user = userInfo[account];
        uint ln = user.stakingIds.length();

        uint256 bal;
        for (uint i = 0; i < ln; ++i) {
            StakingInfo memory staking = stakingInfo[user.stakingIds.at(i)];
            bal = bal.add(staking.amount.mul(poolInfo[staking.pid].allocPoint));
        }

        return bal;
    }

    function transfer(address, uint256) public override returns (bool) {
        revert("can not allow transfer");
    }

    function allowance(address, address) public view override returns (uint256) {
        return 0;
    }

    function approve(address, uint256) public override returns (bool) {
        revert("can not allow approve");
    }

    function transferFrom(address, address, uint256) public override returns (bool) {
        revert("can not allow transfer");
    }




    modifier onlyCaller() {
        require(isCaller(msgSender()), "Treasury: not the caller");
        _;
    }

    function addCaller(address _newCaller) public onlyOwner returns (bool) {
        require(_newCaller != address(0), "MutiRewardPool: address is zero");
        return EnumerableSet.add(_callers, _newCaller);
    }

    function delCaller(address _delCaller) public onlyOwner returns (bool) {
        require(_delCaller != address(0), "MutiRewardPool: address is zero");
        return EnumerableSet.remove(_callers, _delCaller);
    }

    function getCallerLength() public view returns (uint256) {
        return EnumerableSet.length(_callers);
    }

    function isCaller(address _caller) public view returns (bool) {
        return EnumerableSet.contains(_callers, _caller);
    }

    function getCaller(uint256 _index) public view returns (address) {
        require(_index <= getCallerLength() - 1, "MutiRewardPool: index out of bounds");
        return EnumerableSet.at(_callers, _index);
    }
}

