contract Bollystake is ERC20("sBOLLY Staked Bollycoin", "sBOLLY"),Ownable{
    using SafeMath for uint256;

    IERC20 public immutable BOLLY;

    constructor(IERC20 _BOLLY) {
        require(address(_BOLLY) != address(0), "_BOLLY is a zero address");
        BOLLY = _BOLLY;
    }
    uint256 private constant _TIMELOCK_30 = 3 minutes;
    uint256 private constant _TIMELOCK_60 = 6 minutes;
    uint256 private constant _TIMELOCK_90 = 9 minutes;
    uint256 private constant _TIMELOCK_180 = 18 minutes;
    uint256 private constant _TIMELOCK_365 = 36 minutes;
    uint256 private constant _TIMELOCK_540 = 54 minutes;
    uint256 private constant _TIMELOCK_730 = 73 minutes;



     struct locked{
        uint256 expire;
        uint256 locked_amount;
     }
     mapping(address => locked) users;
     mapping(address => locked[7]) user_stake;
      address[] internal stakeholders;

   function isStakeholder(address _address)
       public
       view
       returns(bool, uint256)
   {
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           if (_address == stakeholders[s]) return (true, s);
       }
       return (false, 0);
   }


   function addStakeholder(address _stakeholder)
       private
   {
       (bool _isStakeholder, ) = isStakeholder(_stakeholder);
       if(!_isStakeholder) stakeholders.push(_stakeholder);
   }


   function removeStakeholder(address _stakeholder)
       private
   {
       (bool _isStakeholder, uint256 s) = isStakeholder(_stakeholder);
       if(_isStakeholder){
           stakeholders[s] = stakeholders[stakeholders.length - 1];
           stakeholders.pop();
       }
   }

   mapping(address => uint256) internal stakes;


   function stakeOf(address _stakeholder)
       public
       view
       returns(uint256)
   {
       return stakes[_stakeholder];
   }


   function totalStakes()
       external
       view 
       returns(uint256)
   {
       uint256 _totalStakes = 0;
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           _totalStakes = _totalStakes.add(stakes[stakeholders[s]]);
       }
       return _totalStakes;
   }

   function total_eligible_Stakes()
       public
       view
       returns(uint256)
   {
       uint256 _totaleligibleStakes = 0;
       uint256 _usereligiblestakes = 0;
       uint256 _expired_stakes = 0;
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           _expired_stakes = expired_stakes(stakeholders[s]);
           _usereligiblestakes = stakes[stakeholders[s]].sub(_expired_stakes);
           _totaleligibleStakes = _totaleligibleStakes.add(_usereligiblestakes);
       }
       return _totaleligibleStakes;
   }

   function Eligible_stakes() external view returns (address [] memory,uint256 [] memory)
   {
       uint256 [] memory eligible_stakes = new uint256[](stakeholders.length);
       address [] memory user_address = new address[](stakeholders.length);
       uint256 _expired_stakes = 0;
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           _expired_stakes = expired_stakes(stakeholders[s]);
           eligible_stakes[s] = stakes[stakeholders[s]].sub(_expired_stakes);
           user_address[s]= stakeholders[s];
       }
      return (user_address,eligible_stakes);
   }

    function get_all_user_stakes() external view returns (address [] memory, uint256 [7][] memory,uint256 [7][] memory)
   {
       uint256[7][] memory all_user_stakes = new uint256[7][](stakeholders.length);
       uint256[7][] memory all_user_eligible_stakes = new uint256[7][](stakeholders.length);
       address [] memory user_address = new address[](stakeholders.length);
       for (uint256 s = 0; s < stakeholders.length; s += 1){
           all_user_stakes[s] = [user_stake[stakeholders[s]][0].locked_amount,user_stake[stakeholders[s]][1].locked_amount,user_stake[stakeholders[s]][2].locked_amount,user_stake[stakeholders[s]][3].locked_amount,user_stake[stakeholders[s]][4].locked_amount,user_stake[stakeholders[s]][5].locked_amount,user_stake[stakeholders[s]][6].locked_amount];
           user_address[s]= stakeholders[s];
           for(uint k=0;k<7;k+=1){
               if(user_stake[stakeholders[s]][k].expire > block.timestamp ) {
                 all_user_eligible_stakes[s][k]=user_stake[stakeholders[s]][k].locked_amount;
               } else {
                 all_user_eligible_stakes[s][k]=0;  
               }
           }
       }
      return (user_address,all_user_stakes,all_user_eligible_stakes);
   }

   function expired_stakes (address _stakeholder) public view returns(uint256)
   {
       locked[7] storage user_stake_info = user_stake[_stakeholder];
        uint256 expired_amount=0;
        for (uint256 s = 0; s < 7; s += 1){
             if (user_stake_info[s].expire < block.timestamp) {
                 expired_amount = expired_amount.add(user_stake_info[s].locked_amount);
             }
        }
        return expired_amount;
   }    


    function enter_stake(uint256 _amount ,uint256 _days) external {

        require(_days ==30||_days==60||_days==90||_days==180||_days==365||_days==540||_days==730,"number of days should be among 30,60,90,180,365,540,730");
        if(stakes[msg.sender] == 0) addStakeholder(msg.sender);
       stakes[msg.sender] = stakes[msg.sender].add(_amount);

        locked[7] storage user_stake_info = user_stake[msg.sender];
        if (_days ==30) {
        user_stake_info[0].expire = block.timestamp + _TIMELOCK_30;
        user_stake_info[0].locked_amount = user_stake_info[0].locked_amount.add(_amount);
        } else if (_days ==60) {
        user_stake_info[1].expire = block.timestamp + _TIMELOCK_60;
        user_stake_info[1].locked_amount = user_stake_info[1].locked_amount.add(_amount);
        } else if (_days ==90) {
        user_stake_info[2].expire = block.timestamp + _TIMELOCK_90;
        user_stake_info[2].locked_amount = user_stake_info[2].locked_amount.add(_amount);
        } else if (_days ==180) {
        user_stake_info[3].expire = block.timestamp + _TIMELOCK_180;
        user_stake_info[3].locked_amount = user_stake_info[3].locked_amount.add(_amount);
        } else if (_days ==365) {
        user_stake_info[4].expire = block.timestamp + _TIMELOCK_365;
        user_stake_info[4].locked_amount = user_stake_info[4].locked_amount.add(_amount);
        } else if (_days ==540) {
        user_stake_info[5].expire = block.timestamp + _TIMELOCK_540;
        user_stake_info[5].locked_amount = user_stake_info[5].locked_amount.add(_amount);
        } else if (_days ==730) {
        user_stake_info[6].expire = block.timestamp + _TIMELOCK_730;
        user_stake_info[6].locked_amount = user_stake_info[6].locked_amount.add(_amount);
        }
        BOLLY.transferFrom(msg.sender, address(this), _amount);
        _mint(msg.sender, _amount);
        emit _enter_stake(_amount,msg.sender,_days);
    }

    function relock_stake(uint256 _days) external {
        (bool _isStakeholder, ) = isStakeholder(msg.sender);
        require(_isStakeholder==true, "only current stakeholders can relock stake");
        require(_days ==30||_days==60||_days==90||_days==180||_days==365||_days==540||_days==730,"number of days should be among 30,60,90,180,365,540,730");
        locked[7] storage user_stake_info = user_stake[msg.sender];
        uint256 expired_amount = expired_stakes(msg.sender);
        for (uint256 s = 0; s < 7; s += 1){
             if (user_stake_info[s].expire < block.timestamp) {
                 user_stake_info[s].locked_amount = 0;
             }
        }    
        if (_days ==30) {    
        user_stake_info[0].expire = block.timestamp + _TIMELOCK_30;
        user_stake_info[0].locked_amount = expired_amount;
        } else if (_days ==60) {
        user_stake_info[1].expire = block.timestamp + _TIMELOCK_60;
        user_stake_info[1].locked_amount = expired_amount;
        } else if (_days ==90) {
        user_stake_info[2].expire = block.timestamp + _TIMELOCK_90;
        user_stake_info[2].locked_amount = expired_amount;
        } else if (_days ==180) {
        user_stake_info[3].expire = block.timestamp + _TIMELOCK_180;
        user_stake_info[3].locked_amount = expired_amount;
        } else if (_days ==365) {
        user_stake_info[4].expire = block.timestamp + _TIMELOCK_365;
        user_stake_info[4].locked_amount = expired_amount;
        } else if (_days ==540) {
        user_stake_info[5].expire = block.timestamp + _TIMELOCK_540;
        user_stake_info[5].locked_amount = expired_amount;
        } else if (_days ==730) {
        user_stake_info[6].expire = block.timestamp + _TIMELOCK_730;
        user_stake_info[6].locked_amount = expired_amount;
        }
        emit _relock_stake(msg.sender,_days,expired_amount);
    }



    function remove_stake() external {
        locked[7] storage user_stake_info = user_stake[msg.sender];
        uint256 expired_amount = expired_stakes(msg.sender);
        require( (expired_amount>0) ,"Please wait until some stakes are expired");
        _burn(msg.sender,expired_amount );
         for (uint256 s = 0; s < 7; s += 1){
             if (user_stake_info[s].expire < block.timestamp) {
                 user_stake_info[s].locked_amount = 0;
             }
        }
         stakes[msg.sender] = stakes[msg.sender].sub(expired_amount);
       if(stakes[msg.sender] == 0) removeStakeholder(msg.sender);
        BOLLY.transfer(msg.sender, expired_amount);
        emit _remove_stake(expired_amount,msg.sender);
    }

    function emergency_remove_stake(address _user) external onlyOwner{
        locked[7] storage user_stake_info = user_stake[_user];
        uint256 locked_amount = stakeOf(_user);
        require( (locked_amount>0) ,"Please wait until some stakes are expired");
        _burn(_user,locked_amount);
         for (uint256 s = 0; s < 7; s += 1){
                 user_stake_info[s].locked_amount = 0;
        }
         stakes[_user] = stakes[_user].sub(locked_amount);
       if(stakes[_user] == 0) removeStakeholder(_user);
        BOLLY.transfer(_user, locked_amount);
        emit _remove_stake(locked_amount,_user);
    }


    event _set_owner(address _owner, address _from) ;    
    event _enter_stake(uint256 _amount, address _stake_from, uint256 _days);
    event _relock_stake(address stake_from,uint256 _days, uint256 _expired_amount);
    event _remove_stake(uint256 _amount,address _stake_to); 
}

pragma solidity ^0.6.0;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "@openzeppelin/contracts/token/ERC20/ERC20.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "./utils/OwnablePausable.sol";
import "./uniswap/IUniswapV2Router02.sol";
import "./uniswap/IUniswapAnchoredView.sol";

contract Market is OwnablePausable {
    using SafeMath for uint256;
    using SafeERC20 for ERC20;

    uint256 public constant PRICE_DECIMALS = 6;

    uint256 public constant REWARD_DECIMALS = 12;


    ERC20 public cumulative;


    ERC20 public productToken;


    ERC20 public rewardToken;


    IUniswapV2Router02 public uniswapRouter;


    IUniswapAnchoredView public priceOracle;


    mapping(address => string) internal allowedTokens;


    event PriceOracleChanged(address newPriceOracle);


    event UniswapRouterChanged(address newUniswapRouter);


    event CumulativeChanged(address newToken);


    event TokenAllowed(address token, string symbol);


    event TokenDenied(address token);


    event Buy(address customer, address token, uint256 amount, uint256 buy, uint256 reward);


    event Withdrawal(address recipient, address token, uint256 amount);


    constructor(
        address _cumulative,
        address _productToken,
        address _rewardToken,
        address _uniswapRouter,
        address _priceOracle
    ) public {
        cumulative = ERC20(_cumulative);
        productToken = ERC20(_productToken);
        rewardToken = ERC20(_rewardToken);
        uniswapRouter = IUniswapV2Router02(_uniswapRouter);
        priceOracle = IUniswapAnchoredView(_priceOracle);
    }


    function changeUniswapRouter(address _uniswapRouter) external onlyOwner {
        uniswapRouter = IUniswapV2Router02(_uniswapRouter);
        emit UniswapRouterChanged(_uniswapRouter);
    }


    function changePriceOracle(address _priceOracle) external onlyOwner {
        priceOracle = IUniswapAnchoredView(_priceOracle);
        emit PriceOracleChanged(_priceOracle);
    }


    function changeCumulativeToken(address newToken, address recipient) external onlyOwner {
        withdraw(recipient);
        cumulative = ERC20(newToken);
        emit CumulativeChanged(newToken);
    }


    function allowToken(address token, string calldata symbol) external onlyOwner {
        allowedTokens[token] = symbol;
        emit TokenAllowed(token, symbol);
    }


    function denyToken(address token) external onlyOwner {
        allowedTokens[token] = "";
        emit TokenDenied(token);
    }


    function isAllowedToken(address token) public view returns (bool) {
        return bytes(allowedTokens[token]).length != 0;
    }


    function transfer(
        ERC20 from,
        address recipient,
        uint256 amount
    ) internal {
        require(recipient != address(0), "Market::transfer: cannot transfer to the zero address");

        uint256 currentBalance = from.balanceOf(address(this));
        require(amount <= currentBalance, "Market::transfer: not enough tokens");

        from.safeTransfer(recipient, amount);
    }


    function transferProductToken(address recipient, uint256 amount) external onlyOwner {
        transfer(productToken, recipient, amount);
    }


    function transferRewardToken(address recipient, uint256 amount) external onlyOwner {
        transfer(rewardToken, recipient, amount);
    }



    function price(address currency, uint256 payment) public view returns (uint256 product, uint256 reward) {
        require(isAllowedToken(currency), "Market::price: currency not allowed");

        uint256 tokenDecimals = ERC20(currency).decimals();
        uint256 productDecimals = productToken.decimals();
        uint256 tokenPrice = priceOracle.price(allowedTokens[currency]);
        uint256 cumulativePrice = priceOracle.price(cumulative.symbol());

        product = payment.mul(10**productDecimals.sub(tokenDecimals));
        if (address(productToken) != currency) {
            product = tokenPrice.mul(10**PRICE_DECIMALS).div(cumulativePrice).mul(payment).div(10**PRICE_DECIMALS).mul(10**productDecimals.sub(tokenDecimals));
        }

        uint256 productTokenBalance = productToken.balanceOf(address(this));
        if (productTokenBalance > 0) {
            uint256 rewardTokenBalance = rewardToken.balanceOf(address(this));
            reward = product.mul(10**REWARD_DECIMALS).div(productTokenBalance).mul(rewardTokenBalance).div(10**REWARD_DECIMALS);
        }
    }


    function _path(address currency) internal view returns (address[] memory) {
        address weth = uniswapRouter.WETH();
        if (weth == currency) {
            address[] memory path = new address[](2);
            path[0] = currency;
            path[1] = address(cumulative);
            return path;
        }

        address[] memory path = new address[](3);
        path[0] = currency;
        path[1] = weth;
        path[2] = address(cumulative);
        return path;
    }


    function _amountOut(address currency, uint256 payment) internal view returns (uint256) {
        uint256[] memory amountsOut = uniswapRouter.getAmountsOut(payment, _path(currency));
        require(amountsOut.length != 0, "Market::_amountOut: invalid amounts out length");

        return amountsOut[amountsOut.length - 1];
    }


    function buy(address currency, uint256 payment) external whenNotPaused returns (bool) {
        (uint256 product, uint256 reward) = price(currency, payment);
        uint256 productTokenBalance = productToken.balanceOf(address(this));
        require(productTokenBalance > 0 && product <= productTokenBalance, "Market::buy: exceeds balance");

        ERC20(currency).safeTransferFrom(_msgSender(), address(this), payment);

        if (currency != address(cumulative)) {
            uint256 amountOut = _amountOut(currency, payment);
            require(amountOut != 0, "Market::buy: liquidity pool is empty");

            ERC20(currency).safeApprove(address(uniswapRouter), payment);
            uniswapRouter.swapExactTokensForTokens(payment, amountOut, _path(currency), address(this), block.timestamp);
        }

        productToken.safeTransfer(_msgSender(), product);
        if (reward > 0) {
            rewardToken.safeTransfer(_msgSender(), reward);
        }
        emit Buy(_msgSender(), currency, payment, product, reward);

        return true;
    }


    function buyFromETH() external payable whenNotPaused returns (bool) {
        address currency = uniswapRouter.WETH();
        uint256 payment = msg.value;

        (uint256 product, uint256 reward) = price(currency, payment);
        uint256 productTokenBalance = productToken.balanceOf(address(this));
        require(product <= productTokenBalance, "Market::buyFromETH: balance is empty");

        if (currency != address(cumulative)) {
            uint256 amountOut = _amountOut(currency, payment);
            require(amountOut != 0, "Market::buyFromETH: liquidity pool is empty");

            uniswapRouter.swapExactETHForTokens{value: payment}(amountOut, _path(currency), address(this), block.timestamp);
        }

        productToken.safeTransfer(_msgSender(), product);
        if (reward > 0) {
            rewardToken.safeTransfer(_msgSender(), reward);
        }
        emit Buy(_msgSender(), currency, payment, product, reward);

        return true;
    }


    function withdraw(address recipient) public onlyOwner {
        require(recipient != address(0), "Market::withdraw: cannot transfer to the zero address");

        uint256 balance = cumulative.balanceOf(address(this));
        cumulative.safeTransfer(recipient, balance);

        emit Withdrawal(recipient, address(cumulative), balance);
    }
}

pragma solidity ^0.6.0;

import "@openzeppelin/contracts/math/SafeMath.sol";
import "../utils/OwnablePausable.sol";
import "./IDepositaryBalanceView.sol";

contract AgregateDepositaryBalanceView is IDepositaryBalanceView, OwnablePausable {
    using SafeMath for uint256;


    uint256 public maxSize;


    uint256 public override decimals;


    IDepositaryBalanceView[] public depositaries;


    mapping(address => uint256) internal depositariesIndex;


    event DepositaryAdded(address depositary);


    event DepositaryRemoved(address depositary);


    constructor(uint256 _decimals, uint256 _maxSize) public {
        decimals = _decimals;
        maxSize = _maxSize;
    }


    function size() public view returns (uint256) {
        return depositaries.length;
    }



    function addDepositary(address depositary) external onlyOwner {
        require(depositariesIndex[depositary] == 0, "AgregateDepositaryBalanceView::addDepositary: depositary already added");
        require(size() < maxSize, "AgregateDepositaryBalanceView::addDepositary: too many depositaries");

        depositaries.push(IDepositaryBalanceView(depositary));
        depositariesIndex[depositary] = size().sub(1);
        emit DepositaryAdded(depositary);
    }


    function removeDepositary(address depositary) external onlyOwner {
        uint256 depositaryIndex = depositariesIndex[depositary];
        require(depositaryIndex != 0, "AgregateDepositaryBalanceView::removeDepositary: depositary already removed");

        delete depositariesIndex[depositary];
        depositaries[depositaryIndex] = depositaries[size().sub(1)];
        delete depositaries[size().sub(1)];
        emit DepositaryRemoved(depositary);
    }


    function allowedDepositaries() external view returns (address[] memory) {
        address[] memory result = new address[](size());

        for (uint256 i = 0; i < size(); i++) {
            result[i] = address(depositaries[i]);
        }

        return result;
    }

    function balance() external view override returns (uint256) {
        uint256 result;

        for (uint256 i = 0; i < size(); i++) {
            uint256 depositaryBalance = depositaries[i].balance();
            uint256 depositaryDecimals = depositaries[i].decimals();
            uint256 decimalsPower = decimals.sub(depositaryDecimals);
            result = result.add(depositaryBalance.mul(10**decimalsPower));
        }

        return result;
    }
}

