pragma solidity 0.6.12;

import "./BToken.sol";
import "./BMath.sol";
import "../interfaces/IPoolRestrictions.sol";
import "../interfaces/BPoolInterface.sol";
import "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";

contract BPool is BToken, BMath, BPoolInterface {
    using SafeERC20 for IERC20;

    struct Record {
        bool bound;   
        uint index;   
        uint denorm;  
        uint balance;
    }




    event LOG_SWAP(
        address indexed caller,
        address indexed tokenIn,
        address indexed tokenOut,
        uint256         tokenAmountIn,
        uint256         tokenAmountOut
    );


    event LOG_JOIN(
        address indexed caller,
        address indexed tokenIn,
        uint256         tokenAmountIn
    );


    event LOG_EXIT(
        address indexed caller,
        address indexed tokenOut,
        uint256         tokenAmountOut
    );


    event LOG_CALL(
        bytes4  indexed sig,
        address indexed caller,
        bytes           data
    ) anonymous;


    event LOG_CALL_VOTING(
        address indexed voting,
        bool    indexed success,
        bytes4  indexed inputSig,
        bytes           inputData,
        bytes           outputData
    );


    event LOG_COMMUNITY_FEE(
        address indexed caller,
        address indexed receiver,
        address indexed token,
        uint256         tokenAmount
    );



    modifier _logs_() {
        emit LOG_CALL(msg.sig, msg.sender, msg.data);
        _;
    }

    modifier _lock_() {
        _preventReentrancy();
        _mutex = true;
        _;
        _mutex = false;
    }

    modifier _viewlock_() {
        _preventReentrancy();
        _;
    }



    bool private _mutex;





    address internal _controller;


    bool private _swapsDisabled;



    address private _wrapper;


    bool private _wrapperMode;



    IPoolRestrictions private _restrictions;


    uint private _swapFee;


    uint private _communitySwapFee;
    uint private _communityJoinFee;
    uint private _communityExitFee;



    address private _communityFeeReceiver;


    bool private _finalized;


    address[] internal _tokens;

    mapping(address => Record) internal _records;

    uint internal _totalWeight;


    mapping(address => uint256) internal _lastSwapBlock;

    constructor(string memory name, string memory symbol) public {
        _name = name;
        _symbol = symbol;
        _controller = msg.sender;
        _swapFee = MIN_FEE;
        _communitySwapFee = 0;
        _communityJoinFee = 0;
        _communityExitFee = 0;
        _swapsDisabled = false;
        _finalized = false;
    }




    function isBound(address t)
        external view override
        returns (bool)
    {
        return _records[t].bound;
    }


    function getNumTokens()
        external view
        returns (uint)
    {
        return _tokens.length;
    }


    function getCurrentTokens()
        external view override
        _viewlock_
        returns (address[] memory tokens)
    {
