pragma solidity 0.6.12;
pragma experimental ABIEncoderV2;

import {BaseStrategy} from "@yearnvaults/contracts/BaseStrategy.sol";
import "@openzeppelin/contracts/math/Math.sol";
import {
    SafeERC20,
    SafeMath,
    IERC20,
    Address
} from "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";

import "./libraries/MakerDaiDelegateLib.sol";

import "../interfaces/chainlink/AggregatorInterface.sol";
import "../interfaces/swap/ISwap.sol";
import "../interfaces/yearn/IOSMedianizer.sol";
import "../interfaces/yearn/IVault.sol";

contract Strategy is BaseStrategy {
    using SafeERC20 for IERC20;
    using Address for address;
    using SafeMath for uint256;


    uint256 internal constant WAD = 10**18;
    uint256 internal constant RAY = 10**27;


    IERC20 internal constant investmentToken =
        IERC20(0x6B175474E89094C44Da98b954EedeAC495271d0F);


    uint256 internal constant MAX_BPS = WAD;


    uint256 internal constant MAX_LOSS_BPS = 10000;


    address internal constant WETH = 0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2;


    ISwap internal constant sushiswapRouter =
        ISwap(0xd9e1cE17f2641f24aE83637ab66a2cca9C378B9F);


    ISwap internal constant uniswapRouter =
        ISwap(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D);


    address public gemJoinAdapter;


    IOSMedianizer public wantToUSDOSMProxy;


    AggregatorInterface public chainlinkWantToETHPriceFeed;


    AggregatorInterface public chainlinkWantToUSDPriceFeed;


    IVault public yVault;


    ISwap public router;


    bytes32 public ilk;


    uint256 public cdpId;


    uint256 public collateralizationRatio;


    uint256 public rebalanceTolerance;


    uint256 public maxLoss;


    bool public leaveDebtBehind;


    string internal strategyName;



    constructor(
        address _vault,
        address _yVault,
        string memory _strategyName,
        bytes32 _ilk,
        address _gemJoin,
        address _wantToUSDOSMProxy,
        address _chainlinkWantToUSDPriceFeed,
        address _chainlinkWantToETHPriceFeed
    ) public BaseStrategy(_vault) {
        _initializeThis(
            _yVault,
            _strategyName,
            _ilk,
            _gemJoin,
            _wantToUSDOSMProxy,
            _chainlinkWantToUSDPriceFeed,
            _chainlinkWantToETHPriceFeed
        );
    }

    function initialize(
        address _vault,
        address _yVault,
        string memory _strategyName,
        bytes32 _ilk,
        address _gemJoin,
        address _wantToUSDOSMProxy,
        address _chainlinkWantToUSDPriceFeed,
        address _chainlinkWantToETHPriceFeed
    ) public {

        require(address(yVault) == address(0)); 

        address sender = msg.sender;


        _initialize(_vault, sender, sender, sender);


        _initializeThis(
            _yVault,
            _strategyName,
            _ilk,
            _gemJoin,
            _wantToUSDOSMProxy,
            _chainlinkWantToUSDPriceFeed,
            _chainlinkWantToETHPriceFeed
        );
    }

    function _initializeThis(
        address _yVault,
        string memory _strategyName,
        bytes32 _ilk,
        address _gemJoin,
        address _wantToUSDOSMProxy,
        address _chainlinkWantToUSDPriceFeed,
        address _chainlinkWantToETHPriceFeed
    ) internal {
        yVault = IVault(_yVault);
        strategyName = _strategyName;
        ilk = _ilk;
        gemJoinAdapter = _gemJoin;
        wantToUSDOSMProxy = IOSMedianizer(_wantToUSDOSMProxy);
        chainlinkWantToUSDPriceFeed = AggregatorInterface(
            _chainlinkWantToUSDPriceFeed
        );
        chainlinkWantToETHPriceFeed = AggregatorInterface(
            _chainlinkWantToETHPriceFeed
        );


        router = sushiswapRouter;


        healthCheck = 0xDDCea799fF1699e98EDF118e0629A974Df7DF012;

        cdpId = MakerDaiDelegateLib.openCdp(ilk);
        require(cdpId > 0); 



        rebalanceTolerance = (15 * MAX_BPS) / 100;



        collateralizationRatio = (225 * MAX_BPS) / 100;


        leaveDebtBehind = true;


        maxLoss = 1;
    }




    function setCollateralizationRatio(uint256 _collateralizationRatio)
        external
        onlyEmergencyAuthorized
    {
        require(
            _collateralizationRatio.sub(rebalanceTolerance) >
                MakerDaiDelegateLib.getLiquidationRatio(ilk).mul(MAX_BPS).div(
                    RAY
                )
        ); 
        collateralizationRatio = _collateralizationRatio;
    }


    function setRebalanceTolerance(uint256 _rebalanceTolerance)
        external
        onlyEmergencyAuthorized
    {
        require(
            collateralizationRatio.sub(_rebalanceTolerance) >
                MakerDaiDelegateLib.getLiquidationRatio(ilk).mul(MAX_BPS).div(
                    RAY
                )
        ); 
        rebalanceTolerance = _rebalanceTolerance;
    }


    function setMaxLoss(uint256 _maxLoss) external onlyVaultManagers {
        require(_maxLoss <= MAX_LOSS_BPS); 
        maxLoss = _maxLoss;
    }


    function setLeaveDebtBehind(bool _leaveDebtBehind)
        external
        onlyEmergencyAuthorized
    {
        leaveDebtBehind = _leaveDebtBehind;
    }



    function shiftToCdp(uint256 newCdpId) external onlyGovernance {
        MakerDaiDelegateLib.shiftCdp(cdpId, newCdpId);
        cdpId = newCdpId;
    }


    function migrateToNewDaiYVault(IVault newYVault) external onlyGovernance {
        uint256 balanceOfYVault = yVault.balanceOf(address(this));
        if (balanceOfYVault > 0) {
            yVault.withdraw(balanceOfYVault, address(this), maxLoss);
        }
        investmentToken.safeApprove(address(yVault), 0);

        yVault = newYVault;
        _depositInvestmentTokenInYVault();
    }


    function grantCdpManagingRightsToUser(address user, bool allow)
        external
        onlyGovernance
    {
        MakerDaiDelegateLib.allowManagingCdp(cdpId, user, allow);
    }


    function switchDex(bool isUniswap) external onlyVaultManagers {
        if (isUniswap) {
            router = uniswapRouter;
        } else {
            router = sushiswapRouter;
        }
    }



    function name() external view override returns (string memory) {
        return strategyName;
    }

    function delegatedAssets() external view override returns (uint256) {
        return _convertInvestmentTokenToWant(_valueOfInvestment());
    }

    function estimatedTotalAssets() public view override returns (uint256) {
        return
            balanceOfWant()
                .add(balanceOfMakerVault())
                .add(_convertInvestmentTokenToWant(balanceOfInvestmentToken()))
                .add(_convertInvestmentTokenToWant(_valueOfInvestment()))
                .sub(_convertInvestmentTokenToWant(balanceOfDebt()));
    }

    function prepareReturn(uint256 _debtOutstanding)
        internal
        override
        returns (
            uint256 _profit,
            uint256 _loss,
            uint256 _debtPayment
        )
    {
        uint256 totalDebt = vault.strategies(address(this)).totalDebt;


        _takeYVaultProfit();

        uint256 totalAssetsAfterProfit = estimatedTotalAssets();

        _profit = totalAssetsAfterProfit > totalDebt
            ? totalAssetsAfterProfit.sub(totalDebt)
            : 0;

        uint256 _amountFreed;
        (_amountFreed, _loss) = liquidatePosition(
            _debtOutstanding.add(_profit)
        );
        _debtPayment = Math.min(_debtOutstanding, _amountFreed);

        if (_loss > _profit) {




            _loss = _loss.sub(_profit);
            _profit = 0;
        } else {




            _profit = _profit.sub(_loss);
            _loss = 0;
        }
    }

    function adjustPosition(uint256 _debtOutstanding) internal override {
        MakerDaiDelegateLib.keepBasicMakerHygiene(ilk);



        uint256 wantBalance = balanceOfWant();
        if (wantBalance > _debtOutstanding) {
            uint256 amountToDeposit = wantBalance.sub(_debtOutstanding);
            _depositToMakerVault(amountToDeposit);
        }


        uint256 currentRatio = getCurrentMakerVaultRatio();
        if (currentRatio < collateralizationRatio.sub(rebalanceTolerance)) {
            _repayDebt(currentRatio);
        } else if (
            currentRatio > collateralizationRatio.add(rebalanceTolerance)
        ) {
            _mintMoreInvestmentToken();
        }


        _depositInvestmentTokenInYVault();
    }

    function liquidatePosition(uint256 _amountNeeded)
        internal
        override
        returns (uint256 _liquidatedAmount, uint256 _loss)
    {
        uint256 balance = balanceOfWant();


        if (balance >= _amountNeeded) {
            return (_amountNeeded, 0);
        }


        uint256 amountToFree = _amountNeeded.sub(balance);

        uint256 price = _getWantTokenPrice();
        uint256 collateralBalance = balanceOfMakerVault();


        amountToFree = Math.min(amountToFree, collateralBalance);

        uint256 totalDebt = balanceOfDebt();


        if (totalDebt == 0) {
            totalDebt = 1;
        }

        uint256 toFreeIT = amountToFree.mul(price).div(WAD);
        uint256 collateralIT = collateralBalance.mul(price).div(WAD);
        uint256 newRatio =
            collateralIT.sub(toFreeIT).mul(MAX_BPS).div(totalDebt);


        _repayDebt(newRatio);


        amountToFree = Math.min(amountToFree, _maxWithdrawal());
        _freeCollateralAndRepayDai(amountToFree, 0);


        if (
            !leaveDebtBehind &&
            balanceOfWant() < _amountNeeded &&
            balanceOfDebt() > 0
        ) {
            _sellCollateralToRepayRemainingDebtIfNeeded();
        }

        uint256 looseWant = balanceOfWant();
        if (_amountNeeded > looseWant) {
            _liquidatedAmount = looseWant;
            _loss = _amountNeeded.sub(looseWant);
        } else {
            _liquidatedAmount = _amountNeeded;
            _loss = 0;
        }
    }

    function liquidateAllPositions()
        internal
        override
        returns (uint256 _amountFreed)
    {
        (_amountFreed, ) = liquidatePosition(estimatedTotalAssets());
    }

    function tendTrigger(uint256 callCostInWei)
        public
        view
        override
        returns (bool)
    {

        if (balanceOfMakerVault() == 0) {
            return false;
        }

        uint256 currentRatio = getCurrentMakerVaultRatio();



        if (currentRatio < collateralizationRatio.sub(rebalanceTolerance)) {
            return true;
        }



        return
            (currentRatio > collateralizationRatio.add(rebalanceTolerance)) &&
            MakerDaiDelegateLib.isDaiAvailableToMint(ilk);
    }

    function prepareMigration(address _newStrategy) internal override {

        MakerDaiDelegateLib.transferCdp(cdpId, _newStrategy);


        IERC20(yVault).safeTransfer(
            _newStrategy,
            yVault.balanceOf(address(this))
        );
    }

    function protectedTokens()
        internal
        view
        override
        returns (address[] memory)
    {
        address[] memory protected = new address[](2);
        protected[0] = address(investmentToken);
        protected[1] = address(yVault);
        return protected;
    }

    function ethToWant(uint256 _amtInWei)
        public
        view
        virtual
        override
        returns (uint256)
    {
        if (address(want) == address(WETH)) {
            return _amtInWei;
        }

        uint256 price = uint256(chainlinkWantToETHPriceFeed.latestAnswer());
        return _amtInWei.mul(WAD).div(price);
    }



    function _repayDebt(uint256 currentRatio) internal {
        uint256 currentDebt = balanceOfDebt();



        if (currentRatio > collateralizationRatio || currentDebt == 0) {
            return;
        }







        uint256 newDebt =
            currentDebt.mul(currentRatio).div(collateralizationRatio);

        uint256 amountToRepay;




        uint256 debtFloor = MakerDaiDelegateLib.debtFloor(ilk);
        if (newDebt <= debtFloor) {


            uint256 totalInvestmentAvailableToRepay =
                _valueOfInvestment().add(balanceOfInvestmentToken());

            if (totalInvestmentAvailableToRepay >= currentDebt) {

                amountToRepay = currentDebt;
            } else {

                amountToRepay = currentDebt.sub(debtFloor).sub(1e15);
            }
        } else {


            amountToRepay = currentDebt.sub(newDebt);
        }

        uint256 balanceIT = balanceOfInvestmentToken();
        if (amountToRepay > balanceIT) {
            _withdrawFromYVault(amountToRepay.sub(balanceIT));
        }
        _repayInvestmentTokenDebt(amountToRepay);
    }

    function _sellCollateralToRepayRemainingDebtIfNeeded() internal {
        uint256 currentInvestmentValue = _valueOfInvestment();

        uint256 investmentLeftToAcquire =
            balanceOfDebt().sub(currentInvestmentValue);

        uint256 investmentLeftToAcquireInWant =
            _convertInvestmentTokenToWant(investmentLeftToAcquire);

        if (investmentLeftToAcquireInWant <= balanceOfWant()) {
            _buyInvestmentTokenWithWant(investmentLeftToAcquire);
            _repayDebt(0);
            _freeCollateralAndRepayDai(balanceOfMakerVault(), 0);
        }
    }


    function _mintMoreInvestmentToken() internal {
        uint256 price = _getWantTokenPrice();
        uint256 amount = balanceOfMakerVault();

        uint256 daiToMint =
            amount.mul(price).mul(MAX_BPS).div(collateralizationRatio).div(WAD);
        daiToMint = daiToMint.sub(balanceOfDebt());
        _lockCollateralAndMintDai(0, daiToMint);
    }

    function _withdrawFromYVault(uint256 _amountIT) internal returns (uint256) {
        if (_amountIT == 0) {
            return 0;
        }

        uint256 balancePrior = balanceOfInvestmentToken();
        uint256 sharesToWithdraw =
            Math.min(
                _investmentTokenToYShares(_amountIT),
                yVault.balanceOf(address(this))
            );
        if (sharesToWithdraw == 0) {
            return 0;
        }
        yVault.withdraw(sharesToWithdraw, address(this), maxLoss);
        return balanceOfInvestmentToken().sub(balancePrior);
    }

    function _depositInvestmentTokenInYVault() internal {
        uint256 balanceIT = balanceOfInvestmentToken();
        if (balanceIT > 0) {
            _checkAllowance(
                address(yVault),
                address(investmentToken),
                balanceIT
            );

            yVault.deposit();
        }
    }

    function _repayInvestmentTokenDebt(uint256 amount) internal {
        if (amount == 0) {
            return;
        }

        uint256 debt = balanceOfDebt();
        uint256 balanceIT = balanceOfInvestmentToken();


        amount = Math.min(amount, balanceIT);


        amount = Math.min(amount, debt);

        _checkAllowance(
            MakerDaiDelegateLib.daiJoinAddress(),
            address(investmentToken),
            amount
        );

        if (amount > 0) {






            if (debt.sub(amount) == 0 && balanceIT.sub(amount) >= 1) {
                amount = amount.add(1);
            }


            _freeCollateralAndRepayDai(0, amount);
        }
    }

    function _checkAllowance(
        address _contract,
        address _token,
        uint256 _amount
    ) internal {
        if (IERC20(_token).allowance(address(this), _contract) < _amount) {
            IERC20(_token).safeApprove(_contract, 0);
            IERC20(_token).safeApprove(_contract, type(uint256).max);
        }
    }

    function _takeYVaultProfit() internal {
        uint256 _debt = balanceOfDebt();
        uint256 _valueInVault = _valueOfInvestment();
        if (_debt >= _valueInVault) {
            return;
        }

        uint256 profit = _valueInVault.sub(_debt);
        uint256 ySharesToWithdraw = _investmentTokenToYShares(profit);
        if (ySharesToWithdraw > 0) {
            yVault.withdraw(ySharesToWithdraw, address(this), maxLoss);
            _sellAForB(
                balanceOfInvestmentToken(),
                address(investmentToken),
                address(want)
            );
        }
    }

    function _depositToMakerVault(uint256 amount) internal {
        if (amount == 0) {
            return;
        }

        _checkAllowance(gemJoinAdapter, address(want), amount);

        uint256 price = _getWantTokenPrice();
        uint256 daiToMint =
            amount.mul(price).mul(MAX_BPS).div(collateralizationRatio).div(WAD);

        _lockCollateralAndMintDai(amount, daiToMint);
    }


    function _maxWithdrawal() internal view returns (uint256) {

        uint256 totalCollateral = balanceOfMakerVault();


        uint256 totalDebt = balanceOfDebt();


        if (totalDebt == 0) {
            return totalCollateral;
        }

        uint256 price = _getWantTokenPrice();



        uint256 minCollateral =
            collateralizationRatio
                .sub(rebalanceTolerance)
                .mul(totalDebt)
                .mul(WAD)
                .div(price)
                .div(MAX_BPS);


        if (minCollateral > totalCollateral) {
            return 0;
        }

        return totalCollateral.sub(minCollateral);
    }



    function balanceOfWant() public view returns (uint256) {
        return want.balanceOf(address(this));
    }

    function balanceOfInvestmentToken() public view returns (uint256) {
        return investmentToken.balanceOf(address(this));
    }

    function balanceOfDebt() public view returns (uint256) {
        return MakerDaiDelegateLib.debtForCdp(cdpId, ilk);
    }


    function balanceOfMakerVault() public view returns (uint256) {
        return MakerDaiDelegateLib.balanceOfCdp(cdpId, ilk);
    }


    function getCurrentMakerVaultRatio() public view returns (uint256) {
        return
            MakerDaiDelegateLib.getPessimisticRatioOfCdpWithExternalPrice(
                cdpId,
                ilk,
                _getWantTokenPrice(),
                MAX_BPS
            );
    }



    function _getWantTokenPrice() internal view returns (uint256) {
        uint256 minPrice;


        (uint256 current, ) = wantToUSDOSMProxy.read();
        (uint256 future, ) = wantToUSDOSMProxy.foresight();

        minPrice = Math.min(future, current);


        uint256 chainLinkPrice =
            uint256(chainlinkWantToUSDPriceFeed.latestAnswer()).mul(1e10);




        minPrice = Math.min(minPrice, chainLinkPrice).mul(RAY).div(
            MakerDaiDelegateLib.getDaiPar()
        );



        require(minPrice > 0); 
        return minPrice;
    }

    function _valueOfInvestment() internal view returns (uint256) {
        return
            yVault.balanceOf(address(this)).mul(yVault.pricePerShare()).div(
                10**yVault.decimals()
            );
    }

    function _investmentTokenToYShares(uint256 amount)
        internal
        view
        returns (uint256)
    {
        return amount.mul(10**yVault.decimals()).div(yVault.pricePerShare());
    }

    function _lockCollateralAndMintDai(
        uint256 collateralAmount,
        uint256 daiToMint
    ) internal {
        MakerDaiDelegateLib.lockGemAndDraw(
            gemJoinAdapter,
            cdpId,
            collateralAmount,
            daiToMint,
            balanceOfDebt()
        );
    }

    function _freeCollateralAndRepayDai(
        uint256 collateralAmount,
        uint256 daiToRepay
    ) internal {
        MakerDaiDelegateLib.wipeAndFreeGem(
            gemJoinAdapter,
            cdpId,
            collateralAmount,
            daiToRepay
        );
    }



    function _convertInvestmentTokenToWant(uint256 amount)
        internal
        view
        returns (uint256)
    {
        return amount.mul(WAD).div(_getWantTokenPrice());
    }

    function _getTokenOutPath(address _token_in, address _token_out)
        internal
        pure
        returns (address[] memory _path)
    {
        bool is_weth =
            _token_in == address(WETH) || _token_out == address(WETH);
        _path = new address[](is_weth ? 2 : 3);
        _path[0] = _token_in;

        if (is_weth) {
            _path[1] = _token_out;
        } else {
            _path[1] = address(WETH);
            _path[2] = _token_out;
        }
    }

    function _sellAForB(
        uint256 _amount,
        address tokenA,
        address tokenB
    ) internal {
        if (_amount == 0 || tokenA == tokenB) {
            return;
        }

        _checkAllowance(address(router), tokenA, _amount);
        router.swapExactTokensForTokens(
            _amount,
            0,
            _getTokenOutPath(tokenA, tokenB),
            address(this),
            now
        );
    }


    function _buyInvestmentTokenWithWant(uint256 _amount) internal {

        if (_amount == 0 || address(investmentToken) == address(want)) {
            return;
        }

        _checkAllowance(address(router), address(want), _amount);
        router.swapTokensForExactTokens(
            _amount,
            type(uint256).max,
            _getTokenOutPath(address(want), address(investmentToken)),
            address(this),
            now
        );
    }
}

pragma solidity 0.6.12;
pragma experimental ABIEncoderV2;

import {BaseStrategy, VaultAPI} from "@yearnvaults/contracts/BaseStrategy.sol";
import {
    SafeERC20,
    SafeMath,
    IERC20,
    Address
} from "@openzeppelin/contracts/token/ERC20/SafeERC20.sol";
import "@openzeppelin/contracts/math/Math.sol";

import "../interfaces/ISynthetix.sol";
import "../interfaces/IIssuer.sol";
import "../interfaces/IFeePool.sol";
import "../interfaces/IReadProxy.sol";
import "../interfaces/IAddressResolver.sol";
import "../interfaces/IExchangeRates.sol";
import "../interfaces/IRewardEscrowV2.sol";

import "../interfaces/IVault.sol";
import "../interfaces/ISushiRouter.sol";

contract Strategy is BaseStrategy {
    using SafeERC20 for IERC20;
    using Address for address;
    using SafeMath for uint256;

    uint256 public constant MIN_ISSUE = 50 * 1e18;
    uint256 public ratioThreshold = 1e15;
    uint256 public constant MAX_RATIO = type(uint256).max;
    uint256 public constant MAX_BPS = 10_000;

    address public constant susd =
        address(0x57Ab1ec28D129707052df4dF418D58a2D46d5f51);
    IReadProxy public constant readProxy =
        IReadProxy(address(0x4E3b31eB0E5CB73641EE1E65E7dCEFe520bA3ef2));
    address public constant WETH =
        address(0xC02aaA39b223FE8D0A0e5C4F27eAD9083C756Cc2);

    ISushiRouter public constant sushiswap =
        ISushiRouter(address(0xd9e1cE17f2641f24aE83637ab66a2cca9C378B9F));
    ISushiRouter public constant uniswap =
        ISushiRouter(address(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D));
    ISushiRouter public router =
        ISushiRouter(address(0x7a250d5630B4cF539739dF2C5dAcb4c659F2488D));

    uint256 public targetRatioMultiplier = 12_500;
    IVault public susdVault;


    uint256 public entryIDIndex = 0;

    uint256[] public entryIDs;

    bytes32 private constant CONTRACT_SYNTHETIX = "Synthetix";
    bytes32 private constant CONTRACT_EXRATES = "ExchangeRates";
    bytes32 private constant CONTRACT_REWARDESCROW_V2 = "RewardEscrowV2";
    bytes32 private constant CONTRACT_ISSUER = "Issuer";
    bytes32 private constant CONTRACT_FEEPOOL = "FeePool";



    event RepayDebt(uint256 repaidAmount, uint256 debtAfterRepayment);



    constructor(address _vault, address _susdVault)
        public
        BaseStrategy(_vault)
    {
        susdVault = IVault(_susdVault);


        maxReportDelay = 7 * 24 * 3600;


        IERC20(susd).safeApprove(address(_susdVault), type(uint256).max);

        IERC20(susd).safeApprove(address(uniswap), type(uint256).max);
        IERC20(susd).safeApprove(address(sushiswap), type(uint256).max);

        IERC20(want).safeApprove(address(uniswap), type(uint256).max);
        IERC20(want).safeApprove(address(sushiswap), type(uint256).max);
    }


    function setRouter(uint256 _isSushi) external onlyAuthorized {
        if (_isSushi == uint256(1)) {
            router = sushiswap;
        } else if (_isSushi == uint256(0)) {
            router = uniswap;
        } else {
            revert("!invalid-arg. Use 1 for sushi. 0 for uni");
        }
    }

    function setTargetRatioMultiplier(uint256 _targetRatioMultiplier) external {
        require(
            msg.sender == governance() ||
                msg.sender == VaultAPI(address(vault)).management()
        );
        targetRatioMultiplier = _targetRatioMultiplier;
    }

    function setRatioThreshold(uint256 _ratioThreshold)
        external
        onlyStrategist
    {
        ratioThreshold = _ratioThreshold;
    }


    function migrateSusdVault(IVault newSusdVault, uint256 maxLoss)
        external
        onlyGovernance
    {


        susdVault.withdraw(
            susdVault.balanceOf(address(this)),
            address(this),
            maxLoss
        );
        IERC20(susd).safeApprove(address(susdVault), 0);

        susdVault = newSusdVault;
        IERC20(susd).safeApprove(address(newSusdVault), type(uint256).max);
        newSusdVault.deposit();
    }



    function manuallyRepayDebt(uint256 amount) external onlyAuthorized {

        repayDebt(amount);
    }



    function name() external view override returns (string memory) {
        return "StrategySynthetixSusdMinter";
    }

    function estimatedTotalAssets() public view override returns (uint256) {
        uint256 totalAssets =
            balanceOfWant().add(estimatedProfit()).add(
                sUSDToWant(balanceOfSusdInVault().add(balanceOfSusd()))
            );
        uint256 totalLiabilities = sUSDToWant(balanceOfDebt());


        return
            totalAssets > totalLiabilities
                ? totalAssets.sub(totalLiabilities)
                : 0;
    }

    function prepareReturn(uint256 _debtOutstanding)
        internal
        override
        returns (
            uint256 _profit,
            uint256 _loss,
            uint256 _debtPayment
        )
    {
        uint256 totalDebt = vault.strategies(address(this)).totalDebt;

        claimProfits();
        vestNextRewardsEntry();

        uint256 totalAssetsAfterProfit = estimatedTotalAssets();

        _profit = totalAssetsAfterProfit > totalDebt
            ? totalAssetsAfterProfit.sub(totalDebt)
            : 0;


        if (_debtOutstanding > 0) {
            uint256 _amountFreed = 0;
            (_amountFreed, _loss) = liquidatePosition(_debtOutstanding);
            _debtPayment = Math.min(_debtOutstanding, _amountFreed);

            if (_loss > 0) {
                _profit = 0;
            }
        }
    }

    function adjustPosition(uint256 _debtOutstanding) internal override {
        if (emergencyExit) {
            return;
        }

        if (_debtOutstanding >= balanceOfWant()) {
            return;
        }


        uint256 _currentRatio = getCurrentRatio();

        uint256 _targetRatio = getTargetRatio();
        uint256 _issuanceRatio = getIssuanceRatio();



        if (
            _currentRatio > _targetRatio &&
            _currentRatio.sub(_targetRatio) >= ratioThreshold
        ) {



            uint256 _debtToRepay =
                balanceOfDebt().sub(getTargetDebt(_collateral()));
            repayDebt(_debtToRepay);
        } else if (
            _issuanceRatio > _currentRatio &&
            _issuanceRatio.sub(_currentRatio) >= ratioThreshold
        ) {



            uint256 _maxSynths = _synthetix().maxIssuableSynths(address(this));
            uint256 _debtBalance = balanceOfDebt();

            if (
                _maxSynths > _debtBalance &&
                _maxSynths.sub(_debtBalance) >= MIN_ISSUE
            ) {
                _synthetix().issueMaxSynths();
            }
        }



        if (balanceOfSusd() >= MIN_ISSUE) {
            susdVault.deposit();
        }
    }

    function liquidatePosition(uint256 _amountNeeded)
        internal
        override
        returns (uint256 _liquidatedAmount, uint256 _loss)
    {




        uint256 unlockedWant = _unlockedWant();
        if (unlockedWant < _amountNeeded) {

            reduceLockedCollateral(_amountNeeded.sub(unlockedWant));
        }




        unlockedWant = _unlockedWant();

        if (_amountNeeded > unlockedWant) {
            _liquidatedAmount = unlockedWant;
            _loss = _amountNeeded.sub(unlockedWant);
        } else {
            _liquidatedAmount = _amountNeeded;
        }
    }

    function prepareMigration(address _newStrategy) internal override {
        liquidatePosition(vault.strategies(address(this)).totalDebt);
    }



    function reduceLockedCollateral(uint256 amountToFree) internal {

        amountToFree = Math.min(amountToFree, _unlockableWant());

        if (amountToFree == 0) {
            return;
        }

        uint256 _currentDebt = balanceOfDebt();
        uint256 _newCollateral = _lockedCollateral().sub(amountToFree);
        uint256 _targetDebt = _newCollateral.mul(getIssuanceRatio()).div(1e18);

        uint256 _amountToRepay = _currentDebt.sub(_targetDebt);

        repayDebt(_amountToRepay);
    }

    function repayDebt(uint256 amountToRepay) internal {




        if (amountToRepay == 0) {
            return;
        }
        uint256 repaidAmount = 0;
        uint256 _debtBalance = balanceOfDebt();

        amountToRepay = Math.min(_debtBalance, amountToRepay);


        if (
            _debtBalance > amountToRepay &&
            _debtBalance.sub(amountToRepay) <= MIN_ISSUE
        ) {
            amountToRepay = _debtBalance;
        }

        uint256 currentSusdBalance = balanceOfSusd();
        if (amountToRepay > currentSusdBalance) {



            uint256 _withdrawAmount = amountToRepay.sub(currentSusdBalance);
            withdrawFromSUSDVault(_withdrawAmount);

            currentSusdBalance = balanceOfSusd();
            if (amountToRepay > currentSusdBalance) {







                if (currentSusdBalance > 0) {

                    if (burnSusd(currentSusdBalance)) {



                        repaidAmount = _debtBalance.sub(balanceOfDebt());
                    }
                }


                uint256 amountToBuy =
                    Math.min(
                        _getSusdForWant(_unlockedWant()),
                        amountToRepay.sub(repaidAmount)
                    );
                if (amountToBuy > 0) {
                    buySusdWithWant(amountToBuy);
                }

            }
        }


        if (amountToRepay > repaidAmount) {
            burnSusd(amountToRepay.sub(repaidAmount)); 
            repaidAmount = amountToRepay;
        }
        emit RepayDebt(repaidAmount, _debtBalance.sub(repaidAmount));
    }


    function claimProfits() internal returns (bool) {
        uint256 feesAvailable;
        uint256 rewardsAvailable;
        (feesAvailable, rewardsAvailable) = _getFeesAvailable();

        if (feesAvailable > 0 || rewardsAvailable > 0) {






            uint256 _targetDebt =
                getIssuanceRatio().mul(wantToSUSD(_collateral())).div(1e18);
            uint256 _balanceOfDebt = balanceOfDebt();
            bool claim = true;

            if (_balanceOfDebt > _targetDebt) {
                uint256 _requiredPayment = _balanceOfDebt.sub(_targetDebt);
                uint256 _maxCash =
                    balanceOfSusd().add(balanceOfSusdInVault()).mul(50).div(
                        100
                    );


                claim = _requiredPayment <= _maxCash;
            }

            if (claim) {

                burnSusdToTarget();



                if (rewardsAvailable > 0) {
                    entryIDs.push(_rewardEscrowV2().nextEntryId());
                }

                _feePool().claimFees();
            }
        }


        if (balanceOfDebt() < balanceOfSusdInVault()) {

            uint256 _valueToWithdraw =
                balanceOfSusdInVault().sub(balanceOfDebt());
            withdrawFromSUSDVault(_valueToWithdraw);
        }


        uint256 _balance = balanceOfSusd();
        if (_balance > 0) {
            buyWantWithSusd(_balance);
        }
    }

    function vestNextRewardsEntry() internal {




        if (entryIDs.length == 0) {
            return;
        }



        IRewardEscrowV2 re = _rewardEscrowV2();
        uint256 nextEntryID = entryIDs[entryIDIndex];
        uint256 _claimable =
            re.getVestingEntryClaimable(address(this), nextEntryID);

        if (_claimable == 0) {
            return;
        }


        uint256[] memory params = new uint256[](1);
        params[0] = nextEntryID;
        re.vest(params);


        entryIDIndex++;
    }

    function tendTrigger(uint256 callCost) public view override returns (bool) {
        uint256 _currentRatio = getCurrentRatio(); 
        uint256 _targetRatio = getTargetRatio(); 
        uint256 _issuanceRatio = getIssuanceRatio(); 

        if (_currentRatio < _issuanceRatio) {


            return _issuanceRatio.sub(_currentRatio) >= ratioThreshold;
        } else if (_currentRatio <= _targetRatio) {

            return false;
        } else if (_currentRatio > _targetRatio) {


            return _currentRatio.sub(_targetRatio) >= ratioThreshold;
        }

        return false;
    }

    function protectedTokens()
        internal
        view
        override
        returns (address[] memory)
