        address[] memory path = new address[](3);
        path[0] = address(want);
        path[1] = address(WETH);
        path[2] = address(susd);


        router.swapTokensForExactTokens(
            _amount,
            type(uint256).max,
            path,
            address(this),
            now
        );
    }



    function estimatedProfit() public view returns (uint256) {
